import React from 'react';

interface SliderInputProps {
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (value: number) => void;
  unit?: string;
  description?: string;
}

const SliderInput: React.FC<SliderInputProps> = ({ label, value, min, max, step, onChange, unit = '', description }) => {
  const percentage = Math.min(100, Math.max(0, ((value - min) / (max - min)) * 100));

  // Teal Gradient: Teal-500 (#14B8A6) to Teal-900 (#134E4A) range
  const sliderStyle = {
    background: `linear-gradient(to right, #14B8A6 0%, #115E59 ${percentage}%, rgba(51, 65, 85, 0.5) ${percentage}%, rgba(51, 65, 85, 0.5) 100%)`
  };

  return (
    <div className="group relative">
      <div className="flex justify-between items-center mb-3">
        <label className="text-[10px] font-bold text-navy-300 uppercase tracking-wider">{label}</label>

        {/* Editable Number Input */}
        <div className="flex items-center bg-primary-dim rounded border border-primary/20 shadow-sm focus-within:ring-2 focus-within:ring-primary focus-within:border-primary transition-all duration-200">
            <input
                type="number"
                value={value}
                onChange={(e) => onChange(e.target.value === '' ? 0 : parseFloat(e.target.value))}
                className="w-16 bg-transparent text-xs font-bold text-primary-light text-right outline-none py-1 px-1 appearance-none m-0"
                step={step}
            />
             <span className="text-[10px] text-primary-light font-bold pr-2">{unit}</span>
        </div>
      </div>
      <div className="relative h-5 flex items-center">
        <input
            type="range"
            min={min}
            max={max}
            step={step}
            value={value}
            onChange={(e) => onChange(parseFloat(e.target.value))}
            style={sliderStyle}
            className="w-full h-1.5 rounded-full appearance-none cursor-pointer slider-thumb transition-all"
        />
      </div>
      {description && <p className="text-[10px] text-navy-400 mt-1 opacity-70 group-hover:opacity-100 transition-opacity duration-200">{description}</p>}

      <style>{`
        /* Chrome/Safari/Edge */
        input[type=number]::-webkit-inner-spin-button, 
        input[type=number]::-webkit-outer-spin-button { 
          -webkit-appearance: none; 
          margin: 0; 
        }
        /* Firefox */
        input[type=number] {
            -moz-appearance: textfield;
        }

        .slider-thumb::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 16px;
          height: 16px;
          background: #020617;
          border: 2px solid #14B8A6; /* Teal-500 */
          border-radius: 50%;
          cursor: pointer;
          box-shadow: 0 0 10px rgba(20, 184, 166, 0.6), inset 0 0 4px rgba(20, 184, 166, 0.4);
          transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        .slider-thumb::-webkit-slider-thumb:hover {
            transform: scale(1.2);
            background: #14B8A6;
            box-shadow: 0 0 15px rgba(20, 184, 166, 0.8);
        }
        .slider-thumb::-moz-range-thumb {
          width: 16px;
          height: 16px;
          background: #020617;
          border: 2px solid #14B8A6;
          border-radius: 50%;
          cursor: pointer;
           box-shadow: 0 0 10px rgba(20, 184, 166, 0.6);
           transition: all 0.2s;
        }
        .slider-thumb::-moz-range-thumb:hover {
             transform: scale(1.2);
             background: #14B8A6;
        }
      `}</style>
    </div>
  );
};

export default SliderInput;

import React from 'react';
import InfoTooltip from './InfoTooltip';
import { TooltipInfo } from '../types';

interface MetricDisplayProps {
  label: string;
  value: string;
  highlight?: 'total-costs' | 'net-profit-loss' | 'net-profit-gain' | 'roi' | 'npv' | 'profit-margin';
  tooltip?: TooltipInfo;
  variant?: 'standard' | 'hero';
}

const MetricDisplay: React.FC<MetricDisplayProps> = ({ label, value, highlight, tooltip, variant = 'standard' }) => {
  const highlightClasses = {
    'total-costs': 'text-danger-light drop-shadow-[0_0_8px_rgba(239,68,68,0.5)]',
    'net-profit-loss': 'text-danger-light drop-shadow-[0_0_8px_rgba(239,68,68,0.5)]',
    'net-profit-gain': 'text-success-light drop-shadow-[0_0_8px_rgba(52,211,153,0.5)]',
    'roi': 'text-secondary drop-shadow-[0_0_8px_rgba(139,92,246,0.5)]',
    'npv': 'text-primary-light drop-shadow-[0_0_8px_rgba(20,184,166,0.5)]', // Updated to Teal shadow
    'profit-margin': 'text-primary-light drop-shadow-[0_0_8px_rgba(20,184,166,0.5)]', // Updated to Teal shadow
  };

  const textColor = highlight ? highlightClasses[highlight] : 'text-white';

  if (variant === 'hero') {
      return (
        <div className="bg-glass-200 backdrop-blur-md border border-glass-border p-5 rounded-2xl shadow-glass relative group transition-all duration-300 hover:border-glass-highlight hover:translate-y-[-2px] overflow-hidden">
            {/* Ambient Glow Background - contained within overflow-hidden */}
            {highlight === 'net-profit-gain' && <div className="absolute -top-10 -right-10 w-32 h-32 bg-success/10 blur-3xl rounded-full transition-opacity opacity-60 group-hover:opacity-100 pointer-events-none" />}
            {highlight === 'roi' && <div className="absolute -top-10 -right-10 w-32 h-32 bg-secondary/10 blur-3xl rounded-full transition-opacity opacity-60 group-hover:opacity-100 pointer-events-none" />}
            {highlight === 'npv' && <div className="absolute -top-10 -right-10 w-32 h-32 bg-primary/10 blur-3xl rounded-full transition-opacity opacity-60 group-hover:opacity-100 pointer-events-none" />}
            {highlight === 'profit-margin' && <div className="absolute -top-10 -right-10 w-32 h-32 bg-primary/10 blur-3xl rounded-full transition-opacity opacity-60 group-hover:opacity-100 pointer-events-none" />}
            {highlight === 'net-profit-loss' && <div className="absolute -top-10 -right-10 w-32 h-32 bg-danger/10 blur-3xl rounded-full transition-opacity opacity-60 group-hover:opacity-100 pointer-events-none" />}

            <div className="flex items-center justify-between mb-3 relative z-10">
                <span className="text-[11px] font-bold uppercase tracking-widest text-navy-400">{label}</span>
                {tooltip && <InfoTooltip info={tooltip} />}
            </div>
            <div className={`text-2xl lg:text-3xl font-black tracking-tight ${textColor} relative z-10 truncate`}>
                {value}
            </div>
        </div>
      );
  }

  return (
    <div className="bg-glass-100 border border-glass-border p-3 rounded-xl backdrop-blur-sm hover:bg-glass-200 transition-colors">
      <div className="flex items-center space-x-2 mb-1">
        <span className="text-xs font-medium text-navy-400">{label}</span>
        {tooltip && <InfoTooltip info={tooltip} />}
      </div>
      <div>
        <span className={`text-lg font-bold ${textColor}`}>
            {value}
        </span>
      </div>
    </div>
  );
};

export default MetricDisplay;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, ReferenceLine } from 'recharts';
import { CalculatedResults } from '../types';

interface ProfitabilityChartProps {
  results: CalculatedResults;
  currency: string;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(value);
};

const CustomTooltip = ({ active, payload, currency }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0]?.payload;
    if (!data) return null;

    return (
      <div className="bg-card border border-white/10 rounded-lg p-3 shadow-lg text-sm">
        <p className="font-bold text-white">{data.name}</p>
        <p className="text-navy-200">{formatCurrency(data.value, currency)}</p>
      </div>
    );
  }
  return null;
};


const ProfitWaterfallChart: React.FC<ProfitabilityChartProps> = ({ results, currency }) => {
  const { revenue, costs, profitability } = results;

  const chartData = useMemo(() => {
    const data = [
      { name: 'Leasing Rev', value: revenue.leasingRevenue },
      { name: 'Sales Rev', value: revenue.salesRevenue },
      { name: 'Install Rev', value: revenue.installationRevenue },
      { name: 'Spare Parts', value: revenue.sparePartsRevenue },
      { name: 'SaaS Fees', value: revenue.monthlyFeeRevenue },
      { name: 'Carbon Credits', value: revenue.carbonCreditRevenue },
      { name: 'COGS', value: -costs.cogs },
      { name: 'Install Cost', value: -costs.installationCost },
      { name: 'Maintenance', value: -costs.maintenanceCost },
      { name: 'Warranty', value: -costs.warrantyCost },
      { name: 'Consumables', value: -costs.consumablesCost },
      { name: 'Operations', value: -costs.operationalCost },
      { name: 'Electricity', value: -costs.electricityCost },
      { name: 'CAC', value: -costs.customerAcquisitionCost },
    ]
    .filter(d => Math.abs(d.value) > 1); // Filter out trivial values

    // Add Net Profit as the final bar (representing the total)
    data.push({ name: 'Net Profit', value: profitability.netProfit });

    return data;

  }, [results]);

  const COLORS = {
    revenue: '#10B981',
    cost: '#EF4444',
    profit: '#14B8A6', // Teal for the final total
  };

  return (
    <div className="h-96 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart 
          data={chartData} 
          layout="vertical" 
          margin={{ top: 5, right: 30, left: 40, bottom: 5 }}
          barCategoryGap="15%"
        >
          <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.1)" />
          <XAxis type="number" stroke="#94a3b8" tickFormatter={(v) => formatCurrency(v, currency)} />
          <YAxis 
            type="category" 
            dataKey="name" 
            stroke="#94a3b8" 
            width={100}
            interval={0}
            tick={{fontSize: 11}}
          />
          <Tooltip 
            cursor={{ fill: 'rgba(20, 184, 166, 0.05)' }}
            content={<CustomTooltip currency={currency} />}
          />
          <ReferenceLine x={0} stroke="#f1f5f9" strokeWidth={2} />
          <Bar dataKey="value" radius={[4, 4, 4, 4]}>
            {chartData.map((entry, index) => {
                let color = entry.value >= 0 ? COLORS.revenue : COLORS.cost;
                if (entry.name === 'Net Profit') color = COLORS.profit;
                return <Cell key={`cell-${index}`} fill={color} />;
            })}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ProfitWaterfallChart;

import React, { useMemo } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine } from 'recharts';
import { CalculatedResults, InputParams } from '../types';

interface CashFlowChartProps {
  results: CalculatedResults;
  currency: string;
  inputs: InputParams;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(value);
};

const CustomTooltip = ({ active, payload, label, currency }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-navy-900 border border-white/20 rounded-lg p-4 shadow-lg text-sm w-60">
        <p className="font-bold text-white text-base mb-3">{label}</p>
        {payload.map((pld, index) => (
          <div className={`flex items-center justify-between ${index > 0 ? 'mt-2' : ''}`} key={pld.dataKey}>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pld.stroke }} />
              <span className="text-navy-200">{pld.name}:</span>
            </div>
            <span className="font-semibold text-white">{formatCurrency(pld.value, currency)}</span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};


const CashFlowChart: React.FC<CashFlowChartProps> = ({ results, currency, inputs }) => {
  const data = useMemo(() => {
    let cumulativeFlow = 0;
    let cumulativeDiscountedFlow = 0;
    const discountRate = inputs.discountRate / 100;

    return results.cashFlow.map((flow, index) => {
      cumulativeFlow += flow;

      if (index === 0) { // Year 0 is initial investment, not discounted
        cumulativeDiscountedFlow += flow;
      } else {
        cumulativeDiscountedFlow += flow / Math.pow(1 + discountRate, index);
      }

      const yearData: {
        name: string;
        'Cash Flow': number;
        Discounted?: number;
      } = {
        name: `Year ${index}`,
        'Cash Flow': cumulativeFlow,
      };

      if (inputs.enableCashFlowDiscounting) {
        yearData.Discounted = cumulativeDiscountedFlow;
      }

      return yearData;
    });
  }, [results.cashFlow, inputs.enableCashFlowDiscounting, inputs.discountRate]);

  if (results.cashFlow.length <= 1) {
    return <div className="flex items-center justify-center h-full text-navy-400">Cash flow is not applicable for Direct Sales model.</div>
  }

  const discountedLineName = `Discounted (${inputs.discountRate}%)`;

  return (
    <div className="h-full w-full">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.1)" />
          <XAxis dataKey="name" stroke="#94a3b8" />
          <YAxis stroke="#94a3b8" tickFormatter={(v) => formatCurrency(v, currency)} />
          <Tooltip 
            cursor={{ stroke: 'rgba(139, 92, 246, 0.5)', strokeWidth: 1, strokeDasharray: '3 3' }}
            content={<CustomTooltip currency={currency} />}
          />
          <Legend wrapperStyle={{ color: '#e2e8f0', bottom: -5 }} />
          <ReferenceLine y={0} stroke="#f1f5f9" strokeWidth={1} strokeDasharray="3 3" />
          <Line 
            type="monotone" 
            dataKey="Cash Flow" 
            stroke="#2DD4BF"
            strokeWidth={2} 
            activeDot={{ r: 8, strokeWidth: 2, fill: '#0A0A0A', stroke: '#2DD4BF' }} 
            dot={{ stroke: '#2DD4BF', strokeWidth: 1, r: 4 }}
          />
          {inputs.enableCashFlowDiscounting && (
            <Line 
              type="monotone" 
              dataKey="Discounted"
              name={discountedLineName}
              stroke="#8B5CF6"
              strokeWidth={2} 
              strokeDasharray="5 5"
              activeDot={{ r: 8, strokeWidth: 2, fill: '#0A0A0A', stroke: '#8B5CF6' }} 
              dot={{ stroke: '#8B5CF6', strokeWidth: 1, r: 4 }}
            />
          )}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default CashFlowChart;

