    { key: 'companyRevenueShare', label: 'Revenue Share', description: 'Percentage of recovered gasoline value shared with the company.', type: 'percent' },
  ],
};

const EditableCell: React.FC<{
  value: number;
  onChange: (val: number) => void;
  type: 'currency' | 'percent' | 'number';
  currencySymbol: string;
  unit?: string;
  step?: number;
}> = ({ value, onChange, type, currencySymbol, unit, step }) => {
  const [localValue, setLocalValue] = useState(value.toString());

  useEffect(() => {
    setLocalValue(value.toString());
  }, [value]);

  const handleBlur = () => {
    let num = parseFloat(localValue);
    if (isNaN(num)) num = 0;
    onChange(num);
    setLocalValue(num.toString());
  };

  return (
    <div className="relative group">
      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
        <span className="text-navy-400 font-medium">
          {type === 'currency' ? currencySymbol : ''}
        </span>
      </div>
      <input
        type="number"
        value={localValue}
        onChange={(e) => setLocalValue(e.target.value)}
        onBlur={handleBlur}
        onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()}
        step={step || (type === 'percent' ? 0.1 : 1)}
        className={`bg-navy-950/50 border border-white/10 text-white text-sm rounded-lg focus:ring-2 focus:ring-primary focus:border-primary block w-full p-2.5 outline-none transition-all
          ${type === 'currency' ? 'pl-7' : 'pl-3'}
          ${(type === 'percent' || unit) ? 'pr-12' : 'pr-3'}
        `}
      />
      {(type === 'percent' || unit) && (
        <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
          <span className="text-navy-400 font-medium text-xs">
            {type === 'percent' ? '%' : unit}
          </span>
        </div>
      )}
    </div>
  );
};

