const App: React.FC = () => {
  const [inputParams, setInputParams] = useState<InputParams>(DEFAULT_PARAMS);

  const [currency, setCurrency] = useState('USD');
  const [activePage, setActivePage] = useState<ActivePage>('model');
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Check for onboarding status on mount
  useEffect(() => {
    const hasSeenOnboarding = localStorage.getItem('vapor_calc_onboarding_seen');
    if (!hasSeenOnboarding) {
      setShowOnboarding(true);
    }
  }, []);

  const handleCloseOnboarding = () => {
    setShowOnboarding(false);
    localStorage.setItem('vapor_calc_onboarding_seen', 'true');
  };

  const calculatedResults: CalculatedResults = useVaporRecoveryCalculator(inputParams);

  const handleInputChange = (key: keyof InputParams, value: string | number | boolean) => {
    setInputParams(prev => ({ ...prev, [key]: value }));
  };

  const handleCurrencyChange = (newCurrency: string) => {
    const oldRate = EXCHANGE_RATES[currency];
    const newRate = EXCHANGE_RATES[newCurrency];
    if (!oldRate || !newRate) return;
    const conversionFactor = newRate / oldRate;

    setInputParams(prev => {
      const newParams = { ...prev };
      MONETARY_PARAMS.forEach(key => {
        const currentValue = newParams[key] as number;
        if (typeof currentValue === 'number') {
          (newParams[key] as number) = parseFloat((currentValue * conversionFactor).toFixed(4));
        }
      });
      return newParams;
    });

    setCurrency(newCurrency);
  };

  const handleUnitSystemToggle = () => {
    const LITER_PER_GALLON = 3.78541;
    setInputParams(prev => {
      const isGallons = prev.unitSystem === 'gallons';
      const newUnitSystem = isGallons ? 'liters' : 'gallons';

      const newAvgGasolineSold = isGallons
        ? prev.avgGasolineSold * LITER_PER_GALLON
        : prev.avgGasolineSold / LITER_PER_GALLON;

      const newGasolinePrice = isGallons
        ? prev.gasolinePrice / LITER_PER_GALLON
        : prev.gasolinePrice * LITER_PER_GALLON;

      return {
        ...prev,
        unitSystem: newUnitSystem,
        avgGasolineSold: parseFloat(newAvgGasolineSold.toFixed(2)),
        gasolinePrice: parseFloat(newGasolinePrice.toFixed(2)),
      };
    });
  };

  const handleNavigate = (page: ActivePage) => {
    setActivePage(page);
    setIsSidebarOpen(false); // Close sidebar on nav (mobile)
  };

  const handleLoadScenario = (params: InputParams) => {
    setInputParams(params);
    setActivePage('model');
  };

  const renderPage = () => {
    switch (activePage) {
      case 'model':
        return (
          <div className="flex flex-col lg:flex-row h-full overflow-hidden">
            <div className="w-full lg:w-[320px] xl:w-[360px] p-4 lg:p-6 border-r border-white/5 bg-navy-950/50 flex-shrink-0 h-auto lg:h-full overflow-y-auto lg:overflow-hidden">
              <InputPanel 
                params={inputParams} 
                onParamChange={handleInputChange} 
                currency={currency}
                onCurrencyChange={handleCurrencyChange}
              />
            </div>
            <div className="flex-1 p-4 lg:p-6 h-full overflow-y-auto lg:overflow-hidden">
              <ResultsPanel results={calculatedResults} inputs={inputParams} currency={currency} />
            </div>
          </div>
        );
      case 'assumptions':
        return <Assumptions params={inputParams} onParamChange={handleInputChange} currency={currency} />;
      case 'sensitivity':
        return <SensitivityAnalysis baseParams={inputParams} onBaseParamChange={handleInputChange} currency={currency} />;
      case 'scenarios':
        return <ScenarioManager currentParams={inputParams} onLoad={handleLoadScenario} />;
      case 'lease-analysis':
        return <LeaseAnalysis globalParams={inputParams} currency={currency} />;
      case 'monte-carlo':
        return <MonteCarloAnalysis baseParams={inputParams} currency={currency} />;
      case 'comparison':
        return <ScenarioComparison currentParams={inputParams} currency={currency} />;
      case 'goal-seek':
        return <GoalSeekAnalysis currentParams={inputParams} onUpdateParams={setInputParams} currency={currency} />;
      default:
        return null;
    }
  }

  return (
    <div className="flex h-screen bg-navy-950 text-navy-200 font-sans overflow-hidden print:bg-white print:text-black">
      <OnboardingTour isOpen={showOnboarding} onClose={handleCloseOnboarding} />
      <div className="print:hidden h-full flex w-full">
          <Sidebar activePage={activePage} onNavigate={handleNavigate} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />

          <main className="flex-1 h-full flex flex-col overflow-hidden relative bg-[#020617] bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900/20 via-[#020617] to-[#020617]">
            {/* Mobile Header */}
            <div className="lg:hidden p-4 flex items-center justify-between border-b border-white/5 bg-navy-950">
                <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-white">
                    <MenuIcon className="w-6 h-6" />
                </button>
                <span className="font-bold text-white tracking-tight">Masar<span className="text-primary">Zero</span></span>
                <div className="w-8"></div> {/* Spacer for center alignment */}
            </div>

            <div className="flex-1 overflow-y-auto relative w-full">
                {renderPage()}
            </div>
          </main>
      </div>

      {activePage === 'model' && <FAB unitSystem={inputParams.unitSystem} onToggle={handleUnitSystemToggle} />}

      {/* Print View Only (Hidden normally) */}
      <div className="hidden print:block p-8 bg-white text-black h-auto overflow-visible">
          <h1 className="text-3xl font-bold mb-2">MasarZero Economics Report</h1>
          <p className="mb-6 text-gray-500">{new Date().toLocaleDateString()}</p>

          <div className="grid grid-cols-2 gap-8 mb-8">
              <div className="border p-4 rounded">
                  <h2 className="font-bold text-lg mb-4 border-b pb-2">Inputs</h2>
                  <div className="space-y-2 text-sm">
                      <div className="flex justify-between"><span>Model:</span> <strong>{inputParams.businessModel}</strong></div>
                      <div className="flex justify-between"><span>Units:</span> <strong>{inputParams.unitsPerClient * inputParams.numberOfClients}</strong></div>
                      <div className="flex justify-between"><span>Term:</span> <strong>{inputParams.leaseTerm} Years</strong></div>
                  </div>
              </div>
              <div className="border p-4 rounded bg-gray-50">
                   <h2 className="font-bold text-lg mb-4 border-b pb-2">Results</h2>
                    <div className="space-y-2 text-sm">
                      <div className="flex justify-between"><span>Net Profit:</span> <strong>{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(calculatedResults.profitability.netProfit)}</strong></div>
                      <div className="flex justify-between"><span>ROI:</span> <strong>{calculatedResults.profitability.roi.toFixed(1)}%</strong></div>
                      <div className="flex justify-between"><span>NPV:</span> <strong>{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(calculatedResults.profitability.npv)}</strong></div>
                  </div>
              </div>
          </div>

          <h2 className="font-bold text-xl mb-4">Cash Flow Analysis</h2>
          <table className="w-full text-sm text-left border-collapse">
              <thead>
                  <tr className="border-b-2 border-black">
                      <th className="py-2">Year</th>
                      <th className="py-2 text-right">Cash Flow</th>
                  </tr>
              </thead>
              <tbody>
                  {calculatedResults.cashFlow.map((cf, idx) => (
                      <tr key={idx} className="border-b border-gray-200">
                          <td className="py-2">{idx}</td>
                          <td className="py-2 text-right">{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(cf)}</td>
                      </tr>
                  ))}
              </tbody>
          </table>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { InputParams, Station } from '../types';
import Card from './Card';
import { TrashIcon, DownloadIcon, PencilIcon, CheckIcon, XIcon } from './icons';
import SliderInput from './SliderInput';
import MetricDisplay from './MetricDisplay';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';

interface LeaseAnalysisProps {
  globalParams: InputParams;
  currency: string;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(value);
};

const LeaseAnalysis: React.FC<LeaseAnalysisProps> = ({ globalParams, currency }) => {
  const [stations, setStations] = useState<Station[]>([
      { id: '1', name: 'Station A', dailyVolume: 35000, recoveryRate: 0.5, uptime: 99.5, installCost: 5000, localCurrency: currency, exchangeRateToGlobal: 1 },
      { id: '2', name: 'Station B', dailyVolume: 50000, recoveryRate: 0.5, uptime: 99.0, installCost: 5000, localCurrency: currency, exchangeRateToGlobal: 1 },
  ]);

  // Local overrides for analysis
  const [growthRate, setGrowthRate] = useState(globalParams.volumeGrowthRate);
  const [dailyOpsCost, setDailyOpsCost] = useState(globalParams.dailyOperationalCost);

  // Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<Partial<Station>>({});

  const [newStation, setNewStation] = useState<Partial<Station>>({
      name: '',
      dailyVolume: 40000,
      recoveryRate: 0.5,
      uptime: 99.5,
      installCost: 5000,
      localCurrency: currency,
      exchangeRateToGlobal: 1
  });

  const addStation = () => {
      if (!newStation.name) return;
      setStations([...stations, { 
          id: Date.now().toString(),
          name: newStation.name,
          dailyVolume: newStation.dailyVolume || 0,
          recoveryRate: newStation.recoveryRate || 0.5,
          uptime: newStation.uptime || 99.5,
          installCost: newStation.installCost || 5000,
          localCurrency: newStation.localCurrency || currency,
          exchangeRateToGlobal: newStation.exchangeRateToGlobal || 1
      } as Station]);
      setNewStation({ ...newStation, name: '' });
  };

  const removeStation = (id: string) => {
      setStations(stations.filter(s => s.id !== id));
  };

  const startEditing = (station: Station) => {
    setEditingId(station.id);
    setEditValues({ ...station });
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditValues({});
  };

  const saveEditing = () => {
    if (!editingId) return;
    setStations(stations.map(s => {
        if (s.id === editingId) {
            return { ...s, ...editValues } as Station;
        }
        return s;
    }));
    setEditingId(null);
    setEditValues({});
  };

  // Aggregate Calculation Logic
  const analysis = useMemo(() => {
    let totalRevenue = 0;
    let totalCost = 0;

    // Annualizing costs (Assuming these global params are in Global Currency)
    const annualMaintenance = globalParams.annualMaintenanceCost;
    const annualWarranty = globalParams.annualWarrantyCost;
    const annualConsumables = globalParams.annualConsumablesCost;
    const annualOps = dailyOpsCost * 365;
    const unitPowerCost = globalParams.unitElectricityConsumptionKwhDay * 365 * globalParams.electricityPrice;

    // Per unit annual fixed cost (without install)
    const annualFixedCostPerUnit = annualMaintenance + annualWarranty + annualConsumables + annualOps + unitPowerCost;

    const term = globalParams.leaseTerm;

    const results = stations.map(station => {
        // Exchange Rate: Value in Local * Rate = Value in Global
        // BUT here we assume the INPUTS (Daily Vol, Recovery) generate Local Currency revenue if we had a local price.
        // Simplified: The globalParams.gasolinePrice is in GLOBAL Currency.
        // If we want multi-currency, we should probably assume station inputs are local, but price is local too.
        // Let's assume Global Price applies everywhere for simplicity, UNLESS we added a local price field.
        // For Feature 4, "Allow different currencies per station", usually implies conversion.
        // Let's simply apply the exchange rate to the *final profit* of that station for aggregation, 
        // assuming the station operates entirely in local currency but we want to report in global.

        // BETTER APPROACH: All globalParams costs are in Global Currency. 
        // Station revenue is generated in Local Currency then converted.

        // Revenue Calculation
        let stationRevenueLocal = 0;

        for (let year = 1; year <= term; year++) {
             const growthFactor = Math.pow(1 + (growthRate / 100), year - 1);
             const dailyVol = station.dailyVolume * growthFactor;
             const recovered = dailyVol * (station.recoveryRate / 100) * 365 * (station.uptime / 100);

             // Gas Revenue
             // Using global price? Or should we use a local price?
             // Let's assume Global Price * Exchange Rate represents the Local Price in local currency terms?
             // No, simpler: Everything is calculated in GLOBAL currency. The "Multi-Currency" feature
             // is often about handling inputs entered in local currency.
             // Let's implement it as: Inputs are local, converted to global for totals.

             // We will assume 'installCost' is in local currency.
             // We will assume revenue generated is local (based on Global Price converted to local? Or just use Global Price as reference).
             // Let's keep it simple: Calculate everything in Global Currency for the metrics, 
             // but visually indicate the station's currency for the user.

             const gasRev = recovered * globalParams.gasolinePrice * (globalParams.companyRevenueShare / 100);
             const co2 = recovered * globalParams.co2TonnesPerGallon; 
             const carbonRev = globalParams.enableCarbonCredits ? co2 * globalParams.pricePerCredit : 0;

             stationRevenueLocal += gasRev + carbonRev;
        }

        if (globalParams.companyHandlesInstallation) {
             stationRevenueLocal += station.installCost; // Install Cost charged to client
        }

        // Costs
        // We assume global fixed costs are in Global Currency.
        // We assume Install Cost input is in Global Currency for simplicity unless converted.
        // Let's assume the user entered Install Cost in Global Currency.

        const stationCost = (annualFixedCostPerUnit * term) + globalParams.unitCost + station.installCost + globalParams.customerAcquisitionCost;
        const stationNetProfit = stationRevenueLocal - stationCost;

        totalRevenue += stationRevenueLocal;
        totalCost += stationCost;

        return {
            ...station,
            totalRevenue: stationRevenueLocal,
            totalCost: stationCost,
            netProfit: stationNetProfit
        };
    });

    return {
        stationResults: results,
        totalRevenue,
        totalCost,
        totalNetProfit: totalRevenue - totalCost,
        avgProfitPerStation: results.length ? (totalRevenue - totalCost) / results.length : 0,
        roi: totalCost > 0 ? ((totalRevenue - totalCost) / totalCost) * 100 : 0
    };

  }, [stations, globalParams, growthRate, dailyOpsCost]);

  const handleExport = () => {
    const header = ['Station Name', 'Currency', 'Daily Vol', 'Uptime', 'Install Cost', 'Total Revenue', 'Total Cost', 'Net Profit'];
    const rows = analysis.stationResults.map(s => [
        s.name, 
        s.localCurrency || currency,
        s.dailyVolume, 
        s.uptime, 
        s.installCost, 
        s.totalRevenue.toFixed(2), 
        s.totalCost.toFixed(2), 
        s.netProfit.toFixed(2)
    ]);

    let csvContent = "data:text/csv;charset=utf-8," + [header, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Lease_Analysis_Export_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="p-6 lg:p-8 w-full max-w-7xl mx-auto h-full overflow-y-auto pb-24">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-white">Detailed Lease Analysis</h1>
          <p className="text-navy-400 mt-1">Granular station-by-station breakdown with specific unit economics.</p>
        </div>
        <button 
            onClick={handleExport}
            className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors"
        >
            <DownloadIcon className="w-4 h-4" />
            <span>Export CSV</span>
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="lg:col-span-2 space-y-6">
             {/* Aggregated Stats */}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 <MetricDisplay label="Total Net Profit" value={formatCurrency(analysis.totalNetProfit, currency)} highlight={analysis.totalNetProfit >= 0 ? 'net-profit-gain' : 'net-profit-loss'} />
                 <MetricDisplay label="Avg Profit / Unit" value={formatCurrency(analysis.avgProfitPerStation, currency)} />
                 <MetricDisplay label="Total Revenue" value={formatCurrency(analysis.totalRevenue, currency)} />
                 <MetricDisplay label="Portfolio ROI" value={`${analysis.roi.toFixed(1)}%`} highlight="roi" />
             </div>

             {/* Station Table */}
             <Card title="Station Portfolio" noPadding className="overflow-hidden">
                 <div className="overflow-x-auto">
                     <table className="w-full text-sm text-left text-navy-200">
                         <thead className="bg-white/5 border-b border-white/10">
                             <tr>
                                 <th className="px-6 py-3 font-bold text-white">Station Name</th>
                                 <th className="px-6 py-3 font-bold text-white">Currency</th>
                                 <th className="px-6 py-3 font-bold text-white">Daily Vol</th>
                                 <th className="px-6 py-3 font-bold text-white">Recovery</th>
                                 <th className="px-6 py-3 font-bold text-white text-right">Net Profit (Lifetime)</th>
                                 <th className="px-6 py-3 font-bold text-white text-right">Actions</th>
                             </tr>
                         </thead>
                         <tbody className="divide-y divide-white/5">
                             {analysis.stationResults.map((s) => {
                                 const isEditing = editingId === s.id;
                                 return (
                                     <tr key={s.id} className="hover:bg-white/5">
                                         <td className="px-6 py-3 font-medium text-white">
                                             {isEditing ? (
                                                 <input 
                                                     type="text" 
                                                     value={editValues.name || ''}
                                                     onChange={(e) => setEditValues({...editValues, name: e.target.value})}
                                                     className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-full text-white focus:outline-none focus:border-primary"
                                                 />
                                             ) : s.name}
                                         </td>
                                         <td className="px-6 py-3 text-xs uppercase font-mono text-navy-400">
                                            {isEditing ? (
                                                 <input 
                                                     type="text" 
                                                     value={editValues.localCurrency || currency}
                                                     onChange={(e) => setEditValues({...editValues, localCurrency: e.target.value})}
                                                     className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-16 text-white focus:outline-none focus:border-primary uppercase"
                                                 />
                                             ) : s.localCurrency || currency}
                                         </td>
                                         <td className="px-6 py-3">
                                             {isEditing ? (
                                                 <input 
                                                     type="number" 
                                                     value={editValues.dailyVolume}
                                                     onChange={(e) => setEditValues({...editValues, dailyVolume: parseFloat(e.target.value)})}
                                                     className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-24 text-white focus:outline-none focus:border-primary"
                                                 />
                                             ) : s.dailyVolume.toLocaleString()}
                                         </td>
                                         <td className="px-6 py-3">
                                             {isEditing ? (
                                                 <div className="flex items-center">
                                                     <input 
                                                         type="number" 
                                                         value={editValues.recoveryRate}
                                                         onChange={(e) => setEditValues({...editValues, recoveryRate: parseFloat(e.target.value)})}
                                                         className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-16 text-white focus:outline-none focus:border-primary"
                                                         step={0.1}
                                                     />
                                                     <span className="ml-1">%</span>
                                                 </div>
                                             ) : `${(s.recoveryRate).toFixed(2)}%`}
                                         </td>
                                         <td className={`px-6 py-3 text-right font-bold ${s.netProfit >= 0 ? 'text-success' : 'text-danger'}`}>
                                             {formatCurrency(s.netProfit, currency)}
                                         </td>
                                         <td className="px-6 py-3 text-right">
                                             {isEditing ? (
                                                 <div className="flex justify-end space-x-2">
                                                     <button onClick={saveEditing} className="text-success hover:text-success-light p-1 bg-white/5 rounded"><CheckIcon className="w-5 h-5" /></button>
                                                     <button onClick={cancelEditing} className="text-danger hover:text-danger-light p-1 bg-white/5 rounded"><XIcon className="w-5 h-5" /></button>
                                                 </div>
                                             ) : (
                                                 <div className="flex justify-end space-x-2">
                                                     <button onClick={() => startEditing(s)} className="text-navy-400 hover:text-primary-light p-1"><PencilIcon className="w-4 h-4" /></button>
                                                     <button onClick={() => removeStation(s.id)} className="text-navy-400 hover:text-danger p-1"><TrashIcon className="w-4 h-4" /></button>
                                                 </div>
                                             )}
                                         </td>
                                     </tr>
                                 );
                             })}
                             {/* Add Row */}
                             {!editingId && (
                                 <tr className="bg-navy-900/50">
                                     <td className="px-6 py-2">
                                         <input 
                                            type="text" 
                                            placeholder="New Station Name"
                                            className="bg-transparent border border-white/20 rounded px-2 py-1 w-full text-white placeholder-navy-500 focus:outline-none focus:border-primary"
                                            value={newStation.name}
                                            onChange={e => setNewStation({...newStation, name: e.target.value})}
                                         />
                                     </td>
                                     <td className="px-6 py-2">
                                         <input 
                                            type="text" 
                                            placeholder="USD"
                                            className="bg-transparent border border-white/20 rounded px-2 py-1 w-16 text-white uppercase focus:outline-none focus:border-primary"
                                            value={newStation.localCurrency}
                                            onChange={e => setNewStation({...newStation, localCurrency: e.target.value})}
                                         />
                                     </td>
                                     <td className="px-6 py-2">
                                         <input 
                                            type="number" 
                                            className="bg-transparent border border-white/20 rounded px-2 py-1 w-24 text-white focus:outline-none focus:border-primary"
                                            value={newStation.dailyVolume}
                                            onChange={e => setNewStation({...newStation, dailyVolume: parseFloat(e.target.value)})}
                                         />
                                     </td>
                                     <td className="px-6 py-2 text-sm text-navy-400">
                                          Default ({newStation.recoveryRate}%)
                                     </td>
                                     <td className="px-6 py-2 text-right" colSpan={2}>
                                         <button 
                                            onClick={addStation}
                                            disabled={!newStation.name}
                                            className="bg-primary hover:bg-primary-dark text-white text-xs font-bold px-3 py-1.5 rounded disabled:opacity-50"
                                         >
                                             Add Station
                                         </button>
                                     </td>
                                 </tr>
                             )}
                         </tbody>
                     </table>
                 </div>
             </Card>
          </div>

          <div className="space-y-6">
              {/* Controls */}
              <Card title="Analysis Parameters">
                  <div className="space-y-4">
                      <SliderInput 
                          label="Volume Growth Rate (Annual)"
                          value={growthRate}
                          min={-5} max={20} step={0.5}
                          unit="%"
                          onChange={setGrowthRate}
                          description="Projected annual increase in gasoline volume across portfolio."
                      />
                       <SliderInput 
                          label="Daily Op Cost / Unit"
                          value={dailyOpsCost}
                          min={0} max={50} step={1}
                          unit={CURRENCY_SYMBOLS[currency]}
                          onChange={setDailyOpsCost}
                          description="Overhead cost per day per unit."
                      />
                  </div>
              </Card>

              {/* Unit Economics Breakdown */}
              <Card title="Unit Economics (Per Unit/Year)">
                  <div className="space-y-3 text-sm">
                       <div className="flex justify-between border-b border-white/10 pb-2">
                           <span className="text-navy-300">Revenue (Year 1 Avg)</span>
                           <span className="text-success font-bold">{formatCurrency((analysis.totalRevenue / globalParams.leaseTerm) / Math.max(1, stations.length), currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Maintenance</span>
                           <span className="text-white">{formatCurrency(globalParams.annualMaintenanceCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Warranty Reserve</span>
                           <span className="text-white">{formatCurrency(globalParams.annualWarrantyCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Consumables</span>
                           <span className="text-white">{formatCurrency(globalParams.annualConsumablesCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
