import React from 'react';
import { CalculatedResults, InputParams } from '../types';
import Card from './Card';
import MetricDisplay from './MetricDisplay';
import { ShieldCheckIcon, TreeIcon, LightningIcon, LeafIcon } from './icons';

interface ImpactAnalysisProps {
  results: CalculatedResults;
  inputs: InputParams;
  currency: string;
}

const formatVolume = (val: number, unit: string) => 
    `${Math.round(val).toLocaleString()} ${unit}`;

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, minimumFractionDigits: 0 }).format(val);

const ProgressBar: React.FC<{ current: number; max: number; threshold: number; label: string }> = ({ current, max, threshold, label }) => {
    const percent = Math.min(100, (current / max) * 100);
    const thresholdPercent = Math.min(100, (threshold / max) * 100);
    const isSafe = current > threshold;

    return (
        <div className="mb-4">
            <div className="flex justify-between text-xs mb-1">
                <span className="text-navy-300 font-medium">{label}</span>
                <span className={isSafe ? 'text-success font-bold' : 'text-danger font-bold'}>
                    {isSafe ? 'Safe' : 'Risk'}
                </span>
            </div>
            <div className="relative h-4 bg-navy-900 rounded-full overflow-hidden border border-white/10">
                {/* Threshold Marker */}
                <div 
                    className="absolute top-0 bottom-0 w-0.5 bg-white z-10 shadow-[0_0_10px_white]"
                    style={{ left: `${thresholdPercent}%` }}
                />

                {/* Progress Bar */}
                <div 
                    className={`h-full transition-all duration-500 ${isSafe ? 'bg-success' : 'bg-danger'}`}
                    style={{ width: `${percent}%` }}
                />
            </div>
            <div className="flex justify-between text-[10px] text-navy-400 mt-1">
                <span>0</span>
                <span className="text-white font-mono">BE: {Math.round(threshold).toLocaleString()}</span>
                <span>{Math.round(max).toLocaleString()}</span>
            </div>
        </div>
    );
};

const ImpactAnalysis: React.FC<ImpactAnalysisProps> = ({ results, inputs, currency }) => {
  const { impact } = results;
  const unitLabel = inputs.unitSystem === 'gallons' ? 'Gal' : 'L';
  const dailyVol = inputs.avgGasolineSold;

  // Max range for charts is typically current volume + 50% buffer or BreakEven + 50%
  const chartMax = Math.max(dailyVol * 1.5, impact.breakEvenTotalVolume * 1.5);

  return (
    <div className="p-6 lg:p-8 w-full max-w-6xl mx-auto h-full overflow-y-auto">
        <div className="flex items-center space-x-4 mb-8">
            <div className="p-3 bg-gradient-to-br from-green-400 to-emerald-600 rounded-xl shadow-glow">
                <ShieldCheckIcon className="w-8 h-8 text-white" />
            </div>
            <div>
                <h1 className="text-3xl font-bold text-white">Impact & Thresholds</h1>
                <p className="text-navy-400 mt-1">Operational safety margins and environmental ESG performance.</p>
            </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
            {/* Left Col: Break Even Analysis */}
            <div className="space-y-6">
                <Card title="Operational Safety Margin">
                    <div className="p-4 bg-navy-900/50 rounded-xl border border-white/5 mb-6">
                        <div className="text-center">
                            <span className="text-sm text-navy-400 uppercase tracking-widest">Safety Margin</span>
                            <div className={`text-5xl font-black mt-2 ${impact.safetyMargin > 20 ? 'text-success' : impact.safetyMargin > 0 ? 'text-warning' : 'text-danger'}`}>
                                {impact.safetyMargin.toFixed(1)}%
                            </div>
                            <p className="text-xs text-navy-400 mt-2">
                                Current volume can drop by this % before ROI turns negative.
                            </p>
                        </div>
                    </div>

                    <div className="space-y-6">
                        <ProgressBar 
                            label={`OpEx Break-Even (${formatVolume(impact.breakEvenDailyVolume, unitLabel)}/day)`}
                            current={dailyVol}
                            threshold={impact.breakEvenDailyVolume}
                            max={chartMax}
                        />
                         <ProgressBar 
                            label={`Total ROI Break-Even (${formatVolume(impact.breakEvenTotalVolume, unitLabel)}/day)`}
                            current={dailyVol}
                            threshold={impact.breakEvenTotalVolume}
                            max={chartMax}
                        />
                    </div>
                </Card>

                <div className="grid grid-cols-2 gap-4">
                    <MetricDisplay label="OpEx Break-Even" value={formatVolume(impact.breakEvenDailyVolume, unitLabel)} />
                    <MetricDisplay label="ROI Break-Even" value={formatVolume(impact.breakEvenTotalVolume, unitLabel)} />
                </div>
            </div>

            {/* Right Col: ESG Dashboard */}
            <div className="space-y-6">
                 <Card title="Environmental Impact (ESG)">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="bg-gradient-to-br from-emerald-500/10 to-emerald-900/20 border border-emerald-500/30 p-4 rounded-xl flex items-center space-x-4">
                            <div className="bg-emerald-500/20 p-3 rounded-full">
                                <LeafIcon className="w-6 h-6 text-emerald-400" />
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{Math.round(impact.totalCo2Saved).toLocaleString()}</div>
                                <div className="text-xs text-emerald-200 uppercase font-bold tracking-wider">Tonnes CO2 Saved</div>
                            </div>
                        </div>

                        <div className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center space-x-4">
                             <div className="bg-white/10 p-3 rounded-full">
                                <TreeIcon className="w-6 h-6 text-green-400" />
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{Math.round(impact.treesPlantedEquiv).toLocaleString()}</div>
                                <div className="text-xs text-navy-400 uppercase font-bold tracking-wider">Trees Planted</div>
                            </div>
                        </div>

                         <div className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center space-x-4">
                             <div className="bg-white/10 p-3 rounded-full">
                                <ShieldCheckIcon className="w-6 h-6 text-blue-400" /> {/* Using Shield as Car proxy if needed or just Generic */}
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{impact.carsOffRoadEquiv.toFixed(1)}</div>
                                <div className="text-xs text-navy-400 uppercase font-bold tracking-wider">Cars Off Road</div>
                            </div>
                        </div>

                        <div className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center space-x-4">
                             <div className="bg-white/10 p-3 rounded-full">
                                <LightningIcon className="w-6 h-6 text-yellow-400" />
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{Math.round(impact.homesPoweredEquiv).toLocaleString()}</div>
                                <div className="text-xs text-navy-400 uppercase font-bold tracking-wider">Homes Powered</div>
                            </div>
                        </div>
                    </div>
                </Card>

                <Card title="Impact Summary">
                     <p className="text-sm text-navy-200 leading-relaxed">
                         Over the <strong>{inputs.leaseTerm} year</strong> term, this project will prevent <strong>{Math.round(impact.totalCo2Saved).toLocaleString()} metric tonnes</strong> of CO2 from entering the atmosphere.
                         <br/><br/>
                         This is equivalent to the carbon sequestered by <strong>{Math.round(impact.treesPlantedEquiv).toLocaleString()} tree seedlings</strong> grown for 10 years, or removing <strong>{Math.round(impact.carsOffRoadEquiv)} gasoline-powered passenger vehicles</strong> from the road for one year.
                     </p>
                </Card>
            </div>
        </div>
    </div>
  );
};

export default ImpactAnalysis;

