import React, { useState } from 'react';
import { InputParams, CalculatedResults } from '../types';
import CashFlowChart from './CashFlowChart';
import ProfitWaterfallChart from './ProfitabilityChart';
import { LeafIcon, ShieldCheckIcon, TreeIcon, CalculatorIcon, ChevronDownIcon, ChevronUpIcon } from './icons';

interface PresentationModeProps {
  inputs: InputParams;
  results: CalculatedResults;
  currency: string;
  onExit: () => void;
}

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);

const formatPercent = (val: number) => `${val.toFixed(1)}%`;

const Slide: React.FC<{ children: React.ReactNode; isActive: boolean }> = ({ children, isActive }) => {
    return (
        <div className={`absolute inset-0 transition-all duration-500 ease-in-out flex flex-col items-center justify-center p-8 ${isActive ? 'opacity-100 translate-x-0 z-10' : 'opacity-0 translate-x-12 z-0 pointer-events-none'}`}>
            {children}
        </div>
    );
}

const PresentationMode: React.FC<PresentationModeProps> = ({ inputs, results, currency, onExit }) => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const totalSlides = 4;

  const nextSlide = () => setCurrentSlide(prev => (prev + 1) % totalSlides);
  const prevSlide = () => setCurrentSlide(prev => (prev - 1 + totalSlides) % totalSlides);

  // Keyboard navigation
  React.useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
        if (e.key === 'ArrowRight' || e.key === ' ') nextSlide();
        if (e.key === 'ArrowLeft') prevSlide();
        if (e.key === 'Escape') onExit();
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, []);

  const { profitability, impact } = results;

  return (
    <div className="fixed inset-0 z-[200] bg-navy-950 flex flex-col text-white">
        {/* Header Controls */}
        <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-50">
            <button onClick={onExit} className="bg-white/10 hover:bg-white/20 text-white px-4 py-2 rounded-lg text-sm font-bold backdrop-blur-md transition-colors">
                Exit Presentation
            </button>
            <div className="flex items-center space-x-2">
                 <div className="flex space-x-1">
                     {Array.from({length: totalSlides}).map((_, i) => (
                         <div key={i} className={`h-1.5 rounded-full transition-all duration-300 ${i === currentSlide ? 'w-8 bg-primary' : 'w-2 bg-white/20'}`} />
                     ))}
                 </div>
            </div>
        </div>

        {/* Slides Container */}
        <div className="flex-1 relative w-full max-w-7xl mx-auto">

            {/* Slide 1: The Executive Summary */}
            <Slide isActive={currentSlide === 0}>
                <div className="text-center space-y-8 max-w-4xl animate-in fade-in slide-in-from-bottom-8 duration-700">
                    <div className="inline-flex items-center justify-center p-4 bg-gradient-primary rounded-2xl shadow-glow mb-4">
                        <CalculatorIcon className="w-12 h-12 text-white" />
                    </div>
                    <h1 className="text-5xl md:text-7xl font-black tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-white via-primary-light to-white">
                        Project Economics
                    </h1>
                    <p className="text-xl md:text-2xl text-navy-300 max-w-2xl mx-auto leading-relaxed">
                        A comprehensive analysis of profitability, environmental impact, and return on investment for your vapor recovery initiative.
                    </p>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-12">
                        <div className="bg-glass-200 border border-glass-border p-8 rounded-2xl backdrop-blur-xl">
                            <div className="text-navy-400 text-sm font-bold uppercase tracking-widest mb-2">Net Profit</div>
                            <div className="text-4xl md:text-5xl font-black text-white">{formatCurrency(profitability.netProfit, currency)}</div>
                        </div>
                        <div className="bg-glass-200 border border-glass-border p-8 rounded-2xl backdrop-blur-xl">
                             <div className="text-navy-400 text-sm font-bold uppercase tracking-widest mb-2">ROI</div>
                            <div className="text-4xl md:text-5xl font-black text-secondary">{formatPercent(profitability.roi)}</div>
                        </div>
                         <div className="bg-glass-200 border border-glass-border p-8 rounded-2xl backdrop-blur-xl">
                             <div className="text-navy-400 text-sm font-bold uppercase tracking-widest mb-2">Payback Period</div>
                            <div className="text-4xl md:text-5xl font-black text-primary-light">{profitability.paybackPeriod.toFixed(1)} <span className="text-lg text-navy-400 font-medium">Years</span></div>
                        </div>
                    </div>
                </div>
            </Slide>

            {/* Slide 2: Environmental Impact */}
            <Slide isActive={currentSlide === 1}>
                <div className="w-full max-w-5xl">
                    <h2 className="text-4xl font-bold mb-12 text-center">Environmental Impact</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
                        <div className="space-y-8">
                             <div className="bg-emerald-900/20 border border-emerald-500/30 p-8 rounded-3xl flex items-center space-x-6">
                                <div className="bg-emerald-500/20 p-5 rounded-full">
                                    <LeafIcon className="w-10 h-10 text-emerald-400" />
                                </div>
                                <div>
                                    <div className="text-5xl font-black text-white">{Math.round(impact.totalCo2Saved).toLocaleString()}</div>
                                    <div className="text-lg text-emerald-200 uppercase font-bold tracking-wider mt-1">Tonnes CO2 Saved</div>
                                </div>
                            </div>
                             <div className="p-6 bg-white/5 rounded-2xl border border-white/10">
                                <p className="text-lg leading-relaxed text-navy-200">
                                    Over the <strong>{inputs.leaseTerm} year</strong> term, this project significantly reduces your carbon footprint, aligning with corporate sustainability goals (ESG) and generating <strong>{formatCurrency(results.revenue.carbonCreditRevenue, currency)}</strong> in potential carbon credit revenue.
                                </p>
                             </div>
                        </div>

                        <div className="grid grid-cols-1 gap-6">
                            <div className="bg-navy-900 border border-white/10 p-6 rounded-2xl flex items-center space-x-4">
                                <TreeIcon className="w-8 h-8 text-green-400" />
                                <div>
                                    <div className="text-3xl font-bold text-white">{Math.round(impact.treesPlantedEquiv).toLocaleString()}</div>
                                    <div className="text-xs text-navy-400 uppercase">Trees Planted Equivalent</div>
                                </div>
                            </div>
                             <div className="bg-navy-900 border border-white/10 p-6 rounded-2xl flex items-center space-x-4">
                                <ShieldCheckIcon className="w-8 h-8 text-blue-400" />
                                <div>
                                    <div className="text-3xl font-bold text-white">{Math.round(impact.carsOffRoadEquiv).toLocaleString()}</div>
                                    <div className="text-xs text-navy-400 uppercase">Cars Taken Off Road</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </Slide>

             {/* Slide 3: Financial Trajectory */}
             <Slide isActive={currentSlide === 2}>
                <div className="w-full h-full max-h-[80vh] flex flex-col">
                    <h2 className="text-3xl font-bold mb-6 text-center">Cumulative Cash Flow</h2>
                    <div className="flex-1 bg-navy-900/50 border border-white/10 rounded-3xl p-6 shadow-2xl">
                        <CashFlowChart results={results} currency={currency} inputs={inputs} />
                    </div>
                    <div className="mt-8 grid grid-cols-3 gap-8 text-center">
                         <div>
                            <div className="text-navy-400 text-xs uppercase font-bold">Total Revenue</div>
                            <div className="text-2xl font-bold text-white">{formatCurrency(results.revenue.totalRevenue, currency)}</div>
                        </div>
                         <div>
                            <div className="text-navy-400 text-xs uppercase font-bold">Total Costs</div>
                            <div className="text-2xl font-bold text-white">{formatCurrency(results.costs.totalCosts, currency)}</div>
                        </div>
                         <div>
                            <div className="text-navy-400 text-xs uppercase font-bold">Net Present Value</div>
                            <div className="text-2xl font-bold text-primary-light">{formatCurrency(profitability.npv, currency)}</div>
                        </div>
                    </div>
                </div>
            </Slide>

            {/* Slide 4: Closing */}
            <Slide isActive={currentSlide === 3}>
                 <div className="w-full max-w-4xl text-center">
                     <h2 className="text-4xl font-bold mb-12">Profit Waterfall</h2>
                     <div className="h-[400px] w-full mb-12">
                         <ProfitWaterfallChart results={results} currency={currency} />
                     </div>
                     <div className="bg-gradient-to-r from-navy-900 to-navy-800 p-8 rounded-2xl border border-white/10">
                         <h3 className="text-2xl font-bold text-white mb-4">Proposed Next Steps</h3>
                         <p className="text-navy-300">
                             Based on the input parameters ({inputs.numberOfClients} clients, {inputs.unitsPerClient} units each), this project achieves break-even in <strong>{profitability.paybackPeriod.toFixed(1)} years</strong>. We recommend proceeding to the site survey phase to validate installation costs.
                         </p>
                     </div>
                 </div>
            </Slide>

        </div>

        {/* Footer Navigation */}
        <div className="absolute bottom-0 left-0 right-0 p-8 flex justify-between items-center z-50">
             <button 
                onClick={prevSlide}
                className={`flex items-center space-x-2 text-white/50 hover:text-white transition-colors ${currentSlide === 0 ? 'opacity-0 pointer-events-none' : ''}`}
             >
                 <ChevronDownIcon className="w-6 h-6 rotate-90" />
                 <span className="text-sm font-bold uppercase tracking-wider">Previous</span>
             </button>

             <div className="text-navy-600 text-xs font-mono">
                 Use Arrow Keys to Navigate
             </div>

             <button 
                onClick={nextSlide}
                className={`flex items-center space-x-2 text-white/50 hover:text-white transition-colors ${currentSlide === totalSlides - 1 ? 'opacity-0 pointer-events-none' : ''}`}
             >
                 <span className="text-sm font-bold uppercase tracking-wider">Next</span>
                 <ChevronUpIcon className="w-6 h-6 rotate-90" />
             </button>
        </div>
    </div>
  );
};

export default PresentationMode;

import React from 'react';
import { CalculatorIcon, ChartBarIcon, BeakerIcon, FolderIcon, ClipboardListIcon, TableIcon, ViewBoardsIcon, SlidersIcon, AdjustmentsIcon, ShieldCheckIcon, PresentationChartLineIcon } from './icons';

interface SidebarProps {
  activePage: 'model' | 'assumptions' | 'sensitivity' | 'scenarios' | 'lease-analysis' | 'monte-carlo' | 'comparison' | 'goal-seek' | 'impact' | 'presentation';
  onNavigate: (page: any) => void;
  isOpen?: boolean;
