                        defaultValue=""
                     >
                         <option value="" disabled>Select a configuration...</option>
                         {PRESETS.map(p => <option key={p.name} value={p.name}>{p.name}</option>)}
                     </select>
                 </div>
                 <button 
                    onClick={handleShare}
                    className="bg-navy-800 hover:bg-navy-700 border border-white/10 rounded-lg p-2.5 transition-colors flex items-center justify-center text-white"
                    title="Share Configuration via URL"
                 >
                     {copied ? <CheckIcon className="w-5 h-5 text-success" /> : <ShareIcon className="w-5 h-5" />}
                 </button>
            </div>
            <div>
                <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2">Business Model</label>
                <SegmentedControl
                    options={['Direct Sales', 'Leasing']}
                    selected={params.businessModel}
                    setSelected={(val) => onParamChange('businessModel', val)}
                />
            </div>
             <SelectInput 
                label="Currency"
                value={currency}
                onChange={onCurrencyChange}
                options={[
                    { value: 'USD', label: '$ USD' },
                    { value: 'EUR', label: '€ EUR' },
                    { value: 'GBP', label: '£ GBP' },
                    { value: 'JPY', label: '¥ JPY' },
                    { value: 'CAD', label: '$ CAD' },
                ]}
            />
        </div>

        {/* Scrollable Content Area */}
        {/* Removed internal overflow-y-auto for mobile to let parent handle scroll */}
        <div className="flex-1 pr-1 lg:overflow-y-auto custom-scrollbar space-y-1 pb-4">
             <label className="block text-[10px] font-bold text-navy-400 uppercase tracking-widest mb-2 pl-1">Input Parameters</label>

            <AccordionItem 
                title="Site & Client Info" 
                isOpen={openSections['client']} 
                onToggle={() => toggleSection('client')}
            >
                <SliderInput
                    label="Units per Client"
                    value={params.unitsPerClient}
                    min={1} max={200} step={1}
                    onChange={(v) => onParamChange('unitsPerClient', v)}
                />
                <TextInput
                    label="Number of Clients"
                    value={params.numberOfClients}
                    onChange={(v) => onParamChange('numberOfClients', v)}
                />

                {/* Installation Subsection */}
                <div className="mt-4 pt-4 border-t border-white/10">
