                        onChange={(v) => onParamChange('companyHandlesInstallation', v)}
                    />
                    {params.companyHandlesInstallation && (
                        <div className="mt-3 space-y-3 pl-3 border-l-2 border-primary/30">
                             <TextInput
                                label="Installation Cost (Expense)"
