                            <div className="flex justify-between items-center text-xs bg-black/20 p-2 rounded">
                                <span className="text-navy-400">Client Price/Unit:</span>
                                <span className="font-bold text-white">
                                    {new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(installationPrice)}
                                </span>
