            {/* Slide 4: Closing */}
            <Slide isActive={currentSlide === 3}>
                 <div className="w-full max-w-4xl text-center">
                     <h2 className="text-2xl md:text-4xl font-bold mb-8 md:mb-12">Profit Waterfall</h2>
