                         <p className="text-sm md:text-base text-navy-300">
                             Based on the input parameters ({inputs.numberOfClients} clients, {inputs.unitsPerClient} units each), this project achieves break-even in <strong>{profitability.paybackPeriod.toFixed(1)} years</strong>. We recommend proceeding to the site survey phase to validate installation costs.
                         </p>
                     </div>
                 </div>
            </Slide>

        </div>

        {/* Footer Navigation */}
        <div className="absolute bottom-0 left-0 right-0 p-6 md:p-8 flex justify-between items-center z-50 bg-gradient-to-t from-navy-950/90 to-transparent pointer-events-none">
             <button 
                onClick={prevSlide}
                className={`flex items-center space-x-2 text-white/50 hover:text-white transition-colors pointer-events-auto ${currentSlide === 0 ? 'opacity-0 pointer-events-none' : ''}`}
             >
                 <ChevronDownIcon className="w-5 h-5 md:w-6 md:h-6 rotate-90" />
                 <span className="text-xs md:text-sm font-bold uppercase tracking-wider">Previous</span>
