import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, ReferenceLine } from 'recharts';
import { CalculatedResults } from '../types';

interface ProfitabilityChartProps {
  results: CalculatedResults;
  currency: string;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(value);
};

const CustomTooltip = ({ active, payload, currency }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0]?.payload;
    if (!data) return null;

    return (
      <div className="bg-card border border-white/10 rounded-lg p-3 shadow-lg text-sm z-50">
        <p className="font-bold text-white">{data.name}</p>
        <p className="text-navy-200">{formatCurrency(data.value, currency)}</p>
      </div>
    );
  }
  return null;
};


const ProfitWaterfallChart: React.FC<ProfitabilityChartProps> = ({ results, currency }) => {
  const { revenue, costs, profitability } = results;

  const chartData = useMemo(() => {
    const data = [
      { name: 'Leasing Rev', value: revenue.leasingRevenue },
      { name: 'Sales Rev', value: revenue.salesRevenue },
      { name: 'Install Rev', value: revenue.installationRevenue },
      { name: 'Spare Parts', value: revenue.sparePartsRevenue },
      { name: 'SaaS Fees', value: revenue.monthlyFeeRevenue },
      { name: 'Carbon Credits', value: revenue.carbonCreditRevenue },
      { name: 'COGS', value: -costs.cogs },
      { name: 'Install Cost', value: -costs.installationCost },
      { name: 'Maintenance', value: -costs.maintenanceCost },
      { name: 'Warranty', value: -costs.warrantyCost },
      { name: 'Consumables', value: -costs.consumablesCost },
      { name: 'Operations', value: -costs.operationalCost },
      { name: 'Electricity', value: -costs.electricityCost },
      { name: 'CAC', value: -costs.customerAcquisitionCost },
    ]
    .filter(d => Math.abs(d.value) > 1); // Filter out trivial values

    // Add Net Profit as the final bar (representing the total)
    data.push({ name: 'Net Profit', value: profitability.netProfit });

    return data;

  }, [results]);

  const COLORS = {
    revenue: '#10B981',
    cost: '#EF4444',
    profit: '#14B8A6', // Teal for the final total
  };

  return (
    <div className="h-[350px] lg:h-full w-full min-h-[300px]">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart 
          data={chartData} 
          layout="vertical" 
          margin={{ top: 5, right: 30, left: 40, bottom: 5 }}
          barCategoryGap="15%"
        >
          <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.1)" />
          <XAxis type="number" stroke="#94a3b8" tickFormatter={(v) => formatCurrency(v, currency)} />
          <YAxis 
            type="category" 
            dataKey="name" 
            stroke="#94a3b8" 
            width={100}
            interval={0}
            tick={{fontSize: 11}}
          />
          <Tooltip 
            cursor={{ fill: 'rgba(20, 184, 166, 0.05)' }}
            content={<CustomTooltip currency={currency} />}
          />
          <ReferenceLine x={0} stroke="#f1f5f9" strokeWidth={2} />
          <Bar dataKey="value" radius={[4, 4, 4, 4]}>
            {chartData.map((entry, index) => {
                let color = entry.value >= 0 ? COLORS.revenue : COLORS.cost;
                if (entry.name === 'Net Profit') color = COLORS.profit;
                return <Cell key={`cell-${index}`} fill={color} />;
            })}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ProfitWaterfallChart;

import React, { useMemo } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine } from 'recharts';
import { CalculatedResults, InputParams } from '../types';

interface CashFlowChartProps {
  results: CalculatedResults;
  currency: string;
  inputs: InputParams;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(value);
};

const CustomTooltip = ({ active, payload, label, currency }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-navy-900 border border-white/20 rounded-lg p-4 shadow-lg text-sm w-60 z-50">
        <p className="font-bold text-white text-base mb-3">{label}</p>
        {payload.map((pld, index) => (
          <div className={`flex items-center justify-between ${index > 0 ? 'mt-2' : ''}`} key={pld.dataKey}>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pld.stroke }} />
              <span className="text-navy-200">{pld.name}:</span>
            </div>
            <span className="font-semibold text-white">{formatCurrency(pld.value, currency)}</span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};


const CashFlowChart: React.FC<CashFlowChartProps> = ({ results, currency, inputs }) => {
  const data = useMemo(() => {
    let cumulativeFlow = 0;
    let cumulativeDiscountedFlow = 0;
    const discountRate = inputs.discountRate / 100;

    return results.cashFlow.map((flow, index) => {
      cumulativeFlow += flow;

      if (index === 0) { // Year 0 is initial investment, not discounted
        cumulativeDiscountedFlow += flow;
      } else {
        cumulativeDiscountedFlow += flow / Math.pow(1 + discountRate, index);
      }

      const yearData: {
        name: string;
        'Cash Flow': number;
        Discounted?: number;
      } = {
        name: `Year ${index}`,
        'Cash Flow': cumulativeFlow,
      };

      if (inputs.enableCashFlowDiscounting) {
        yearData.Discounted = cumulativeDiscountedFlow;
      }

      return yearData;
    });
  }, [results.cashFlow, inputs.enableCashFlowDiscounting, inputs.discountRate]);

  if (results.cashFlow.length <= 1) {
    return <div className="flex items-center justify-center h-full text-navy-400">Cash flow is not applicable for Direct Sales model.</div>
  }

  const discountedLineName = `Discounted (${inputs.discountRate}%)`;

  return (
    <div className="h-[350px] lg:h-full w-full min-h-[300px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.1)" />
          <XAxis dataKey="name" stroke="#94a3b8" />
          <YAxis stroke="#94a3b8" tickFormatter={(v) => formatCurrency(v, currency)} />
          <Tooltip 
            cursor={{ stroke: 'rgba(139, 92, 246, 0.5)', strokeWidth: 1, strokeDasharray: '3 3' }}
            content={<CustomTooltip currency={currency} />}
          />
          <Legend wrapperStyle={{ color: '#e2e8f0', bottom: -5 }} />
          <ReferenceLine y={0} stroke="#f1f5f9" strokeWidth={1} strokeDasharray="3 3" />
          <Line 
            type="monotone" 
            dataKey="Cash Flow" 
            stroke="#2DD4BF"
            strokeWidth={2} 
            activeDot={{ r: 8, strokeWidth: 2, fill: '#0A0A0A', stroke: '#2DD4BF' }} 
            dot={{ stroke: '#2DD4BF', strokeWidth: 1, r: 4 }}
          />
          {inputs.enableCashFlowDiscounting && (
            <Line 
              type="monotone" 
              dataKey="Discounted"
              name={discountedLineName}
              stroke="#8B5CF6"
              strokeWidth={2} 
              strokeDasharray="5 5"
              activeDot={{ r: 8, strokeWidth: 2, fill: '#0A0A0A', stroke: '#8B5CF6' }} 
              dot={{ stroke: '#8B5CF6', strokeWidth: 1, r: 4 }}
            />
          )}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default CashFlowChart;

