    setShowOnboarding(false);
    localStorage.setItem('vapor_calc_onboarding_seen', 'true');
  };

  const calculatedResults: CalculatedResults = useVaporRecoveryCalculator(inputParams);

  const handleInputChange = (key: keyof InputParams, value: string | number | boolean) => {
    setInputParams(prev => ({ ...prev, [key]: value }));
  };

  const handleCurrencyChange = (newCurrency: string) => {
    const oldRate = EXCHANGE_RATES[currency];
    const newRate = EXCHANGE_RATES[newCurrency];
    if (!oldRate || !newRate) return;
    const conversionFactor = newRate / oldRate;

    setInputParams(prev => {
      const newParams = { ...prev };
      MONETARY_PARAMS.forEach(key => {
        const currentValue = newParams[key] as number;
        if (typeof currentValue === 'number') {
          (newParams[key] as number) = parseFloat((currentValue * conversionFactor).toFixed(4));
        }
      });
      return newParams;
    });

    setCurrency(newCurrency);
  };

  const handleUnitSystemToggle = () => {
    const LITER_PER_GALLON = 3.78541;
    setInputParams(prev => {
      const isGallons = prev.unitSystem === 'gallons';
      const newUnitSystem = isGallons ? 'liters' : 'gallons';

      const newAvgGasolineSold = isGallons
        ? prev.avgGasolineSold * LITER_PER_GALLON
        : prev.avgGasolineSold / LITER_PER_GALLON;

      const newGasolinePrice = isGallons
        ? prev.gasolinePrice / LITER_PER_GALLON
        : prev.gasolinePrice * LITER_PER_GALLON;

      return {
        ...prev,
        unitSystem: newUnitSystem,
        avgGasolineSold: parseFloat(newAvgGasolineSold.toFixed(2)),
        gasolinePrice: parseFloat(newGasolinePrice.toFixed(2)),
      };
    });
  };

  const handleNavigate = (page: ActivePage) => {
    setActivePage(page);
    setIsSidebarOpen(false); // Close sidebar on nav (mobile)
  };

  const handleLoadScenario = (params: InputParams) => {
    setInputParams(params);
    setActivePage('model');
  };

  const renderPage = () => {
    // Special full-screen mode for presentation
    if (activePage === 'presentation') {
        return <PresentationMode inputs={inputParams} results={calculatedResults} currency={currency} onExit={() => setActivePage('model')} />;
    }

    switch (activePage) {
      case 'model':
        return (
          // Fixed Layout for Model Dashboard
          <div className="flex flex-col lg:flex-row w-full h-full lg:overflow-hidden">
            {/* Sidebar Wrapper: 
                On desktop, it has fixed width, full height, and overflow-hidden because 
                the inner InputPanel manages its own scrollable area (keeping header sticky).
            */}
            <div className="w-full lg:w-[340px] xl:w-[380px] bg-navy-950/50 border-r border-white/5 flex-shrink-0 p-4 lg:p-6 lg:h-full lg:overflow-hidden">
              <InputPanel 
                params={inputParams} 
                onParamChange={handleInputChange} 
                currency={currency}
                onCurrencyChange={handleCurrencyChange}
              />
            </div>

            {/* Main Result Area Wrapper:
                On desktop, full height, no scroll on wrapper. ResultsPanel manages layout.
            */}
            <div className="w-full flex-1 p-4 lg:p-6 lg:h-full lg:overflow-hidden relative">
              <ResultsPanel results={calculatedResults} inputs={inputParams} currency={currency} />
            </div>
          </div>
        );
      case 'assumptions':
        return <Assumptions params={inputParams} onParamChange={handleInputChange} currency={currency} />;
      case 'sensitivity':
        return <SensitivityAnalysis baseParams={inputParams} onBaseParamChange={handleInputChange} currency={currency} />;
      case 'scenarios':
        return <ScenarioManager currentParams={inputParams} onLoad={handleLoadScenario} />;
      case 'lease-analysis':
        return <LeaseAnalysis globalParams={inputParams} currency={currency} />;
      case 'monte-carlo':
        return <MonteCarloAnalysis baseParams={inputParams} currency={currency} />;
      case 'comparison':
        return <ScenarioComparison currentParams={inputParams} currency={currency} />;
      case 'goal-seek':
        return <GoalSeekAnalysis currentParams={inputParams} onUpdateParams={setInputParams} currency={currency} />;
      case 'impact':
        return <ImpactAnalysis results={calculatedResults} inputs={inputParams} currency={currency} />;
      default:
        return null;
    }
  }

  return (
    // Outer container: h-screen fixed to viewport. 
    <div className="flex h-screen w-full bg-navy-950 text-navy-200 font-sans overflow-hidden print:bg-white print:text-black">
      <OnboardingTour isOpen={showOnboarding} onClose={handleCloseOnboarding} />

      {/* Hide Sidebar in Presentation Mode */}
      {activePage !== 'presentation' && (
        <div className="print:hidden h-full flex w-full">
            <Sidebar activePage={activePage} onNavigate={handleNavigate} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />

            {/* Main Content Area */}
            {/* Mobile: overflow-y-auto allows the whole page content to scroll underneath the fixed sidebar/header */}
            {/* Desktop: overflow-hidden prevents body scroll, relying on inner panel scrolling where needed */}
            <main className="flex-1 h-full flex flex-col relative bg-[#020617] bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900/20 via-[#020617] to-[#020617] overflow-y-auto lg:overflow-hidden supports-scrollbars:pr-2">
                {/* Mobile Header - Sticky */}
                <div className="lg:hidden sticky top-0 z-20 px-4 py-3 flex items-center justify-between border-b border-white/5 bg-navy-950/90 backdrop-blur-md">
                    <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-white -ml-2">
                        <MenuIcon className="w-6 h-6" />
                    </button>
                    <span className="font-bold text-white tracking-tight">Masar<span className="text-primary">Zero</span></span>
                    <div className="w-8"></div> {/* Spacer */}
                </div>

                <div className="flex-1 w-full relative h-full">
                    {renderPage()}
                </div>
            </main>
        </div>
      )}

      {/* Render Presentation Mode directly if active (it handles its own layout) */}
      {activePage === 'presentation' && renderPage()}

      {activePage === 'model' && <FAB unitSystem={inputParams.unitSystem} onToggle={handleUnitSystemToggle} />}

      {/* Print View Only (Hidden normally) */}
      <div className="hidden print:block p-8 bg-white text-black h-auto overflow-visible">
          <h1 className="text-3xl font-bold mb-2">MasarZero Economics Report</h1>
          <p className="mb-6 text-gray-500">{new Date().toLocaleDateString()}</p>

          <div className="grid grid-cols-2 gap-8 mb-8">
              <div className="border p-4 rounded">
                  <h2 className="font-bold text-lg mb-4 border-b pb-2">Inputs</h2>
                  <div className="space-y-2 text-sm">
                      <div className="flex justify-between"><span>Model:</span> <strong>{inputParams.businessModel}</strong></div>
                      <div className="flex justify-between"><span>Units:</span> <strong>{inputParams.unitsPerClient * inputParams.numberOfClients}</strong></div>
                      <div className="flex justify-between"><span>Term:</span> <strong>{inputParams.leaseTerm} Years</strong></div>
                  </div>
              </div>
              <div className="border p-4 rounded bg-gray-50">
                   <h2 className="font-bold text-lg mb-4 border-b pb-2">Results</h2>
                    <div className="space-y-2 text-sm">
                      <div className="flex justify-between"><span>Net Profit:</span> <strong>{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(calculatedResults.profitability.netProfit)}</strong></div>
                      <div className="flex justify-between"><span>ROI:</span> <strong>{calculatedResults.profitability.roi.toFixed(1)}%</strong></div>
                      <div className="flex justify-between"><span>NPV:</span> <strong>{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(calculatedResults.profitability.npv)}</strong></div>
                  </div>
              </div>
          </div>

          <h2 className="font-bold text-xl mb-4">Cash Flow Analysis</h2>
          <table className="w-full text-sm text-left border-collapse">
              <thead>
                  <tr className="border-b-2 border-black">
                      <th className="py-2">Year</th>
                      <th className="py-2 text-right">Cash Flow</th>
                  </tr>
              </thead>
              <tbody>
                  {calculatedResults.cashFlow.map((cf, idx) => (
                      <tr key={idx} className="border-b border-gray-200">
                          <td className="py-2">{idx}</td>
                          <td className="py-2 text-right">{new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(cf)}</td>
                      </tr>
                  ))}
              </tbody>
          </table>
      </div>
    </div>
  );
};

export default App;

