import { InputParams, CalculatedResults } from '../types';

function calculateIRR(cashFlows: number[]): number {
    let min = -1.0;
    let max = 10.0;
    let guess = 0.1;
    let npv = 0;

    // Simple Bisection for 20 iterations
    for(let i=0; i<20; i++) {
        guess = (min + max) / 2;
        npv = 0;
        for(let t=0; t<cashFlows.length; t++) {
            npv += cashFlows[t] / Math.pow(1 + guess, t);
        }
        if (npv > 0) {
            min = guess;
        } else {
            max = guess;
        }
    }
    return guess * 100;
}

// Depreciation Schedules
const MACRS_5_YEAR = [0.20, 0.32, 0.192, 0.1152, 0.1152, 0.0576];
const MACRS_7_YEAR = [0.1429, 0.2449, 0.1749, 0.1249, 0.0893, 0.0892, 0.0893, 0.0446];

export const calculateVaporRecovery = (params: InputParams): CalculatedResults => {
  const totalUnitsSold = params.unitsPerClient * params.numberOfClients;
  const LITER_PER_GALLON = 3.78541;
  const isDirectSales = params.businessModel === 'Direct Sales';
  const isLeasing = params.businessModel === 'Leasing';

  // Constants & Conversions
  const co2TonnesPerVolumeUnit = params.unitSystem === 'gallons'
    ? params.co2TonnesPerGallon
    : params.co2TonnesPerGallon / LITER_PER_GALLON;

  const durationYears = params.leaseTerm;

  // --- REVENUE CALCULATIONS ---
  // Apply Margin to Installation Cost to get Price
  const installationPricePerUnit = params.installationCostPerUnit * (1 + (params.installationMargin || 0) / 100);
  const installationRevenue = params.companyHandlesInstallation ? totalUnitsSold * installationPricePerUnit : 0;

  const salesRevenue = isDirectSales ? totalUnitsSold * params.unitSalePrice : 0;

  // --- LOAN SETUP ---
  let loanPrincipal = 0;
  let annualLoanPayment = 0;

  // Cost of the project (Investment basis)
  // Note: If company installs, they pay the cost. The revenue is separate.
  const installationCostTotal = params.companyHandlesInstallation ? totalUnitsSold * params.installationCostPerUnit : 0;

  if (params.enableFinancing) {
      const totalInvestment = (totalUnitsSold * params.unitCost) + installationCostTotal;

      const downPayment = totalInvestment * (params.loanDownPaymentPercent / 100);
      loanPrincipal = totalInvestment - downPayment;

      // PMT Calculation
      if (loanPrincipal > 0 && params.loanInterestRate > 0) {
          const r = params.loanInterestRate / 100;
          const n = params.loanTermYears;
          // Annual payment formula
          annualLoanPayment = (loanPrincipal * r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1);
      } else if (loanPrincipal > 0) {
          annualLoanPayment = loanPrincipal / params.loanTermYears;
      }
  }

  // --- LOOP ---
  let totalLeasingRevenue = 0;
  let totalRecoveredVolume = 0;
  let totalMonthlyFeeRevenue = 0;
  let totalSparePartsRevenue = 0;
  let totalLoanInterestCost = 0;
  let totalTaxableIncome = 0;
  let totalTaxes = 0;

  // Cost Aggregators
  const cogs = totalUnitsSold * params.unitCost;
  // Installation Cost (The expense to the company)
  const installationCost = installationCostTotal;
  const customerAcquisitionCost = params.customerAcquisitionCost;

  // Base Annual Costs (Year 1)
  const baseAnnualMaintenance = totalUnitsSold * params.annualMaintenanceCost;
  const baseAnnualWarranty = totalUnitsSold * params.annualWarrantyCost;
  const baseAnnualConsumables = totalUnitsSold * params.annualConsumablesCost;
  const baseAnnualOperational = totalUnitsSold * params.dailyOperationalCost * 365;
  const baseAnnualElectricityCostPerUnit = params.unitElectricityConsumptionKwhDay * 365 * params.electricityPrice;
  const baseTotalAnnualElectricity = totalUnitsSold * baseAnnualElectricityCostPerUnit;

  // Cash Flow Setup
  let initialOutflow = 0;
  if (params.enableFinancing) {
      const totalInvestment = cogs + installationCost;
      const downPayment = totalInvestment * (params.loanDownPaymentPercent / 100);
      initialOutflow = downPayment + customerAcquisitionCost;
  } else {
      initialOutflow = cogs + installationCost + customerAcquisitionCost;
  }

  // Year 0 Cashflow (Investment)
  const cashFlow: number[] = [-initialOutflow];

  // Depreciable Basis
  const depreciableBasis = cogs + installationCost;

  // Loop years
  let currentLoanBalance = loanPrincipal;

  // Aggregators for Breakdown
  let totalMaintenance = 0;
  let totalWarranty = 0;
  let totalConsumables = 0;
  let totalOperational = 0;
  let totalElectricity = 0;

  // Payback Period Logic
  let paybackPeriod = 0;
  let cumulativeCashFlow = -initialOutflow;
  let paybackFound = false;

  for (let year = 1; year <= durationYears; year++) {
    const growthFactor = Math.pow(1 + (params.volumeGrowthRate / 100), year - 1);
    const inflationFactor = Math.pow(1 + (params.inflationRate || 0) / 100, year - 1);

    // 1. REVENUE
    let yearRevenue = 0;

    // One-time Sales
    if (year === 1 && isDirectSales) yearRevenue += salesRevenue;
    if (year === 1 && params.companyHandlesInstallation) yearRevenue += installationRevenue;

    // Recurring Leasing
    const dailyVolThisYear = params.avgGasolineSold * growthFactor;
    const recoveredThisYear = dailyVolThisYear * totalUnitsSold * (params.recoveryRate / 100) * 365 * (params.machineUptime / 100);

    if (isLeasing) {
        const leaseRev = recoveredThisYear * params.gasolinePrice * (params.companyRevenueShare / 100);
        yearRevenue += leaseRev;
        totalLeasingRevenue += leaseRev;
    }
    totalRecoveredVolume += recoveredThisYear;

    // Carbon
    if (params.enableCarbonCredits && isLeasing) {
        const carbonRev = (recoveredThisYear * co2TonnesPerVolumeUnit) * params.pricePerCredit;
        yearRevenue += carbonRev;
    }

    // SaaS
    if (params.enableMonthlyFees) {
        const saasRev = totalUnitsSold * params.monthlyFeePerUnit * 12;
        yearRevenue += saasRev;
        totalMonthlyFeeRevenue += saasRev;
    }

    // Spare Parts (Direct Sales only, post warranty)
    if (isDirectSales && year > params.warrantyDurationYears) {
        const partsRev = totalUnitsSold * params.postWarrantyRevenuePerUnit * inflationFactor;
        yearRevenue += partsRev;
        totalSparePartsRevenue += partsRev;
    }

    // 2. OPEX (Apply Inflation)
    let yearOpEx = 0;

    // Inflated Costs
    const thisYearMaintenance = baseAnnualMaintenance * inflationFactor;
    const thisYearConsumables = baseAnnualConsumables * inflationFactor;
    const thisYearOperational = baseAnnualOperational * inflationFactor;
    const thisYearElectricity = baseTotalAnnualElectricity * inflationFactor; // Assuming electricity price inflates
    const thisYearWarranty = baseAnnualWarranty;

    if (isLeasing) {
         yearOpEx = thisYearMaintenance + thisYearWarranty + thisYearConsumables + thisYearOperational + thisYearElectricity;
         totalMaintenance += thisYearMaintenance;
         totalWarranty += thisYearWarranty;
         totalConsumables += thisYearConsumables;
         totalOperational += thisYearOperational;
         totalElectricity += thisYearElectricity;
    } else {
        // Direct Sales Costs
        if (year <= params.warrantyDurationYears) {
            yearOpEx += thisYearWarranty;
            totalWarranty += thisYearWarranty;
        }
    }

    // 3. EBITDA
    const ebitda = yearRevenue - yearOpEx;

    // 4. FINANCING COSTS (Interest)
    let interestPayment = 0;
    let principalPayment = 0;

    if (params.enableFinancing && year <= params.loanTermYears && currentLoanBalance > 0) {
        interestPayment = currentLoanBalance * (params.loanInterestRate / 100);
        principalPayment = annualLoanPayment - interestPayment;
        if (principalPayment > currentLoanBalance) principalPayment = currentLoanBalance; // Cap last payment
        currentLoanBalance -= principalPayment;
    }
    totalLoanInterestCost += interestPayment;

    // 5. DEPRECIATION (Non-cash expense for Tax)
    let depreciation = 0;

    if (params.depreciationMethod === 'Straight Line') {
        depreciation = (year <= params.depreciationPeriod) ? depreciableBasis / params.depreciationPeriod : 0;
    } else if (params.depreciationMethod === 'MACRS 5-Year') {
        const rate = MACRS_5_YEAR[year - 1] || 0;
        depreciation = depreciableBasis * rate;
    } else if (params.depreciationMethod === 'MACRS 7-Year') {
        const rate = MACRS_7_YEAR[year - 1] || 0;
        depreciation = depreciableBasis * rate;
    } else if (params.depreciationMethod === 'Double Declining Balance') {
        // Simplified DDB
         if (year <= params.depreciationPeriod) {
            const rate = 2 / params.depreciationPeriod;
            depreciation = depreciableBasis * rate; 
        }
    }

    // 6. TAX
    const taxableIncome = ebitda - interestPayment - depreciation;
    let tax = 0;
    if (taxableIncome > 0 && params.corporateTaxRate > 0) {
        tax = taxableIncome * (params.corporateTaxRate / 100);
    }
    totalTaxes += tax;
    totalTaxableIncome += taxableIncome;

    // 7. CASH FLOW
    const netCashFlow = yearRevenue - yearOpEx - interestPayment - principalPayment - tax;
    cashFlow.push(netCashFlow);

    // Payback Period Calculation
    if (!paybackFound) {
        const prevCumulative = cumulativeCashFlow;
        cumulativeCashFlow += netCashFlow;
        if (cumulativeCashFlow >= 0) {
            // Fraction of year needed to cover the remainder
            // Guard against division by zero if netCashFlow is 0 (unlikely but possible)
            if (netCashFlow !== 0) {
                const fraction = Math.abs(prevCumulative) / netCashFlow;
                paybackPeriod = (year - 1) + fraction;
            } else {
                paybackPeriod = year;
            }
            paybackFound = true;
        }
    }
  }

  // --- TOTALS ---
  const totalCarbonRevenue = params.enableCarbonCredits && isLeasing
    ? (totalRecoveredVolume * co2TonnesPerVolumeUnit) * params.pricePerCredit
    : 0;

  const totalRevenue = salesRevenue + totalLeasingRevenue + installationRevenue + totalCarbonRevenue + totalMonthlyFeeRevenue + totalSparePartsRevenue;

  const totalOpEx = totalMaintenance + totalWarranty + totalConsumables + totalOperational + totalElectricity;
  const totalCosts = cogs + installationCost + customerAcquisitionCost + totalOpEx + totalLoanInterestCost;

  const netProfit = totalRevenue - totalCosts - totalTaxes; // Post-tax lifetime profit

  // NPV
  let npv = 0;
  cashFlow.forEach((flow, i) => {
      npv += flow / Math.pow(1 + params.discountRate / 100, i);
  });

  // IRR
  const irr = calculateIRR(cashFlow);

  // --- IMPACT & BREAK-EVEN CALCULATIONS ---
  // ESG
  const totalCo2Saved = totalRecoveredVolume * co2TonnesPerVolumeUnit;
  // EPA Factors: 1 Tonne = 0.217 vehicles/year, 1 Tonne = 16.5 tree seedlings (10 years) -> rough approx 40-50 trees planted equivalent for simplified marketing stats
  const carsOffRoadEquiv = totalCo2Saved * 0.22;
  const treesPlantedEquiv = totalCo2Saved * 45; // Approx
  const homesPoweredEquiv = totalCo2Saved * 0.12; // Approx

  // Break Even Volume (Daily)
  // We need to find Volume V such that Revenue(V) = OpEx + (CapEx/Term)
  // Revenue Per Daily Gallon Dispensed = 
  //   (RecoveryRate * Uptime * 365) * [ (GasPrice * RevShare) + (Co2PerGal * CreditPrice) ]

  const recoveryEfficiency = (params.recoveryRate / 100) * (params.machineUptime / 100) * 365;
  const revPerRecoveredUnit = (params.gasolinePrice * (params.companyRevenueShare/100)) + 
                              (params.enableCarbonCredits ? co2TonnesPerVolumeUnit * params.pricePerCredit : 0);

  const annualRevPerDailyDispensedUnit = recoveryEfficiency * revPerRecoveredUnit;

  // Costs
  // OpEx is mostly fixed per unit (maintenance, warranty, etc).
  // Some OpEx is variable (Electricity depends on runtime? usually assumed constant daily profile).
  // Let's assume all OpEx inputs are fixed per machine regardless of volume for this Break Even calc.
  const totalFixedOpExPerYear = totalUnitsSold > 0 
    ? (baseAnnualMaintenance + baseAnnualWarranty + baseAnnualConsumables + baseAnnualOperational + baseTotalAnnualElectricity) / totalUnitsSold
    : 0;

  const totalCapExAmortizedPerYear = (totalUnitsSold > 0 && params.leaseTerm > 0)
    ? ((cogs + installationCost + customerAcquisitionCost) / params.leaseTerm) / totalUnitsSold
    : 0;

  // Break Even for OpEx only (Operating Cash Flow positive)
  let breakEvenDailyVolume = 0;
  let breakEvenTotalVolume = 0;
  let safetyMargin = 0;

  if (isLeasing && annualRevPerDailyDispensedUnit > 0) {
      breakEvenDailyVolume = totalFixedOpExPerYear / annualRevPerDailyDispensedUnit;
      // Break Even for Total ROI > 0
      breakEvenTotalVolume = (totalFixedOpExPerYear + totalCapExAmortizedPerYear) / annualRevPerDailyDispensedUnit;

      if (params.avgGasolineSold > 0) {
          safetyMargin = ((params.avgGasolineSold - breakEvenTotalVolume) / params.avgGasolineSold) * 100;
      }
  }

  return {
    totalUnitsSold,
    revenue: {
      salesRevenue,
      leasingRevenue: totalLeasingRevenue,
      installationRevenue,
      carbonCreditRevenue: totalCarbonRevenue,
      monthlyFeeRevenue: totalMonthlyFeeRevenue,
      sparePartsRevenue: totalSparePartsRevenue,
      totalRevenue,
    },
    costs: {
      cogs,
      installationCost,
      maintenanceCost: totalMaintenance,
      electricityCost: totalElectricity,
      consumablesCost: totalConsumables,
      warrantyCost: totalWarranty,
      operationalCost: totalOperational,
      customerAcquisitionCost,
      loanInterestCost: totalLoanInterestCost,
      totalCosts,
      totalTaxes,
    },
    profitability: {
      grossProfit: totalRevenue - cogs - installationCost, 
      ebitda: totalRevenue - totalOpEx - cogs - installationCost - customerAcquisitionCost,
      netProfit,
      profitMargin: totalRevenue > 0 ? (netProfit / totalRevenue) * 100 : 0,
      roi: (totalCosts + totalTaxes) > 0 ? (netProfit / (totalCosts + totalTaxes)) * 100 : 0,
      npv,
      irr,
      paybackPeriod: paybackFound ? paybackPeriod : 0,
    },
    cashFlow,
    impact: {
        totalCo2Saved,
        treesPlantedEquiv,
        carsOffRoadEquiv,
        homesPoweredEquiv,
        breakEvenDailyVolume,
        breakEvenTotalVolume,
        safetyMargin
    }
  };
};

import { describe, it, expect } from 'vitest';
import { calculateVaporRecovery } from './calculator';
import { DEFAULT_PARAMS } from './presets';
import { InputParams } from '../types';

describe('Vapor Recovery Calculator Logic', () => {

    describe('Leasing Model Profitability', () => {
        const baseParams: InputParams = {
            ...DEFAULT_PARAMS,
            businessModel: 'Leasing',
            unitsPerClient: 1,
            numberOfClients: 1,
            leaseTerm: 5,
            avgGasolineSold: 1000,
            gasolinePrice: 1.0,
            recoveryRate: 0.1, // 0.1% for simplicity in manual calc? No, inputs are usually percents like 50? 
            // DEFAULT_PARAMS uses recoveryRate: 0.5 (which usually means 0.5%). Wait, the calculator uses params.recoveryRate / 100.
            // If user enters 0.5 in UI, it means 0.5%. Let's assume standard recovery is 0.1% or 0.2% of volume?
            // Actually, vapor recovery rate is usually 0.1% to 0.2% of throughput liquid volume. 
            // In the calculator: `dailyVolThisYear * totalUnitsSold * (params.recoveryRate / 100)`
            // If I input 1, that's 1%.

            // Let's stick to easy math:
            // Volume: 1000 gal/day
            // Recovery: 0.1% (entered as 0.1) -> 1 gal/day recovered.
            // Uptime: 100%
            // Price: $1.00/gal
            // Share: 100%
            // Revenue/Year = 1 * 1.00 * 1 * 365 = $365.
        };

        it('calculates leasing revenue correctly', () => {
             const params = {
                 ...baseParams,
                 recoveryRate: 0.1, // 0.1%
                 machineUptime: 100,
                 companyRevenueShare: 100,
                 gasolinePrice: 1.0,
                 enableCarbonCredits: false,
                 enableMonthlyFees: false,
                 companyHandlesInstallation: false
             };

             const result = calculateVaporRecovery(params);
             // Expected Recovered = 1000 * 0.001 * 365 = 365 gallons/year
             // Revenue = 365 * $1.00 = $365/year
             // Term = 5 years -> Total = $1825

             // The calculator logic uses (recoveryRate / 100).
             // If I want 0.1%, I should enter 0.1.

             expect(result.revenue.leasingRevenue).toBeCloseTo(1825, 0);
        });
    });

    describe('Direct Sales Model', () => {
         const directParams: InputParams = {
            ...DEFAULT_PARAMS,
            businessModel: 'Direct Sales',
            unitsPerClient: 10,
            numberOfClients: 1,
            unitSalePrice: 20000,
            companyHandlesInstallation: false,
            warrantyDurationYears: 100 // No post-warranty revenue
        };

        it('calculates sales revenue correctly', () => {
            const result = calculateVaporRecovery(directParams);
            expect(result.revenue.salesRevenue).toBe(10 * 20000); // 200,000
            expect(result.revenue.leasingRevenue).toBe(0);
        });
    });

    describe('Loan Logic', () => {
         const loanParams: InputParams = {
            ...DEFAULT_PARAMS,
            businessModel: 'Direct Sales', // Simplify revenue side
            enableFinancing: true,
            unitCost: 10000,
            unitsPerClient: 1,
            numberOfClients: 1,
            companyHandlesInstallation: false, // No install cost
            customerAcquisitionCost: 0,
            loanDownPaymentPercent: 0,
            loanInterestRate: 10, // 10%
            loanTermYears: 2,
            leaseTerm: 2
        };

        // Principal = 10,000
        // r = 0.10
        // n = 2
        // PMT = (10000 * 0.1 * 1.1^2) / (1.1^2 - 1)
        // PMT = (1000 * 1.21) / (0.21) = 1210 / 0.21 = 5761.90
        // Total Interest = (5761.90 * 2) - 10000 = 11523.80 - 10000 = 1523.80

        it('calculates loan interest correctly', () => {
            const result = calculateVaporRecovery(loanParams);
            expect(result.costs.loanInterestCost).toBeGreaterThan(1500);
            expect(result.costs.loanInterestCost).toBeLessThan(1550);
        });
    });

    describe('Payback Period', () => {
         const paybackParams: InputParams = {
            ...DEFAULT_PARAMS,
            businessModel: 'Direct Sales',
            unitsPerClient: 1,
            unitCost: 100, // Cost 100
            unitSalePrice: 150, // Revenue 150
            companyHandlesInstallation: false,
            customerAcquisitionCost: 0,
            annualMaintenanceCost: 0,
            annualWarrantyCost: 0,
            annualConsumablesCost: 0,
            dailyOperationalCost: 0,
            unitElectricityConsumptionKwhDay: 0,
            leaseTerm: 5,
            warrantyDurationYears: 100
            // Initial Cash Flow = -100
            // Year 1 Revenue = 150. OpEx = 0.
            // Net Cash Flow Y1 = 150.
            // Cumulative Y1 = -100 + 150 = +50.
            // Payback should be < 1 year. 
            // Fraction = abs(-100) / 150 = 0.66 years.
        };

        it('calculates fractional payback period', () => {
             const result = calculateVaporRecovery(paybackParams);
             expect(result.profitability.paybackPeriod).toBeCloseTo(0.67, 1);
        });
    });

    describe('Safeguards', () => {
        const zeroParams: InputParams = {
            ...DEFAULT_PARAMS,
            unitsPerClient: 0, // No units
            numberOfClients: 0
        };

        it('handles zero units without crashing', () => {
            const result = calculateVaporRecovery(zeroParams);
            expect(result.totalUnitsSold).toBe(0);
            expect(result.profitability.roi).toBe(0); // Should handle division by zero
            expect(result.impact.breakEvenDailyVolume).toBe(0);
        });
    });
});

import React, { useState, useMemo, useEffect } from 'react';
import { InputParams, AnalyzableVariable, AnalyzableMetric } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import { SENSITIVITY_CONFIG, METRIC_CONFIG, CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';
import SensitivityChart from './SensitivityChart';
import SensitivityHeatmap from './SensitivityHeatmap';
import Card from './Card';
import Dropdown from './Dropdown';
import SliderInput from './SliderInput';
import ToggleSwitch from './ToggleSwitch';
import { AdjustmentsIcon, ChartBarIcon, TableIcon } from './icons';

interface SensitivityAnalysisProps {
  baseParams: InputParams;
  onBaseParamChange: (key: keyof InputParams, value: string | number | boolean) => void;
  currency: string;
}

type AnalysisMode = '1D' | '2D';

const SensitivityAnalysis: React.FC<SensitivityAnalysisProps> = ({ baseParams, onBaseParamChange, currency }) => {
  const [isControlsOpen, setIsControlsOpen] = useState(true);
  const [analysisMode, setAnalysisMode] = useState<AnalysisMode>('1D');

  const availableVariables = useMemo(() => {
    return (Object.keys(SENSITIVITY_CONFIG) as AnalyzableVariable[])
      .filter(key => SENSITIVITY_CONFIG[key].models.includes(baseParams.businessModel));
  }, [baseParams.businessModel]);

  const availableMetrics = useMemo(() => {
    const allMetrics = Object.keys(METRIC_CONFIG) as AnalyzableMetric[];
    if (baseParams.businessModel === 'Direct Sales') {
      return allMetrics.filter(m => m !== 'npv');
    }
    return allMetrics;
  }, [baseParams.businessModel]);

  const [analyzedVariableX, setAnalyzedVariableX] = useState<AnalyzableVariable>(availableVariables[0]);
  const [analyzedVariableY, setAnalyzedVariableY] = useState<AnalyzableVariable>(availableVariables[1] || availableVariables[0]);
  const [analyzedMetric, setAnalyzedMetric] = useState<AnalyzableMetric>(availableMetrics[0]);

  useEffect(() => {
    if (!availableVariables.includes(analyzedVariableX)) {
      setAnalyzedVariableX(availableVariables[0]);
    }
    if (!availableVariables.includes(analyzedVariableY)) {
      setAnalyzedVariableY(availableVariables[1] || availableVariables[0]);
    }
    if (!availableMetrics.includes(analyzedMetric)) {
        setAnalyzedMetric(availableMetrics[0]);
    }
  }, [availableVariables, availableMetrics, analyzedVariableX, analyzedVariableY, analyzedMetric]);

  const chartData = useMemo(() => {
    if (analysisMode === '1D') {
      if (!analyzedVariableX) return [];
      const config = SENSITIVITY_CONFIG[analyzedVariableX];
      const data = [];
      const iterations = Math.min(100, Math.floor((config.max - config.min) / config.step) + 1);
      const step = (config.max - config.min) / (iterations - 1);

      for (let i = 0; i < iterations; i++) {
        const value = config.min + i * step;
        const modifiedParams: InputParams = { ...baseParams, [analyzedVariableX]: value };
        const results = calculateVaporRecovery(modifiedParams);
        const yValue = analyzedMetric === 'totalRevenue' ? results.revenue.totalRevenue : results.profitability[analyzedMetric];
        data.push({ xValue: value, yValue });
      }
      return data;
    } else { // 2D Mode
      if (!analyzedVariableX || !analyzedVariableY) return [];
      const xConfig = SENSITIVITY_CONFIG[analyzedVariableX];
      const yConfig = SENSITIVITY_CONFIG[analyzedVariableY];
      const data = [];
      const steps = 20; // Fixed steps for performance
      const xStep = (xConfig.max - xConfig.min) / (steps - 1);
      const yStep = (yConfig.max - yConfig.min) / (steps - 1);

      for (let i = 0; i < steps; i++) {
        const xValue = xConfig.min + i * xStep;
        for (let j = 0; j < steps; j++) {
          const yValue = yConfig.min + j * yStep;
          const modifiedParams: InputParams = { ...baseParams, [analyzedVariableX]: xValue, [analyzedVariableY]: yValue };
          const results = calculateVaporRecovery(modifiedParams);
          const zValue = analyzedMetric === 'totalRevenue' ? results.revenue.totalRevenue : results.profitability[analyzedMetric];
          data.push({ x: xValue, y: yValue, z: zValue, xLabel: xConfig.label, yLabel: yConfig.label, xUnit: xConfig.unit, yUnit: yConfig.unit });
        }
      }
      return data;
    }
  }, [analysisMode, analyzedVariableX, analyzedVariableY, analyzedMetric, baseParams]);

  const isGasAnalysisActive = useMemo(() => {
    const activeVars = [analyzedVariableX];
    if (analysisMode === '2D') {
      activeVars.push(analyzedVariableY);
    }
    return activeVars.includes('gasolinePrice') || activeVars.includes('recoveryRate');
  }, [analysisMode, analyzedVariableX, analyzedVariableY]);

  const { annualGasolineRecovered, unitSystemLabel } = useMemo(() => {
      if (baseParams.businessModel !== 'Leasing') return { annualGasolineRecovered: 0, unitSystemLabel: '' };
      const totalUnitsSold = baseParams.unitsPerClient * baseParams.numberOfClients;
      const recovered = baseParams.avgGasolineSold * totalUnitsSold * (baseParams.recoveryRate / 100) * 365 * (baseParams.machineUptime / 100);
      const label = baseParams.unitSystem === 'gallons' ? 'Gallons' : 'Liters';
      return {
          annualGasolineRecovered: recovered,
          unitSystemLabel: label,
      };
  }, [baseParams]);

  const xConfig = SENSITIVITY_CONFIG[analyzedVariableX];
  const yConfig = SENSITIVITY_CONFIG[analyzedVariableY];
  const metricConfig = METRIC_CONFIG[analyzedMetric];

  return (
    <div className="w-full h-full flex flex-col p-6 lg:p-8 overflow-y-auto custom-scrollbar">
      <div className="flex-shrink-0 flex items-center justify-between mb-2">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
             {analysisMode === '1D' && <ChartBarIcon className="w-8 h-8 text-primary" />}
             {analysisMode === '2D' && <TableIcon className="w-8 h-8 text-primary" />}
             Sensitivity Analysis
          </h1>
          <p className="text-md text-navy-400 mt-1">
            Visualize how key variables affect profitability.
          </p>
        </div>
         <div className="flex items-center space-x-2">
           <button 
             className="flex items-center space-x-2 px-4 py-2 bg-primary text-navy-950 rounded-lg text-sm font-bold hover:bg-primary-light transition-colors"
             onClick={() => setIsControlsOpen(!isControlsOpen)}
           >
            <AdjustmentsIcon className="w-5 h-5"/>
            <span>Controls</span>
           </button>
        </div>
      </div>

      {isControlsOpen && (
         <div className="flex-shrink-0 my-6 bg-card border border-white/10 p-6 rounded-xl">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="lg:col-span-2">
                    <label className="block text-sm font-medium text-navy-200 mb-2">Analysis Mode</label>
                    <div className="flex items-center p-1 space-x-1 bg-navy-900 rounded-lg">
                        {(['1D', '2D'] as AnalysisMode[]).map(mode => (
                            <button 
                                key={mode}
                                onClick={() => setAnalysisMode(mode)}
                                className={`w-full py-2 text-sm font-medium leading-5 rounded-md transition-colors duration-200 flex items-center justify-center gap-2
                                ${analysisMode === mode 
                                    ? 'bg-navy-950 shadow text-white border border-white/10' 
                                    : 'text-navy-400 hover:bg-white/5 hover:text-white'
                                }`}
                            >
                                {mode === '1D' && <ChartBarIcon className="w-4 h-4"/>}
                                {mode === '2D' && <TableIcon className="w-4 h-4" />}
                                <span>{mode}</span>
                            </button>
                        ))}
                    </div>
                </div>
                <div>
                    <Dropdown
                        label="Metric to Analyze"
                        options={availableMetrics.map(key => ({ value: key, label: METRIC_CONFIG[key].label }))}
                        value={analyzedMetric}
                        onChange={(val) => setAnalyzedMetric(val)}
                    />
                </div>
                <div>
                     <Dropdown
                        label="Business Model"
                        options={[ {value: 'Leasing', label: 'Leasing'}, {value: 'Direct Sales', label: 'Direct Sales'} ]}
                        value={baseParams.businessModel}
                        onChange={(val) => onBaseParamChange('businessModel', val)}
                    />
                </div>

                <>
                    <div>
                        <Dropdown
                            label={analysisMode === '1D' ? "Variable to Analyze" : "X-Axis Variable"}
                            options={availableVariables.map(key => ({ value: key, label: SENSITIVITY_CONFIG[key].label }))}
                            value={analyzedVariableX}
                            onChange={(val) => setAnalyzedVariableX(val)}
                        />
                    </div>
                    {analysisMode === '2D' && (
                        <div>
                            <Dropdown
                                label="Y-Axis Variable"
                                options={availableVariables.filter(v => v !== analyzedVariableX).map(key => ({ value: key, label: SENSITIVITY_CONFIG[key].label }))}
                                value={analyzedVariableY}
                                onChange={(val) => setAnalyzedVariableY(val)}
                            />
                        </div>
                    )}
                </>
            </div>
         </div>
      )}

      {/* Main Chart Area */}
      <div className="h-[500px] mb-8 shrink-0 bg-glass-200 border border-glass-border rounded-xl p-4">
        {analysisMode === '1D' && (
          <SensitivityChart 
            data={chartData}
            xKey="xValue"
            yKey="yValue"
            xLabel={`${xConfig?.label || ''} ${xConfig?.unit ? `(${xConfig.unit})` : ''}`}
            yLabel={metricConfig?.label || ''}
            currency={currency}
          />
        )}
        {analysisMode === '2D' && (
          <SensitivityHeatmap 
            data={chartData}
            xConfig={xConfig}
            yConfig={yConfig}
            metric={analyzedMetric}
            currency={currency}
          />
        )}
      </div>

       <div className="flex-shrink-0 mt-8 mb-8">
        <h3 className="text-xl font-bold text-white mb-4">Quick Parameters</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {isGasAnalysisActive && baseParams.businessModel === 'Leasing' ? (
              <Card title="Key Revenue Drivers" description="Adjust other variables in the revenue formula.">
                  <SliderInput
                      label="Units per Client"
                      value={baseParams.unitsPerClient}
                      min={1} max={200} step={1}
                      onChange={(v) => onBaseParamChange('unitsPerClient', v)}
                  />
                  <SliderInput
                      label="Company Revenue Share"
                      value={baseParams.companyRevenueShare}
                      min={10} max={90} step={5}
                      unit="%"
                      onChange={(v) => onBaseParamChange('companyRevenueShare', v)}
                  />
              </Card>
          ) : (
              <Card title="Base Scenario Snapshot" description="Key operational assumptions for this analysis.">
                  <div className="space-y-4">
                      <div className="flex justify-between items-center text-sm">
                          <span className="text-navy-300">Gasoline Price</span>
                          <span className="font-bold text-white">{new Intl.NumberFormat('en-US', { style: 'currency', currency: currency, minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(baseParams.gasolinePrice)} / {unitSystemLabel}</span>
                      </div>
