import React, { useState } from 'react';
import { InputParams, CalculatedResults } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import Card from './Card';
import { AdjustmentsIcon } from './icons';

interface GoalSeekAnalysisProps {
  currentParams: InputParams;
  onUpdateParams: (params: InputParams) => void;
  currency: string;
}

type GoalMetric = 'irr' | 'npv' | 'netProfit' | 'roi';
type AdjustableVariable = 'gasolinePrice' | 'companyRevenueShare' | 'avgGasolineSold' | 'unitSalePrice' | 'installationMargin';

const GoalSeekAnalysis: React.FC<GoalSeekAnalysisProps> = ({ currentParams, onUpdateParams, currency }) => {
  const [targetMetric, setTargetMetric] = useState<GoalMetric>('irr');
  const [targetValue, setTargetValue] = useState<number>(25); // Default target 25% IRR
  const [adjustableVariable, setAdjustableVariable] = useState<AdjustableVariable>('gasolinePrice');
  const [isSolving, setIsSolving] = useState(false);
  const [progress, setProgress] = useState(0);
  const [result, setResult] = useState<{ found: boolean, value: number, steps: number } | null>(null);

  const formatTargetValue = (val: number) => {
      if (targetMetric === 'irr' || targetMetric === 'roi') return val + '%';
      return new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);
  };

  const getMetricValue = (res: CalculatedResults, metric: GoalMetric) => {
      return res.profitability[metric];
  };

  const solve = () => {
      setIsSolving(true);
      setResult(null);
      setProgress(0);

      // Wrap in setTimeout to allow UI to render the "Solving" state
      setTimeout(() => {
          let low = 0;
          let high = 0;

          // Set reasonable bounds based on variable
          if (adjustableVariable === 'gasolinePrice') { high = 20; }
          else if (adjustableVariable === 'companyRevenueShare') { high = 100; }
          else if (adjustableVariable === 'avgGasolineSold') { low = 1000; high = 500000; }
          else if (adjustableVariable === 'unitSalePrice') { high = 500000; }
          else if (adjustableVariable === 'installationMargin') { low = -50; high = 500; }

          let iterations = 0;
          const maxIterations = 100;
          let bestGuess = low;
          let found = false;

          // Binary Search with Progress Emulation
          const interval = setInterval(() => {
              if (iterations >= maxIterations) {
                  clearInterval(interval);
                  finish(bestGuess, false, iterations);
                  return;
              }

              iterations++;
              const mid = (low + high) / 2;
              const testParams = { ...currentParams, [adjustableVariable]: mid };
              const res = calculateVaporRecovery(testParams);
              const val = getMetricValue(res, targetMetric);

              // Check if close enough (within 1% or 100 units)
              const tolerance = (targetMetric === 'irr' || targetMetric === 'roi') ? 0.05 : 50;

              if (Math.abs(val - targetValue) < tolerance) {
                  clearInterval(interval);
                  finish(mid, true, iterations);
                  return;
              }

              // Determine direction (assuming monotonic functions which most of these are)
              // Test a small delta to determine slope
              const deltaParams = { ...currentParams, [adjustableVariable]: mid + (mid * 0.01 || 0.01) };
              const deltaRes = calculateVaporRecovery(deltaParams);
              const deltaVal = getMetricValue(deltaRes, targetMetric);
              const increasing = deltaVal > val;

              if (val < targetValue) {
                  if (increasing) low = mid;
                  else high = mid;
              } else {
                  if (increasing) high = mid;
                  else low = mid;
              }
              bestGuess = mid;
              setProgress(Math.round((iterations / maxIterations) * 100));

          }, 5); // Fast interval

          const finish = (val: number, isFound: boolean, steps: number) => {
              setResult({ found: isFound, value: val, steps: steps });
              setIsSolving(false);
              setProgress(100);
          };

      }, 100);
  };

  const applySolution = () => {
      if (result) {
          onUpdateParams({ ...currentParams, [adjustableVariable]: result.value });
      }
  };

  return (
    <div className="p-6 lg:p-8 w-full max-w-4xl mx-auto h-full overflow-y-auto custom-scrollbar">
        <div className="flex items-center space-x-4 mb-8">
            <div className="p-3 bg-secondary rounded-xl shadow-glow">
                <AdjustmentsIcon className="w-8 h-8 text-white" />
            </div>
            <div>
                <h1 className="text-3xl font-bold text-white">Goal Seek</h1>
                <p className="text-navy-400 mt-1">Reverse engineer your model to find the required inputs for a target outcome.</p>
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <Card title="Target Configuration">
                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-navy-400 uppercase tracking-widest mb-2">I want to achieve a...</label>
                        <select 
                            value={targetMetric}
                            onChange={(e) => setTargetMetric(e.target.value as GoalMetric)}
                            className="w-full bg-navy-900 border border-white/20 rounded-lg px-3 py-2 text-white"
                        >
                            <option value="irr">IRR (Internal Rate of Return)</option>
                            <option value="npv">NPV (Net Present Value)</option>
                            <option value="netProfit">Net Profit (Lifetime)</option>
                            <option value="roi">ROI (Return on Investment)</option>
                        </select>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-navy-400 uppercase tracking-widest mb-2">Of...</label>
                        <div className="flex items-center">
                            <input 
                                type="number" 
                                value={targetValue}
                                onChange={(e) => setTargetValue(parseFloat(e.target.value))}
                                className="w-full bg-navy-900 border border-white/20 rounded-lg px-3 py-2 text-white"
                            />
                            <span className="ml-3 font-bold text-white w-12">{targetMetric === 'irr' || targetMetric === 'roi' ? '%' : ''}</span>
                        </div>
                    </div>

                    <div className="border-t border-white/10 pt-4 mt-4">
                        <label className="block text-xs font-bold text-navy-400 uppercase tracking-widest mb-2">By Adjusting...</label>
                         <select 
                            value={adjustableVariable}
                            onChange={(e) => setAdjustableVariable(e.target.value as AdjustableVariable)}
                            className="w-full bg-navy-900 border border-white/20 rounded-lg px-3 py-2 text-white"
                        >
                            <option value="gasolinePrice">Gasoline Price</option>
                            <option value="companyRevenueShare">Revenue Share %</option>
                            <option value="avgGasolineSold">Daily Volume</option>
                            <option value="unitSalePrice">Unit Sale Price</option>
                            <option value="installationMargin">Installation Margin</option>
                        </select>
                    </div>

                    <button 
                        onClick={solve}
                        disabled={isSolving}
                        className="w-full bg-primary hover:bg-primary-dark text-navy-950 font-bold py-3 rounded-lg shadow-lg transition-all mt-2 disabled:opacity-50 relative overflow-hidden"
                    >
                        {isSolving && (
                            <div className="absolute inset-0 bg-primary-dark/20">
                                <div className="h-full bg-primary-light/30 transition-all duration-100" style={{ width: `${progress}%` }}></div>
                            </div>
                        )}
                        <span className="relative z-10">{isSolving ? 'Calculating...' : 'Find Solution'}</span>
                    </button>
                </div>
            </Card>

            <div className="space-y-6">
                <Card title="Results" className={result ? 'border-primary/50' : ''}>
                    {result ? (
                        <div className="text-center py-6 animate-in fade-in slide-in-from-bottom-4">
                            <div className="text-navy-400 text-sm mb-2">Required Value for {adjustableVariable}</div>
                            <div className="text-4xl font-black text-white mb-2">
                                {['companyRevenueShare', 'installationMargin'].includes(adjustableVariable) 
                                    ? result.value.toFixed(1) + '%' 
                                    : adjustableVariable === 'avgGasolineSold'
                                        ? Math.round(result.value).toLocaleString()
                                        : new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(result.value)
                                }
                            </div>
                            <div className="text-xs text-navy-500 mb-6">
                                {result.found ? 'Exact solution found' : 'Best approximate found'} in {result.steps} iterations.
                            </div>

                            <button 
                                onClick={applySolution}
                                className="bg-white/10 hover:bg-white/20 text-white px-6 py-2 rounded-lg text-sm font-bold transition-colors border border-white/10"
                            >
                                Apply to Model
                            </button>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-48 text-navy-500">
                            <AdjustmentsIcon className="w-12 h-12 mb-3 opacity-20" />
                            <p>Run the solver to see results.</p>
                        </div>
                    )}
                </Card>
            </div>
        </div>
    </div>
  );
};

export default GoalSeekAnalysis;

import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceLine, Cell, CartesianGrid } from 'recharts';
import { InputParams, CalculatedResults } from '../types';
import { calculateVaporRecovery } from '../utils/calculator';
import Card from './Card';
import SliderInput from './SliderInput';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';

interface MonteCarloAnalysisProps {
  baseParams: InputParams;
  currency: string;
}

const formatCurrency = (val: number, currency: string) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact' }).format(val);

const MonteCarloAnalysis: React.FC<MonteCarloAnalysisProps> = ({ baseParams, currency }) => {
  const [uncertainty, setUncertainty] = useState(15); // +/- %
  const [simulationCount, setSimulationCount] = useState(500);
  const [isSimulating, setIsSimulating] = useState(false);
  const [results, setResults] = useState<number[]>([]);

  const runSimulation = () => {
      setIsSimulating(true);
      // Use setTimeout to allow UI to render loading state
      setTimeout(() => {
          const newResults: number[] = [];

          for(let i=0; i<simulationCount; i++) {
              // Perturb key inputs
              // Using Uniform Distribution: Base * (1 + (Math.random() - 0.5) * 2 * uncertainty/100)

              const vary = (val: number) => val * (1 + (Math.random() - 0.5) * 2 * (uncertainty / 100));

              const simParams = { ...baseParams };

              // Variables to perturb
              simParams.avgGasolineSold = vary(baseParams.avgGasolineSold);
              simParams.gasolinePrice = vary(baseParams.gasolinePrice);
              simParams.recoveryRate = Math.min(100, Math.max(0, vary(baseParams.recoveryRate))); // Clamp 0-100

              const res = calculateVaporRecovery(simParams);
              newResults.push(res.profitability.netProfit);
          }

          setResults(newResults.sort((a,b) => a - b));
          setIsSimulating(false);
      }, 50);
  };

  const histogramData = useMemo(() => {
      if (results.length === 0) return [];

      const min = results[0];
      const max = results[results.length - 1];
      const binCount = 20;
      const binSize = (max - min) / binCount;

      const bins = Array.from({ length: binCount }, (_, i) => ({
          rangeStart: min + i * binSize,
          rangeEnd: min + (i + 1) * binSize,
          name: formatCurrency(min + i * binSize + binSize/2, currency), // Label center
          count: 0
      }));

      results.forEach(val => {
          const binIndex = Math.min(binCount - 1, Math.floor((val - min) / binSize));
          bins[binIndex].count++;
      });

      return bins;
  }, [results, currency]);

  const stats = useMemo(() => {
      if (results.length === 0) return null;
      const sum = results.reduce((a, b) => a + b, 0);
      const avg = sum / results.length;
      const positiveCount = results.filter(r => r > 0).length;
      const probSuccess = (positiveCount / results.length) * 100;

      return {
          avg,
          min: results[0],
          max: results[results.length - 1],
          probSuccess
      };
  }, [results]);

  return (
    <div className="p-6 lg:p-8 w-full max-w-6xl mx-auto h-full overflow-y-auto custom-scrollbar">
        <div className="flex justify-between items-center mb-8">
            <div>
                <h1 className="text-3xl font-bold text-white">Monte Carlo Simulation</h1>
                <p className="text-navy-400 mt-1">Probabilistic risk assessment based on input uncertainty.</p>
            </div>
            <button
                onClick={runSimulation}
                disabled={isSimulating}
                className="bg-primary hover:bg-primary-dark text-navy-950 font-bold px-6 py-3 rounded-xl transition-all shadow-lg hover:shadow-primary/30 disabled:opacity-50"
            >
                {isSimulating ? 'Running...' : 'Run Simulation'}
            </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
            <div className="lg:col-span-1 space-y-6">
                <Card title="Configuration">
                    <SliderInput 
                        label="Uncertainty Range (+/- %)"
                        value={uncertainty}
                        min={5} max={50} step={5}
                        unit="%"
                        onChange={setUncertainty}
                        description="Variability applied to Volume, Price, and Recovery Rate."
                    />
                     <div className="mt-4">
                        <label className="text-xs text-navy-400 font-bold uppercase">Iterations</label>
                        <select 
                            value={simulationCount}
                            onChange={(e) => setSimulationCount(parseInt(e.target.value))}
                            className="w-full bg-navy-900 border border-white/20 rounded mt-2 px-3 py-2 text-white"
                        >
                            <option value="100">100 Runs (Fast)</option>
                            <option value="500">500 Runs (Balanced)</option>
                            <option value="1000">1000 Runs (Precise)</option>
                        </select>
                     </div>
                </Card>

                {stats && (
                    <Card title="Results Summary" className="bg-gradient-to-br from-navy-900 to-navy-950">
                        <div className="space-y-4">
                            <div>
                                <div className="text-navy-400 text-xs uppercase tracking-wider">Probability of Profit</div>
                                <div className={`text-4xl font-black ${stats.probSuccess > 80 ? 'text-success' : stats.probSuccess > 50 ? 'text-warning' : 'text-danger'}`}>
                                    {stats.probSuccess.toFixed(1)}%
                                </div>
                            </div>
                             <div>
                                <div className="text-navy-400 text-xs uppercase tracking-wider">Average Net Outcome</div>
                                <div className="text-xl font-bold text-white">
                                    {formatCurrency(stats.avg, currency)}
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4 pt-2 border-t border-white/10">
                                <div>
                                    <div className="text-navy-500 text-[10px] uppercase">Worst Case</div>
                                    <div className="text-danger font-mono font-bold">{formatCurrency(stats.min, currency)}</div>
                                </div>
                                <div>
                                    <div className="text-navy-500 text-[10px] uppercase">Best Case</div>
                                    <div className="text-success font-mono font-bold">{formatCurrency(stats.max, currency)}</div>
                                </div>
                            </div>
                        </div>
                    </Card>
                )}
            </div>

            <div className="lg:col-span-2 h-[500px] bg-card border border-white/10 rounded-2xl p-4">
                {results.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={histogramData} margin={{ top: 20, right: 10, left: 10, bottom: 40 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.1)" />
                            <XAxis 
                                dataKey="name" 
                                stroke="#94a3b8" 
                                tick={{fontSize: 10}}
                                interval={Math.floor(histogramData.length / 5)} // Prevent overlapping
                                angle={-45}
                                textAnchor="end"
                            />
                            <YAxis stroke="#94a3b8" />
                            <Tooltip 
                                cursor={{fill: 'rgba(255,255,255,0.05)'}}
                                contentStyle={{backgroundColor: '#0f172a', borderColor: '#334155', color: '#fff'}}
                            />
                            <ReferenceLine x={0} stroke="white" />
                            <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                                {histogramData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.rangeStart < 0 ? '#ef4444' : '#10b981'} />
                                ))}
                            </Bar>
                        </BarChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="h-full flex flex-col items-center justify-center text-navy-500">
                        <p>No simulation data.</p>
                        <button onClick={runSimulation} className="text-primary hover:underline mt-2">Run Simulation</button>
                    </div>
                )}
            </div>
        </div>

        {/* Methodology Explanation */}
        <div className="bg-navy-900/50 p-6 rounded-xl border border-white/5 mb-12">
            <h3 className="text-lg font-bold text-white mb-2">Methodology</h3>
            <p className="text-sm text-navy-300 leading-relaxed">
                This Monte Carlo simulation performs {simulationCount} random iterations to estimate the probability distribution of your project's Net Profit.
                For each iteration, the calculator randomly varies three key inputs—<strong>Gasoline Volume</strong>, <strong>Gasoline Price</strong>, and <strong>Recovery Rate</strong>—within the specified "Uncertainty Range" (Uniform Distribution).
            </p>
        </div>
    </div>
  );
};

