import React, { useState, useMemo, useEffect } from 'react';
import { CalculatedResults, InputParams, TooltipInfo } from '../types';
import ResultRow from './ResultRow';
import ProfitWaterfallChart from './ProfitabilityChart';
import CashFlowChart from './CashFlowChart';
import RevenueBreakdownChart from './RevenueBreakdownChart';
import MetricDisplay from './MetricDisplay';
import SliderInput from './SliderInput';
import { DownloadIcon, TableIcon } from './icons';

interface ResultsPanelProps {
  results: CalculatedResults;
  inputs: InputParams;
  currency: string;
}

type ChartView = 'Profit Waterfall' | 'Cash Flow' | 'Revenue Breakdown' | 'Ledger';

const formatCurrency = (value: number, currency: string) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency,
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const formatCurrencyCompact = (value: number, currency: string) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency,
    notation: "compact",
    compactDisplay: "short",
    maximumFractionDigits: 1
  }).format(value);
};

const formatPercent = (value: number) => {
  return `${value.toFixed(1)}%`;
};

const ResultsPanel: React.FC<ResultsPanelProps> = ({ results, inputs, currency }) => {
  const [activeTab, setActiveTab] = useState<ChartView>('Profit Waterfall');
  const [selectedYear, setSelectedYear] = useState(inputs.leaseTerm);
  const { revenue, costs, profitability } = results;
  const isLeasing = inputs.businessModel === 'Leasing';

  useEffect(() => {
    if (isLeasing && activeTab === 'Profit Waterfall') setActiveTab('Cash Flow');
    if (!isLeasing && activeTab === 'Cash Flow') setActiveTab('Profit Waterfall');
    setSelectedYear(inputs.leaseTerm);
  }, [inputs.leaseTerm, inputs.businessModel]);

  const handlePrintPDF = () => {
      window.print();
  };

  // Generate Year-by-Year Data for Table
  const yearlyData = useMemo(() => {
      const years = [];
      const term = inputs.leaseTerm;
      const growthRate = inputs.volumeGrowthRate / 100;
      const inflationRate = (inputs.inflationRate || 0) / 100;

      // Initial Investment (Year 0)
      years.push({
          year: 0,
          revenue: 0,
          opex: 0,
          capex: costs.cogs + costs.installationCost + costs.customerAcquisitionCost,
          tax: 0,
          net: -(costs.cogs + costs.installationCost + costs.customerAcquisitionCost)
      });

      for (let i = 1; i <= term; i++) {
          // Re-simulate logic simplified for display (Ideally this logic resides in calculator.ts and returns array of objects)
          // For visualization purposes, we can estimate from totals if we assume linear/growth curves, 
          // BUT `results.cashFlow` already has the net values.
          // To be precise, we need the components.
          // Since calculator.ts returns totals, we can approximate the breakdown here or rely on cashFlow array for Net.
          // Let's use the cashFlow array for Net, and estimate components based on growth/inflation.

          const growthFactor = Math.pow(1 + growthRate, i - 1);
          const inflationFactor = Math.pow(1 + inflationRate, i - 1);

          // Estimate proportional revenue
          // This is an approximation for display. For strict auditing, calculator.ts should return detailed yearly arrays.
          // Given the constraint, we will show "Net Cash Flow" from the accurate array, and "Est Revenue/Cost"

          const net = results.cashFlow[i]; 
          years.push({
              year: i,
              net: net,
              // We don't have granular breakdown per year from current `CalculatedResults` interface for display.
              // To solve this properly, we'd refactor `calculator.ts`, but we can just display the Net Flow for now which is 100% accurate.
          });
      }
      return years;
  }, [results, inputs]);

  const handleExportCSV = () => {
      const header = ['Year', 'Net Cash Flow', 'Cumulative Cash Flow'];
      let cumulative = 0;
      const rows = yearlyData.map(y => {
          cumulative += y.net;
          return [y.year, y.net.toFixed(2), cumulative.toFixed(2)];
      });

      // Add Summary Stats at bottom
      rows.push([]);
      rows.push(['Total Net Profit', profitability.netProfit.toFixed(2)]);
      rows.push(['ROI', profitability.roi.toFixed(2) + '%']);
      rows.push(['NPV', profitability.npv.toFixed(2)]);

      const csvContent = "data:text/csv;charset=utf-8," + [header, ...rows].map(e => e.join(",")).join("\n");
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `MasarZero_Financial_Model_${new Date().toISOString().slice(0,10)}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col space-y-4 lg:space-y-6 w-full h-full lg:pb-0 pb-24">

      {/* 1. HERO METRICS SECTION */}
      <div id="hero-metrics" className="grid grid-cols-2 lg:grid-cols-4 gap-3 lg:gap-4 flex-shrink-0">
         <MetricDisplay 
            label="Net Profit" 
            value={formatCurrencyCompact(profitability.netProfit, currency)}
            highlight={profitability.netProfit >= 0 ? 'net-profit-gain' : 'net-profit-loss'}
            variant="hero"
            tooltip={{ title: "Net Profit", shortText: "Net Profit", details: "Total revenue minus all costs and taxes over the lifetime of the project." }}
          />
           <MetricDisplay 
            label="Total ROI" 
            value={formatPercent(profitability.roi)}
            highlight="roi"
            variant="hero"
            tooltip={{ title: "Total ROI", shortText: "Total ROI", details: "Total Return on Investment = (Lifetime Net Profit / Total Costs) * 100." }}
          />
           <MetricDisplay 
              label="NPV" 
              value={formatCurrencyCompact(profitability.npv, currency)}
              highlight="npv"
              variant="hero"
              tooltip={{ title: "Net Present Value", shortText: "NPV", details: "The value of all future cash flows discounted to today's dollars." }}
          />
           <MetricDisplay 
            label="IRR" 
            value={formatPercent(profitability.irr)}
            variant="hero"
            highlight="profit-margin"
            tooltip={{ title: "Internal Rate of Return", shortText: "IRR", details: "The annual growth rate that the project is expected to generate." }}
          />
      </div>

      {/* 2. VISUALIZATION SECTION */}
      <div id="charts-container" className="flex-1 min-h-[400px] w-full bg-glass-200 backdrop-blur-xl border border-glass-border rounded-2xl shadow-glass flex flex-col transition-all duration-300">
          <div className="p-3 lg:p-4 border-b border-glass-border flex flex-col sm:flex-row justify-between items-center gap-3 lg:gap-4 bg-glass-100 flex-shrink-0 rounded-t-2xl">
             <div className="flex space-x-1 bg-navy-950/50 p-1 rounded-lg border border-white/5 overflow-x-auto max-w-full no-scrollbar">
                  {(['Profit Waterfall', 'Cash Flow', 'Revenue Breakdown', 'Ledger'] as ChartView[])
                    .filter(tab => isLeasing ? true : tab !== 'Cash Flow')
                    .map(tab => (
                      <button 
                          key={tab}
                          onClick={() => setActiveTab(tab)}
                          className={`px-3 lg:px-4 py-1.5 text-[10px] lg:text-xs font-bold uppercase tracking-wider rounded-md transition-all duration-200 whitespace-nowrap ${
                              activeTab === tab 
                              ? 'bg-gradient-primary text-white shadow-glow' 
                              : 'text-navy-400 hover:text-white hover:bg-white/5'
                          }`}
                      >
                          {tab}
                      </button>
                  ))}
              </div>

              <div className="flex items-center space-x-2">
                 <button 
                    onClick={handleExportCSV}
                    className="flex items-center space-x-2 text-xs font-bold text-navy-200 bg-white/5 hover:bg-white/10 hover:text-white transition-colors uppercase tracking-wider px-3 py-1.5 rounded-lg border border-white/10"
                    title="Download raw data for Excel"
                  >
                      <TableIcon className="w-4 h-4" />
                      <span className="hidden sm:inline">CSV</span>
                  </button>
                  <button 
                    id="executive-report-btn"
                    onClick={handlePrintPDF}
                    className="flex items-center space-x-2 text-xs font-bold text-white bg-gradient-primary hover:brightness-110 transition-colors uppercase tracking-wider px-3 py-1.5 rounded-lg shadow-lg"
                  >
                      <DownloadIcon className="w-4 h-4" />
                      <span className="hidden sm:inline">Report</span>
                  </button>
              </div>
          </div>

          <div className="flex-1 relative p-2 lg:p-4 min-h-0 overflow-hidden">
              {activeTab === 'Profit Waterfall' && (
                  <div className="w-full h-full">
                      <ProfitWaterfallChart results={results} currency={currency} />
                  </div>
              )}
              {activeTab === 'Cash Flow' && (
                  <div className="w-full h-full">
                      <CashFlowChart results={results} currency={currency} inputs={inputs} />
                  </div>
              )}
              {activeTab === 'Revenue Breakdown' && (
                  <div className="w-full h-full">
                      <RevenueBreakdownChart results={results} currency={currency} />
                  </div>
              )}
              {activeTab === 'Ledger' && (
                   <div className="h-full w-full overflow-hidden flex flex-col">
                        <div className="overflow-auto custom-scrollbar flex-1 w-full border border-white/10 rounded-lg">
                            <table className="w-full text-sm text-left text-navy-200 min-w-[400px]">
                                <thead className="text-xs text-white uppercase bg-white/5 sticky top-0 z-10">
                                    <tr>
                                        <th className="px-6 py-3 font-bold">Year</th>
                                        <th className="px-6 py-3 font-bold text-right">Net Cash Flow</th>
                                        <th className="px-6 py-3 font-bold text-right">Cumulative</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-white/5">
                                    {yearlyData.map((year, idx) => {
                                        // Calculate cumulative for display
                                        const cumulative = yearlyData.slice(0, idx + 1).reduce((sum, y) => sum + y.net, 0);
                                        return (
                                            <tr key={year.year} className="hover:bg-white/5 transition-colors">
                                                <td className="px-6 py-3 font-medium text-white">{year.year === 0 ? 'Start' : `Year ${year.year}`}</td>
                                                <td className={`px-6 py-3 text-right font-mono ${year.net >= 0 ? 'text-success' : 'text-danger'}`}>
                                                    {formatCurrency(year.net, currency)}
                                                </td>
                                                <td className={`px-6 py-3 text-right font-mono font-bold ${cumulative >= 0 ? 'text-white' : 'text-navy-400'}`}>
                                                    {formatCurrency(cumulative, currency)}
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                        <div className="mt-4 text-xs text-navy-400 text-center">
                            * Detailed line-item breakdown available via CSV export.
                        </div>
                   </div>
              )}
          </div>
      </div>
    </div>
  );
};

