import React, { useMemo } from 'react';
import { CalculatedResults, InputParams } from '../types';
import { ShieldCheckIcon, TreeIcon, LightningIcon, AdjustmentsIcon } from './icons';

interface SmartInsightsProps {
  results: CalculatedResults;
  inputs: InputParams;
  currency: string;
}

const SmartInsights: React.FC<SmartInsightsProps> = ({ results, inputs, currency }) => {
  const insights = useMemo(() => {
    const list = [];
    const { profitability, impact, costs } = results;

    // 1. Payback Insight
    if (profitability.paybackPeriod > inputs.leaseTerm) {
        list.push({
            type: 'danger',
            title: 'ROI Risk',
            message: `Payback period (${profitability.paybackPeriod.toFixed(1)}y) exceeds lease term. Consider increasing revenue share or extending the contract.`
        });
    } else if (profitability.paybackPeriod < 2) {
         list.push({
            type: 'success',
            title: 'High Velocity',
            message: `Exceptional payback period of ${profitability.paybackPeriod.toFixed(1)} years. This is a highly compelling sales argument.`
        });
    }

    // 2. OpEx Warning
    const opexRatio = (costs.maintenanceCost + costs.operationalCost + costs.electricityCost) / results.revenue.totalRevenue;
    if (opexRatio > 0.3) {
        list.push({
            type: 'warning',
            title: 'High Operational Costs',
            message: `OpEx is consuming ${(opexRatio * 100).toFixed(0)}% of revenue. Check electricity rates or maintenance assumptions.`
        });
    }

    // 3. Volume Sensitivity
    if (impact.safetyMargin < 10) {
        list.push({
            type: 'warning',
            title: 'Volume Sensitivity',
            message: `Safety margin is only ${impact.safetyMargin.toFixed(1)}%. A small drop in gasoline volume could turn ROI negative.`
        });
    }

    // 4. Pricing / Revenue Share
    if (inputs.businessModel === 'Leasing' && inputs.companyRevenueShare < 30) {
        list.push({
            type: 'info',
            title: 'Revenue Share Opportunity',
            message: `Current revenue share ( ${inputs.companyRevenueShare}%) is below industry standard. Increasing to 35% improves NPV by significant margin.`
        });
    }

    return list.slice(0, 3); // Top 3 insights
  }, [results, inputs]);

  if (insights.length === 0) return null;

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6 animate-in fade-in slide-in-from-top-4 duration-500">
        {insights.map((insight, idx) => (
            <div 
                key={idx} 
                className={`p-4 rounded-xl border flex items-start space-x-3 backdrop-blur-md
                    ${insight.type === 'success' ? 'bg-success/10 border-success/30' : 
                      insight.type === 'danger' ? 'bg-danger/10 border-danger/30' : 
                      insight.type === 'warning' ? 'bg-yellow-500/10 border-yellow-500/30' :
                      'bg-blue-500/10 border-blue-500/30'
                    }
                `}
            >
                <div className={`mt-0.5 ${
                      insight.type === 'success' ? 'text-success' : 
                      insight.type === 'danger' ? 'text-danger' : 
                      insight.type === 'warning' ? 'text-yellow-500' :
                      'text-blue-500'
                }`}>
                    {insight.type === 'success' ? <ShieldCheckIcon className="w-5 h-5"/> : 
                     insight.type === 'warning' ? <LightningIcon className="w-5 h-5"/> :
                     <AdjustmentsIcon className="w-5 h-5"/>
                    }
                </div>
                <div>
                    <h4 className={`text-xs font-bold uppercase tracking-wider mb-1 ${
                        insight.type === 'success' ? 'text-success-light' : 
                        insight.type === 'danger' ? 'text-danger-light' : 
                        insight.type === 'warning' ? 'text-yellow-200' :
                        'text-blue-200'
                    }`}>{insight.title}</h4>
                    <p className="text-sm text-white/90 leading-snug">{insight.message}</p>
                </div>
            </div>
        ))}
    </div>
  );
};

export default SmartInsights;

import React from 'react';
import { PieChart, Pie, Cell, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { CalculatedResults } from '../types';

interface CostBreakdownChartProps {
  results: CalculatedResults;
  currency: string;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, minimumFractionDigits: 0 }).format(value);
};

const CustomTooltip = ({ active, payload, currency }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0];
    return (
      <div className="bg-card border border-white/10 rounded-lg p-3 shadow-lg text-sm z-50">
        <div className="flex items-center space-x-2">
            <div className="w-3 h-3 rounded-full" style={{ backgroundColor: data.payload.fill }}></div>
            <span className="text-navy-400">{data.name}:</span>
            <span className="font-bold text-white">{formatCurrency(data.value, currency)}</span>
        </div>
      </div>
    );
  }
  return null;
};

const CostBreakdownChart: React.FC<CostBreakdownChartProps> = ({ results, currency }) => {
  const { costs } = results;

  const data = [
    { name: 'Hardware (COGS)', value: costs.cogs },
    { name: 'Installation', value: costs.installationCost },
    { name: 'Maintenance', value: costs.maintenanceCost },
    { name: 'Operations & Power', value: costs.operationalCost + costs.electricityCost },
    { name: 'Warranty & Consumables', value: costs.warrantyCost + costs.consumablesCost },
    { name: 'Taxes', value: costs.totalTaxes },
    { name: 'Loan Interest', value: costs.loanInterestCost },
  ].filter(d => d.value > 0);

  // Red/Orange/Pink Palette for Costs
  const COLORS = ['#EF4444', '#F97316', '#F59E0B', '#EC4899', '#8B5CF6', '#64748B', '#94A3B8']; 

  if (data.length === 0) {
    return <div className="flex items-center justify-center h-full text-navy-400">No cost data available.</div>
  }

  return (
    <div className="h-[350px] lg:h-full w-full min-h-[300px]">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Tooltip content={<CustomTooltip currency={currency} />} />
          <Legend wrapperStyle={{ color: '#e2e8f0', fontSize: '12px' }} />
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60} // Donut style
            outerRadius={100}
            paddingAngle={2}
            dataKey="value"
            nameKey="name"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
            ))}
          </Pie>
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

