                  </button>
              </div>
          </div>

          <div className="flex-1 relative p-2 lg:p-4 min-h-0 overflow-hidden">
              {activeTab === 'Profit Waterfall' && (
                  <div className="w-full h-full">
                      <ProfitWaterfallChart results={results} currency={currency} />
                  </div>
              )}
              {activeTab === 'Cash Flow' && (
                  <div className="w-full h-full">
                      <CashFlowChart results={results} currency={currency} inputs={inputs} />
                  </div>
              )}
              {activeTab === 'Revenue' && (
                  <div className="w-full h-full">
                      <RevenueBreakdownChart results={results} currency={currency} />
                  </div>
              )}
              {activeTab === 'Cost Structure' && (
                  <div className="w-full h-full">
                      <CostBreakdownChart results={results} currency={currency} />
                  </div>
              )}
              {activeTab === 'Ledger' && (
                   <div className="h-full w-full overflow-hidden flex flex-col">
                        <div className="overflow-auto custom-scrollbar flex-1 w-full border border-white/10 rounded-lg">
                            <table className="w-full text-sm text-left text-navy-200 min-w-[400px]">
                                <thead className="text-xs text-white uppercase bg-white/5 sticky top-0 z-10">
                                    <tr>
                                        <th className="px-6 py-3 font-bold">Year</th>
                                        <th className="px-6 py-3 font-bold text-right">Net Cash Flow</th>
                                        <th className="px-6 py-3 font-bold text-right">Cumulative</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-white/5">
                                    {yearlyData.map((year, idx) => {
                                        // Calculate cumulative for display
                                        const cumulative = yearlyData.slice(0, idx + 1).reduce((sum, y) => sum + y.net, 0);
                                        return (
                                            <tr key={year.year} className="hover:bg-white/5 transition-colors">
