import React, { useMemo, useState } from 'react';
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine } from 'recharts';
import { CalculatedResults, InputParams } from '../types';
import { ChartBarIcon, PresentationChartLineIcon } from './icons';

interface CashFlowChartProps {
  results: CalculatedResults;
  currency: string;
  inputs: InputParams;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, notation: 'compact', compactDisplay: 'short' }).format(value);
};

const CustomTooltip = ({ active, payload, label, currency }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-navy-900 border border-white/20 rounded-lg p-4 shadow-lg text-sm w-60 z-50">
        <p className="font-bold text-white text-base mb-3">{label}</p>
        {payload.map((pld: any, index: number) => (
          <div className={`flex items-center justify-between ${index > 0 ? 'mt-2' : ''}`} key={pld.dataKey}>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pld.fill || pld.stroke }} />
              <span className="text-navy-200">{pld.name}:</span>
            </div>
            <span className="font-semibold text-white">{formatCurrency(pld.value, currency)}</span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};


const CashFlowChart: React.FC<CashFlowChartProps> = ({ results, currency, inputs }) => {
  const [viewMode, setViewMode] = useState<'cumulative' | 'annual'>('cumulative');

  const data = useMemo(() => {
    let cumulativeFlow = 0;
    let cumulativeDiscountedFlow = 0;
    const discountRate = inputs.discountRate / 100;

    return results.cashFlow.map((flow, index) => {
      cumulativeFlow += flow;

      if (index === 0) { // Year 0 is initial investment
        cumulativeDiscountedFlow += flow;
      } else {
        cumulativeDiscountedFlow += flow / Math.pow(1 + discountRate, index);
      }

      const yearData: any = {
        name: index === 0 ? 'Start' : `Year ${index}`,
        'Annual Flow': flow,
        'Cumulative Flow': cumulativeFlow,
      };

      if (inputs.enableCashFlowDiscounting) {
        yearData['Discounted Cumulative'] = cumulativeDiscountedFlow;
      }

      return yearData;
    });
  }, [results.cashFlow, inputs.enableCashFlowDiscounting, inputs.discountRate]);

  if (results.cashFlow.length <= 1) {
    return <div className="flex items-center justify-center h-full text-navy-400">Cash flow is not applicable.</div>
  }

  const discountedLineName = `Discounted (${inputs.discountRate}%)`;

  return (
    <div className="h-full w-full flex flex-col">
       <div className="flex justify-end px-4 pt-2 mb-2">
            <div className="bg-navy-900 p-1 rounded-lg border border-white/10 flex space-x-1">
                <button
                    onClick={() => setViewMode('cumulative')}
                    className={`p-1.5 rounded transition-colors ${viewMode === 'cumulative' ? 'bg-primary text-white' : 'text-navy-400 hover:text-white'}`}
                    title="Cumulative View"
                >
                    <PresentationChartLineIcon className="w-4 h-4" />
                </button>
                <button
                    onClick={() => setViewMode('annual')}
                    className={`p-1.5 rounded transition-colors ${viewMode === 'annual' ? 'bg-primary text-white' : 'text-navy-400 hover:text-white'}`}
                    title="Annual View"
                >
                    <ChartBarIcon className="w-4 h-4" />
                </button>
            </div>
       </div>

      <div className="flex-1 w-full min-h-[300px]">
      <ResponsiveContainer width="100%" height="100%">
        {viewMode === 'cumulative' ? (
            <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.1)" />
            <XAxis dataKey="name" stroke="#94a3b8" tick={{fontSize: 12}} />
            <YAxis stroke="#94a3b8" tickFormatter={(v) => formatCurrency(v, currency)} tick={{fontSize: 12}} />
            <Tooltip 
                cursor={{ stroke: 'rgba(139, 92, 246, 0.5)', strokeWidth: 1, strokeDasharray: '3 3' }}
                content={<CustomTooltip currency={currency} />}
            />
            <Legend wrapperStyle={{ color: '#e2e8f0', paddingTop: '10px' }} />
            <ReferenceLine y={0} stroke="#f1f5f9" strokeWidth={1} strokeDasharray="3 3" />
            <Line 
                type="monotone" 
                dataKey="Cumulative Flow" 
                stroke="#2DD4BF"
                strokeWidth={3} 
                activeDot={{ r: 6, strokeWidth: 0, fill: '#2DD4BF' }} 
                dot={false}
            />
            {inputs.enableCashFlowDiscounting && (
                <Line 
                type="monotone" 
                dataKey="Discounted Cumulative"
                name={discountedLineName}
                stroke="#8B5CF6"
                strokeWidth={2} 
                strokeDasharray="5 5"
                activeDot={{ r: 6, strokeWidth: 0, fill: '#8B5CF6' }} 
                dot={false}
                />
            )}
            </LineChart>
        ) : (
             <BarChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.1)" vertical={false} />
                <XAxis dataKey="name" stroke="#94a3b8" tick={{fontSize: 12}} />
                <YAxis stroke="#94a3b8" tickFormatter={(v) => formatCurrency(v, currency)} tick={{fontSize: 12}} />
                <Tooltip 
                    cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                    content={<CustomTooltip currency={currency} />}
                />
                <Legend wrapperStyle={{ color: '#e2e8f0', paddingTop: '10px' }} />
                <ReferenceLine y={0} stroke="#f1f5f9" strokeWidth={1} />
                <Bar 
                    dataKey="Annual Flow" 
                    fill="#14B8A6"
                    radius={[4, 4, 0, 0]}
                >
                    {data.map((entry: any, index: number) => (
                         <React.Fragment key={`cell-${index}`}>
                             {/* Color negative bars red, positive teal */}
                            <text x={0} y={0} dy={0} fill="none" /> 
                         </React.Fragment>
                    ))}
                </Bar>
            </BarChart>
        )}
      </ResponsiveContainer>
      </div>
    </div>
  );
};

export default CashFlowChart;

import React, { useState, useMemo } from 'react';
import { InputParams, Station } from '../types';
import Card from './Card';
import { TrashIcon, DownloadIcon, PencilIcon, CheckIcon, XIcon, SlidersIcon } from './icons';
import SliderInput from './SliderInput';
import MetricDisplay from './MetricDisplay';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';

interface LeaseAnalysisProps {
  globalParams: InputParams;
  currency: string;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(value);
};

const LeaseAnalysis: React.FC<LeaseAnalysisProps> = ({ globalParams, currency }) => {
  const [stations, setStations] = useState<Station[]>([
      { id: '1', name: 'Station A', dailyVolume: 35000, recoveryRate: 0.5, uptime: 99.5, installCost: 5000, localCurrency: currency, exchangeRateToGlobal: 1 },
      { id: '2', name: 'Station B', dailyVolume: 50000, recoveryRate: 0.5, uptime: 99.0, installCost: 5000, localCurrency: currency, exchangeRateToGlobal: 1 },
  ]);

  // Local overrides for analysis
  const [growthRate, setGrowthRate] = useState(globalParams.volumeGrowthRate);
  const [dailyOpsCost, setDailyOpsCost] = useState(globalParams.dailyOperationalCost);

  // Bulk Gen State
  const [showBulkGen, setShowBulkGen] = useState(false);
  const [bulkCount, setBulkCount] = useState(10);
  const [bulkVariance, setBulkVariance] = useState(20);

  // Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<Partial<Station>>({});

  const [newStation, setNewStation] = useState<Partial<Station>>({
      name: '',
      dailyVolume: 40000,
      recoveryRate: 0.5,
      uptime: 99.5,
      installCost: 5000,
      localCurrency: currency,
      exchangeRateToGlobal: 1
  });

  const addStation = () => {
      if (!newStation.name) return;
      setStations([...stations, { 
          id: Date.now().toString(),
          name: newStation.name,
          dailyVolume: newStation.dailyVolume || 0,
          recoveryRate: newStation.recoveryRate || 0.5,
          uptime: newStation.uptime || 99.5,
          installCost: newStation.installCost || 5000,
          localCurrency: newStation.localCurrency || currency,
          exchangeRateToGlobal: newStation.exchangeRateToGlobal || 1
      } as Station]);
      setNewStation({ ...newStation, name: '' });
  };

  const generateBulkStations = () => {
      const newBatch: Station[] = [];
      const baseVol = globalParams.avgGasolineSold;
      const baseRec = globalParams.recoveryRate;

      for(let i=0; i < bulkCount; i++) {
          const variance = (Math.random() - 0.5) * 2 * (bulkVariance / 100);
          const vol = Math.round(baseVol * (1 + variance));

          newBatch.push({
              id: `gen-${Date.now()}-${i}`,
              name: `Site #${stations.length + i + 1} (Gen)`,
              dailyVolume: vol,
              recoveryRate: baseRec,
              uptime: 98 + (Math.random() * 2), // 98-100% random uptime
              installCost: globalParams.installationCostPerUnit,
              localCurrency: currency,
              exchangeRateToGlobal: 1
          });
      }
      setStations([...stations, ...newBatch]);
      setShowBulkGen(false);
  };

  const removeStation = (id: string) => {
      setStations(stations.filter(s => s.id !== id));
  };

  const startEditing = (station: Station) => {
    setEditingId(station.id);
    setEditValues({ ...station });
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditValues({});
  };

  const saveEditing = () => {
    if (!editingId) return;
    setStations(stations.map(s => {
        if (s.id === editingId) {
            return { ...s, ...editValues } as Station;
        }
        return s;
    }));
    setEditingId(null);
    setEditValues({});
  };

  // Aggregate Calculation Logic
  const analysis = useMemo(() => {
    let totalRevenue = 0;
    let totalCost = 0;

    // Annualizing costs (Assuming these global params are in Global Currency)
    const annualMaintenance = globalParams.annualMaintenanceCost;
    const annualWarranty = globalParams.annualWarrantyCost;
    const annualConsumables = globalParams.annualConsumablesCost;
    const annualOps = dailyOpsCost * 365;
    const unitPowerCost = globalParams.unitElectricityConsumptionKwhDay * 365 * globalParams.electricityPrice;

    // Per unit annual fixed cost (without install)
    const annualFixedCostPerUnit = annualMaintenance + annualWarranty + annualConsumables + annualOps + unitPowerCost;

    const term = globalParams.leaseTerm;

    const results = stations.map(station => {
        let stationRevenueLocal = 0;

        for (let year = 1; year <= term; year++) {
             const growthFactor = Math.pow(1 + (growthRate / 100), year - 1);
             const dailyVol = station.dailyVolume * growthFactor;
             const recovered = dailyVol * (station.recoveryRate / 100) * 365 * (station.uptime / 100);

             const gasRev = recovered * globalParams.gasolinePrice * (globalParams.companyRevenueShare / 100);
             const co2 = recovered * globalParams.co2TonnesPerGallon; 
             const carbonRev = globalParams.enableCarbonCredits ? co2 * globalParams.pricePerCredit : 0;

             stationRevenueLocal += gasRev + carbonRev;
        }

        if (globalParams.companyHandlesInstallation) {
             stationRevenueLocal += station.installCost; // Install Cost charged to client
        }

        const stationCost = (annualFixedCostPerUnit * term) + globalParams.unitCost + station.installCost + globalParams.customerAcquisitionCost;
        const stationNetProfit = stationRevenueLocal - stationCost;

        totalRevenue += stationRevenueLocal;
        totalCost += stationCost;

        return {
            ...station,
            totalRevenue: stationRevenueLocal,
            totalCost: stationCost,
            netProfit: stationNetProfit
        };
    });

    return {
        stationResults: results,
        totalRevenue,
        totalCost,
        totalNetProfit: totalRevenue - totalCost,
        avgProfitPerStation: results.length ? (totalRevenue - totalCost) / results.length : 0,
        roi: totalCost > 0 ? ((totalRevenue - totalCost) / totalCost) * 100 : 0
    };

  }, [stations, globalParams, growthRate, dailyOpsCost]);

  const handleExport = () => {
    const header = ['Station Name', 'Currency', 'Daily Vol', 'Uptime', 'Install Cost', 'Total Revenue', 'Total Cost', 'Net Profit'];
    const rows = analysis.stationResults.map(s => [
        s.name, 
        s.localCurrency || currency,
        s.dailyVolume, 
        s.uptime, 
        s.installCost, 
        s.totalRevenue.toFixed(2), 
        s.totalCost.toFixed(2), 
        s.netProfit.toFixed(2)
    ]);

    let csvContent = "data:text/csv;charset=utf-8," + [header, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Lease_Analysis_Export_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="p-6 lg:p-8 w-full max-w-7xl mx-auto h-full overflow-y-auto pb-24">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-white">Detailed Lease Analysis</h1>
          <p className="text-navy-400 mt-1">Granular station-by-station breakdown with specific unit economics.</p>
        </div>
        <div className="flex space-x-3">
            <button 
                onClick={() => setShowBulkGen(!showBulkGen)}
                className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors"
            >
                <SlidersIcon className="w-4 h-4" />
                <span>Bulk Add</span>
            </button>
            <button 
                onClick={handleExport}
                className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors"
            >
                <DownloadIcon className="w-4 h-4" />
                <span>Export CSV</span>
            </button>
        </div>
      </div>

      {showBulkGen && (
          <div className="mb-8 bg-glass-200 border border-primary/30 p-4 rounded-xl shadow-lg animate-in fade-in slide-in-from-top-2">
              <div className="flex justify-between items-center mb-4">
                  <h3 className="font-bold text-white">Bulk Station Generator</h3>
                  <button onClick={() => setShowBulkGen(false)} className="text-navy-400 hover:text-white"><XIcon className="w-5 h-5"/></button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                   <div>
                       <label className="text-xs font-bold text-navy-400 uppercase">Number of Stations</label>
                       <input 
                           type="number" 
                           value={bulkCount}
                           onChange={(e) => setBulkCount(Number(e.target.value))}
                           className="w-full bg-navy-950 border border-white/20 rounded p-2 mt-1 text-white"
                           min={1} max={100}
                       />
                   </div>
                   <div>
                       <label className="text-xs font-bold text-navy-400 uppercase">Volume Variance (+/- %)</label>
                       <input 
                           type="number" 
                           value={bulkVariance}
                           onChange={(e) => setBulkVariance(Number(e.target.value))}
                           className="w-full bg-navy-950 border border-white/20 rounded p-2 mt-1 text-white"
                           min={0} max={50}
                       />
                   </div>
                   <div className="flex items-end">
                       <button 
                          onClick={generateBulkStations}
                          className="w-full bg-primary hover:bg-primary-dark text-white font-bold py-2 rounded shadow-lg"
                        >
                           Generate {bulkCount} Stations
                       </button>
                   </div>
              </div>
          </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="lg:col-span-2 space-y-6">
             {/* Aggregated Stats */}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 <MetricDisplay label="Total Net Profit" value={formatCurrency(analysis.totalNetProfit, currency)} highlight={analysis.totalNetProfit >= 0 ? 'net-profit-gain' : 'net-profit-loss'} />
                 <MetricDisplay label="Avg Profit / Unit" value={formatCurrency(analysis.avgProfitPerStation, currency)} />
                 <MetricDisplay label="Total Revenue" value={formatCurrency(analysis.totalRevenue, currency)} />
                 <MetricDisplay label="Portfolio ROI" value={`${analysis.roi.toFixed(1)}%`} highlight="roi" />
             </div>

             {/* Station Table */}
             <Card title={`Station Portfolio (${stations.length} Units)`} noPadding className="overflow-hidden">
                 <div className="w-full overflow-x-auto custom-scrollbar">
                     <table className="w-full text-sm text-left text-navy-200 min-w-[800px]">
                         <thead className="bg-white/5 border-b border-white/10 sticky top-0 z-10">
                             <tr>
                                 <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Station Name</th>
                                 <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Currency</th>
                                 <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Daily Vol</th>
                                 <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Recovery</th>
                                 <th className="px-6 py-3 font-bold text-white text-right whitespace-nowrap">Net Profit (Lifetime)</th>
                                 <th className="px-6 py-3 font-bold text-white text-right whitespace-nowrap">Actions</th>
                             </tr>
                         </thead>
                         <tbody className="divide-y divide-white/5">
                             {analysis.stationResults.map((s) => {
                                 const isEditing = editingId === s.id;
                                 return (
                                     <tr key={s.id} className="hover:bg-white/5">
                                         <td className="px-6 py-3 font-medium text-white">
                                             {isEditing ? (
                                                 <input 
                                                     type="text" 
                                                     value={editValues.name || ''}
                                                     onChange={(e) => setEditValues({...editValues, name: e.target.value})}
                                                     className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-full text-white focus:outline-none focus:border-primary"
                                                 />
                                             ) : s.name}
                                         </td>
                                         <td className="px-6 py-3 text-xs uppercase font-mono text-navy-400">
                                            {isEditing ? (
                                                 <input 
                                                     type="text" 
                                                     value={editValues.localCurrency || currency}
                                                     onChange={(e) => setEditValues({...editValues, localCurrency: e.target.value})}
                                                     className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-16 text-white focus:outline-none focus:border-primary uppercase"
                                                 />
                                             ) : s.localCurrency || currency}
                                         </td>
                                         <td className="px-6 py-3">
                                             {isEditing ? (
                                                 <input 
                                                     type="number" 
                                                     value={editValues.dailyVolume}
                                                     onChange={(e) => setEditValues({...editValues, dailyVolume: parseFloat(e.target.value)})}
                                                     className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-24 text-white focus:outline-none focus:border-primary"
                                                 />
                                             ) : s.dailyVolume.toLocaleString()}
                                         </td>
                                         <td className="px-6 py-3">
                                             {isEditing ? (
                                                 <div className="flex items-center">
                                                     <input 
                                                         type="number" 
                                                         value={editValues.recoveryRate}
                                                         onChange={(e) => setEditValues({...editValues, recoveryRate: parseFloat(e.target.value)})}
                                                         className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-16 text-white focus:outline-none focus:border-primary"
                                                         step={0.1}
                                                     />
                                                     <span className="ml-1">%</span>
                                                 </div>
                                             ) : `${(s.recoveryRate).toFixed(2)}%`}
                                         </td>
                                         <td className={`px-6 py-3 text-right font-bold ${s.netProfit >= 0 ? 'text-success' : 'text-danger'}`}>
                                             {formatCurrency(s.netProfit, currency)}
                                         </td>
                                         <td className="px-6 py-3 text-right">
                                             {isEditing ? (
                                                 <div className="flex justify-end space-x-2">
                                                     <button onClick={saveEditing} className="text-success hover:text-success-light p-1 bg-white/5 rounded"><CheckIcon className="w-5 h-5" /></button>
                                                     <button onClick={cancelEditing} className="text-danger hover:text-danger-light p-1 bg-white/5 rounded"><XIcon className="w-5 h-5" /></button>
                                                 </div>
                                             ) : (
                                                 <div className="flex justify-end space-x-2">
                                                     <button onClick={() => startEditing(s)} className="text-navy-400 hover:text-primary-light p-1"><PencilIcon className="w-4 h-4" /></button>
                                                     <button onClick={() => removeStation(s.id)} className="text-navy-400 hover:text-danger p-1"><TrashIcon className="w-4 h-4" /></button>
                                                 </div>
                                             )}
                                         </td>
                                     </tr>
                                 );
                             })}
                             {/* Add Row */}
                             {!editingId && (
                                 <tr className="bg-navy-900/50">
                                     <td className="px-6 py-2">
                                         <input 
                                            type="text" 
                                            placeholder="New Station Name"
                                            className="bg-transparent border border-white/20 rounded px-2 py-1 w-full text-white placeholder-navy-500 focus:outline-none focus:border-primary"
                                            value={newStation.name}
                                            onChange={e => setNewStation({...newStation, name: e.target.value})}
                                         />
                                     </td>
                                     <td className="px-6 py-2">
                                         <input 
                                            type="text" 
                                            placeholder="USD"
                                            className="bg-transparent border border-white/20 rounded px-2 py-1 w-16 text-white uppercase focus:outline-none focus:border-primary"
                                            value={newStation.localCurrency}
                                            onChange={e => setNewStation({...newStation, localCurrency: e.target.value})}
                                         />
                                     </td>
                                     <td className="px-6 py-2">
                                         <input 
                                            type="number" 
                                            className="bg-transparent border border-white/20 rounded px-2 py-1 w-24 text-white focus:outline-none focus:border-primary"
                                            value={newStation.dailyVolume}
                                            onChange={e => setNewStation({...newStation, dailyVolume: parseFloat(e.target.value)})}
                                         />
                                     </td>
                                     <td className="px-6 py-2 text-sm text-navy-400">
                                          Default ({newStation.recoveryRate}%)
                                     </td>
                                     <td className="px-6 py-2 text-right" colSpan={2}>
                                         <button 
                                            onClick={addStation}
                                            disabled={!newStation.name}
                                            className="bg-primary hover:bg-primary-dark text-white text-xs font-bold px-3 py-1.5 rounded disabled:opacity-50"
                                         >
                                             Add Station
                                         </button>
                                     </td>
                                 </tr>
                             )}
                         </tbody>
                     </table>
                 </div>
             </Card>
          </div>

          <div className="space-y-6">
              {/* Controls */}
              <Card title="Analysis Parameters">
                  <div className="space-y-4">
                      <SliderInput 
                          label="Volume Growth Rate (Annual)"
                          value={growthRate}
                          min={-5} max={20} step={0.5}
                          unit="%"
                          onChange={setGrowthRate}
                          description="Projected annual increase in gasoline volume across portfolio."
                      />
                       <SliderInput 
                          label="Daily Op Cost / Unit"
                          value={dailyOpsCost}
                          min={0} max={50} step={1}
                          unit={CURRENCY_SYMBOLS[currency]}
                          onChange={setDailyOpsCost}
                          description="Overhead cost per day per unit."
                      />
                  </div>
              </Card>

              {/* Unit Economics Breakdown */}
              <Card title="Unit Economics (Per Unit/Year)">
                  <div className="space-y-3 text-sm">
                       <div className="flex justify-between border-b border-white/10 pb-2">
                           <span className="text-navy-300">Revenue (Year 1 Avg)</span>
                           <span className="text-success font-bold">{formatCurrency((analysis.totalRevenue / globalParams.leaseTerm) / Math.max(1, stations.length), currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Maintenance</span>
                           <span className="text-white">{formatCurrency(globalParams.annualMaintenanceCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Warranty Reserve</span>
                           <span className="text-white">{formatCurrency(globalParams.annualWarrantyCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Consumables</span>
                           <span className="text-white">{formatCurrency(globalParams.annualConsumablesCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Daily Ops ({formatCurrency(dailyOpsCost, currency)}/day)</span>
                           <span className="text-white">{formatCurrency(dailyOpsCost * 365, currency)}</span>
                       </div>
                        <div className="flex justify-between border-t border-white/10 pt-2 font-bold">
                           <span className="text-white">Total Operating Cost</span>
                           <span className="text-danger">{formatCurrency(globalParams.annualMaintenanceCost + globalParams.annualWarrantyCost + globalParams.annualConsumablesCost + (dailyOpsCost * 365), currency)}</span>
                       </div>
                  </div>
              </Card>
          </div>
      </div>
    </div>
  );
};

export default LeaseAnalysis;

import React, { useState, useEffect } from 'react';
import { InputParams, Scenario } from '../types';
import { TrashIcon, SaveIcon, FolderIcon, DownloadIcon, ClipboardListIcon } from './icons';
import Card from './Card';

interface ScenarioManagerProps {
  currentParams: InputParams;
  onLoad: (params: InputParams) => void;
}

const ScenarioManager: React.FC<ScenarioManagerProps> = ({ currentParams, onLoad }) => {
  const [scenarios, setScenarios] = useState<Scenario[]>([]);
  const [newScenarioName, setNewScenarioName] = useState('');
  const [notification, setNotification] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('masarzero_scenarios');
    if (saved) {
      try {
        setScenarios(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse scenarios", e);
      }
    }
  }, []);

  const saveScenariosToStorage = (updatedScenarios: Scenario[]) => {
    localStorage.setItem('masarzero_scenarios', JSON.stringify(updatedScenarios));
    setScenarios(updatedScenarios);
  };

  const handleSave = () => {
    if (!newScenarioName.trim()) {
      showNotification('Please enter a name for the scenario.', 'error');
      return;
    }

    const newScenario: Scenario = {
      id: Date.now().toString(),
      name: newScenarioName,
      date: new Date().toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }),
      params: { ...currentParams }
    };

    const updated = [newScenario, ...scenarios];
    saveScenariosToStorage(updated);
    setNewScenarioName('');
    showNotification('Scenario saved successfully!', 'success');
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to delete this scenario?')) {
        const updated = scenarios.filter(s => s.id !== id);
        saveScenariosToStorage(updated);
        showNotification('Scenario deleted.', 'success');
    }
  };

  const handleLoad = (scenario: Scenario) => {
    onLoad(scenario.params);
    showNotification(`Loaded scenario: ${scenario.name}`, 'success');
  };

  const handleExportToFile = () => {
      if (scenarios.length === 0) {
          showNotification('No scenarios to export.', 'error');
          return;
      }
      const dataStr = JSON.stringify(scenarios, null, 2);
      const blob = new Blob([dataStr], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `masarzero_scenarios_backup_${new Date().toISOString().slice(0,10)}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      showNotification('Backup file downloaded.', 'success');
  };

  const handleImportFile = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const imported = JSON.parse(e.target?.result as string);
              if (Array.isArray(imported)) {
                  // Merge with existing or Replace? Let's merge for safety, filtering duplicates by ID
                  const merged = [...scenarios, ...imported].filter((v,i,a)=>a.findIndex(v2=>(v2.id===v.id))===i);
                  saveScenariosToStorage(merged);
                  showNotification(`Imported ${imported.length} scenarios.`, 'success');
              } else {
                  showNotification('Invalid file format.', 'error');
              }
          } catch (err) {
              showNotification('Failed to parse file.', 'error');
          }
      };
      reader.readAsText(file);
      // Reset input value to allow re-importing same file if needed
      event.target.value = '';
  };

  const showNotification = (msg: string, type: 'success' | 'error') => {
      setNotification(msg);
      setTimeout(() => setNotification(null), 3000);
  }

  return (
    <div className="p-6 lg:p-8 w-full max-w-5xl mx-auto h-full overflow-y-auto">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center space-x-4">
            <div className="p-3 bg-gradient-primary rounded-xl shadow-glow">
                <FolderIcon className="w-8 h-8 text-white" />
            </div>
            <div>
                <h1 className="text-3xl font-bold text-white">Scenario Manager</h1>
                <p className="text-navy-400 mt-1">Save your current configuration or load a previous workspace.</p>
            </div>
        </div>
        <div className="flex space-x-3">
             <label className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors cursor-pointer">
                <ClipboardListIcon className="w-4 h-4" />
                <span>Import JSON</span>
                <input type="file" accept="application/json" onChange={handleImportFile} className="hidden" />
            </label>
            <button 
                onClick={handleExportToFile}
                className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors"
            >
                <DownloadIcon className="w-4 h-4" />
                <span>Export JSON</span>
            </button>
        </div>
      </div>

      {notification && (
          <div className="fixed top-6 right-6 z-50 animate-in fade-in slide-in-from-top-2">
              <div className="bg-glass-200 backdrop-blur-md border border-glass-highlight px-6 py-3 rounded-xl shadow-2xl text-white font-semibold">
                  {notification}
              </div>
          </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Create New Scenario */}
        <div className="lg:col-span-1">
             <Card title="Save Current State" className="h-full">
                <div className="space-y-4">
                    <p className="text-sm text-navy-300">
                        Create a snapshot of all your current inputs, assumptions, and settings.
                    </p>
                    <div>
                        <label className="block text-xs font-bold text-navy-400 uppercase tracking-widest mb-2">Scenario Name</label>
                        <input 
                            type="text" 
                            value={newScenarioName}
                            onChange={(e) => setNewScenarioName(e.target.value)}
                            placeholder="e.g. High Volume Site A"
                            className="w-full bg-navy-950 border border-white/20 rounded-lg py-2.5 px-3 text-white placeholder-navy-600 focus:outline-none focus:ring-2 focus:ring-primary focus:border-primary transition"
                            onKeyDown={(e) => e.key === 'Enter' && handleSave()}
                        />
                    </div>
                    <button 
                        onClick={handleSave}
                        disabled={!newScenarioName.trim()}
                        className="w-full bg-gradient-primary text-white font-bold py-3 px-4 rounded-lg shadow-lg hover:shadow-glow hover:brightness-110 active:scale-95 transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center space-x-2"
                    >
                        <SaveIcon className="w-5 h-5" />
                        <span>Save Scenario</span>
                    </button>
                </div>
             </Card>
        </div>

        {/* List Scenarios */}
        <div className="lg:col-span-2 space-y-4">
            <h3 className="text-xl font-bold text-white mb-4">Saved Workspaces</h3>
            {scenarios.length === 0 ? (
                <div className="flex flex-col items-center justify-center p-12 border-2 border-dashed border-white/10 rounded-2xl bg-white/5 text-center">
                    <FolderIcon className="w-12 h-12 text-navy-600 mb-4" />
                    <p className="text-navy-300 font-medium">No saved scenarios yet.</p>
                    <p className="text-navy-500 text-sm mt-1">Save your first configuration to see it here.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {scenarios.map((scenario) => (
                        <div key={scenario.id} className="bg-glass-100 border border-glass-border rounded-xl p-5 hover:border-primary/50 transition-all duration-200 group relative">
                            <div className="flex justify-between items-start mb-3">
                                <div>
                                    <h4 className="font-bold text-white text-lg truncate pr-6" title={scenario.name}>{scenario.name}</h4>
                                    <span className="text-xs text-navy-400 font-mono">{scenario.date}</span>
                                </div>
                                <button 
                                    onClick={() => handleDelete(scenario.id)}
                                    className="text-navy-500 hover:text-danger transition-colors p-1"
                                    title="Delete Scenario"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>

                            <div className="space-y-1 mb-5">
                                <div className="flex justify-between text-xs">
                                    <span className="text-navy-400">Model:</span>
                                    <span className="text-white font-medium">{scenario.params.businessModel}</span>
                                </div>
                                <div className="flex justify-between text-xs">
                                    <span className="text-navy-400">Clients:</span>
                                    <span className="text-white font-medium">{scenario.params.numberOfClients}</span>
                                </div>
                                 <div className="flex justify-between text-xs">
                                    <span className="text-navy-400">Units/Client:</span>
                                    <span className="text-white font-medium">{scenario.params.unitsPerClient}</span>
                                </div>
                            </div>

                            <button 
                                onClick={() => handleLoad(scenario)}
                                className="w-full bg-navy-800 hover:bg-primary text-primary-light hover:text-white border border-primary/30 hover:border-primary font-semibold py-2 rounded-lg transition-all duration-200 text-sm"
                            >
                                Load Workspace
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default ScenarioManager;

