                    style={{ left: `${thresholdPercent}%` }}
                />

                {/* Progress Bar */}
                <div 
                    className={`h-full transition-all duration-500 ${isSafe ? 'bg-success' : 'bg-danger'}`}
                    style={{ width: `${percent}%` }}
                />
            </div>
            <div className="flex justify-between text-[10px] text-navy-400 mt-1">
                <span>0</span>
                <span className="text-white font-mono">BE: {Math.round(threshold).toLocaleString()}</span>
                <span>{Math.round(max).toLocaleString()}</span>
            </div>
        </div>
    );
};

const ImpactAnalysis: React.FC<ImpactAnalysisProps> = ({ results, inputs, currency }) => {
  const { impact } = results;
  const unitLabel = inputs.unitSystem === 'gallons' ? 'Gal' : 'L';
  const dailyVol = inputs.avgGasolineSold;

  // Max range for charts is typically current volume + 50% buffer or BreakEven + 50%
  const chartMax = Math.max(dailyVol * 1.5, impact.breakEvenTotalVolume * 1.5);

  // Derive fixed cost and variable revenue for the chart
  // This is an estimation based on the break even logic in calculator
  // BE Volume = FixedCost / RevPerUnit
  // FixedCost = BE Volume * RevPerUnit
  const recoveryEfficiency = (inputs.recoveryRate / 100) * (inputs.machineUptime / 100) * 365;
  const revPerRecoveredUnit = (inputs.gasolinePrice * (inputs.companyRevenueShare/100)) + 
                              (inputs.enableCarbonCredits ? (inputs.unitSystem === 'gallons' ? inputs.co2TonnesPerGallon : inputs.co2TonnesPerGallon/3.785) * inputs.pricePerCredit : 0);

  const variableRevenuePerUnit = recoveryEfficiency * revPerRecoveredUnit;
  const estimatedFixedCost = impact.breakEvenTotalVolume * variableRevenuePerUnit;

  return (
    <div className="p-6 lg:p-8 w-full max-w-6xl mx-auto h-full overflow-y-auto">
        <div className="flex items-center space-x-4 mb-8">
