                    </div>
                </Card>

                <div className="grid grid-cols-2 gap-4">
                    <MetricDisplay label="OpEx Break-Even" value={formatVolume(impact.breakEvenDailyVolume, unitLabel)} />
                    <MetricDisplay label="ROI Break-Even" value={formatVolume(impact.breakEvenTotalVolume, unitLabel)} />
                </div>
            </div>

            {/* Right Col: ESG Dashboard */}
            <div className="space-y-6">
                 <Card title="Environmental Impact (ESG)">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="bg-gradient-to-br from-emerald-500/10 to-emerald-900/20 border border-emerald-500/30 p-4 rounded-xl flex items-center space-x-4">
                            <div className="bg-emerald-500/20 p-3 rounded-full">
                                <LeafIcon className="w-6 h-6 text-emerald-400" />
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{Math.round(impact.totalCo2Saved).toLocaleString()}</div>
                                <div className="text-xs text-emerald-200 uppercase font-bold tracking-wider">Tonnes CO2 Saved</div>
                            </div>
                        </div>

                        <div className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center space-x-4">
                             <div className="bg-white/10 p-3 rounded-full">
                                <TreeIcon className="w-6 h-6 text-green-400" />
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{Math.round(impact.treesPlantedEquiv).toLocaleString()}</div>
                                <div className="text-xs text-navy-400 uppercase font-bold tracking-wider">Trees Planted</div>
                            </div>
                        </div>

                         <div className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center space-x-4">
                             <div className="bg-white/10 p-3 rounded-full">
                                <ShieldCheckIcon className="w-6 h-6 text-blue-400" /> {/* Using Shield as Car proxy if needed or just Generic */}
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{impact.carsOffRoadEquiv.toFixed(1)}</div>
                                <div className="text-xs text-navy-400 uppercase font-bold tracking-wider">Cars Off Road</div>
                            </div>
                        </div>

                        <div className="bg-white/5 border border-white/10 p-4 rounded-xl flex items-center space-x-4">
                             <div className="bg-white/10 p-3 rounded-full">
                                <LightningIcon className="w-6 h-6 text-yellow-400" />
                            </div>
                            <div>
                                <div className="text-2xl font-bold text-white">{Math.round(impact.homesPoweredEquiv).toLocaleString()}</div>
                                <div className="text-xs text-navy-400 uppercase font-bold tracking-wider">Homes Powered</div>
