};

export default ImpactAnalysis;

import React, { useState, useMemo } from 'react';
import { InputParams, Station } from '../types';
import Card from './Card';
import { TrashIcon, DownloadIcon, PencilIcon, CheckIcon, XIcon, SlidersIcon, ChartBarIcon, TableIcon } from './icons';
import SliderInput from './SliderInput';
import MetricDisplay from './MetricDisplay';
import { CURRENCY_SYMBOLS } from '../utils/sensitivityConfig';
import { ScatterChart, Scatter, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, ReferenceLine } from 'recharts';

interface LeaseAnalysisProps {
  globalParams: InputParams;
  currency: string;
}

const formatCurrency = (value: number, currency: string) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(value);
};

const CustomScatterTooltip = ({ active, payload, currency }: any) => {
    if (active && payload && payload.length) {
        const data = payload[0].payload;
        return (
            <div className="bg-navy-900 border border-white/20 rounded-lg p-3 shadow-lg text-sm">
                <div className="font-bold text-white mb-1">{data.name}</div>
                <div className="text-navy-300">Volume: <span className="text-white font-mono">{data.dailyVolume.toLocaleString()}</span></div>
                <div className="text-navy-300">Profit: <span className="text-white font-mono">{formatCurrency(data.netProfit, currency)}</span></div>
            </div>
        )
    }
    return null;
}

const LeaseAnalysis: React.FC<LeaseAnalysisProps> = ({ globalParams, currency }) => {
  const [stations, setStations] = useState<Station[]>([
      { id: '1', name: 'Station A', dailyVolume: 35000, recoveryRate: 0.5, uptime: 99.5, installCost: 5000, localCurrency: currency, exchangeRateToGlobal: 1 },
      { id: '2', name: 'Station B', dailyVolume: 50000, recoveryRate: 0.5, uptime: 99.0, installCost: 5000, localCurrency: currency, exchangeRateToGlobal: 1 },
  ]);

  // Local overrides for analysis
  const [growthRate, setGrowthRate] = useState(globalParams.volumeGrowthRate);
  const [dailyOpsCost, setDailyOpsCost] = useState(globalParams.dailyOperationalCost);
  const [viewMode, setViewMode] = useState<'table' | 'matrix'>('table');

  // Bulk Gen State
  const [showBulkGen, setShowBulkGen] = useState(false);
  const [bulkCount, setBulkCount] = useState(10);
  const [bulkVariance, setBulkVariance] = useState(20);

  // Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<Partial<Station>>({});

  const [newStation, setNewStation] = useState<Partial<Station>>({
      name: '',
      dailyVolume: 40000,
      recoveryRate: 0.5,
      uptime: 99.5,
      installCost: 5000,
      localCurrency: currency,
      exchangeRateToGlobal: 1
  });

  const addStation = () => {
      if (!newStation.name) return;
      setStations([...stations, { 
          id: Date.now().toString(),
          name: newStation.name,
          dailyVolume: newStation.dailyVolume || 0,
          recoveryRate: newStation.recoveryRate || 0.5,
          uptime: newStation.uptime || 99.5,
          installCost: newStation.installCost || 5000,
          localCurrency: newStation.localCurrency || currency,
          exchangeRateToGlobal: newStation.exchangeRateToGlobal || 1
      } as Station]);
      setNewStation({ ...newStation, name: '' });
  };

  const generateBulkStations = () => {
      const newBatch: Station[] = [];
      const baseVol = globalParams.avgGasolineSold;
      const baseRec = globalParams.recoveryRate;

      for(let i=0; i < bulkCount; i++) {
          const variance = (Math.random() - 0.5) * 2 * (bulkVariance / 100);
          const vol = Math.round(baseVol * (1 + variance));

          newBatch.push({
              id: `gen-${Date.now()}-${i}`,
              name: `Site #${stations.length + i + 1} (Gen)`,
              dailyVolume: vol,
              recoveryRate: baseRec,
              uptime: 98 + (Math.random() * 2), // 98-100% random uptime
              installCost: globalParams.installationCostPerUnit,
              localCurrency: currency,
              exchangeRateToGlobal: 1
          });
      }
      setStations([...stations, ...newBatch]);
      setShowBulkGen(false);
  };

  const removeStation = (id: string) => {
      setStations(stations.filter(s => s.id !== id));
  };

  const startEditing = (station: Station) => {
    setEditingId(station.id);
    setEditValues({ ...station });
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditValues({});
  };

  const saveEditing = () => {
    if (!editingId) return;
    setStations(stations.map(s => {
        if (s.id === editingId) {
            return { ...s, ...editValues } as Station;
        }
        return s;
    }));
    setEditingId(null);
    setEditValues({});
  };

  // Aggregate Calculation Logic
  const analysis = useMemo(() => {
    let totalRevenue = 0;
    let totalCost = 0;

    const annualMaintenance = globalParams.annualMaintenanceCost;
    const annualWarranty = globalParams.annualWarrantyCost;
    const annualConsumables = globalParams.annualConsumablesCost;
    const annualOps = dailyOpsCost * 365;
    const unitPowerCost = globalParams.unitElectricityConsumptionKwhDay * 365 * globalParams.electricityPrice;

    const annualFixedCostPerUnit = annualMaintenance + annualWarranty + annualConsumables + annualOps + unitPowerCost;
    const term = globalParams.leaseTerm;

    const results = stations.map(station => {
        let stationRevenueLocal = 0;

        for (let year = 1; year <= term; year++) {
             const growthFactor = Math.pow(1 + (growthRate / 100), year - 1);
             const dailyVol = station.dailyVolume * growthFactor;
             const recovered = dailyVol * (station.recoveryRate / 100) * 365 * (station.uptime / 100);

             const gasRev = recovered * globalParams.gasolinePrice * (globalParams.companyRevenueShare / 100);
             const co2 = recovered * globalParams.co2TonnesPerGallon; 
             const carbonRev = globalParams.enableCarbonCredits ? co2 * globalParams.pricePerCredit : 0;

             stationRevenueLocal += gasRev + carbonRev;
        }

        if (globalParams.companyHandlesInstallation) {
             stationRevenueLocal += station.installCost; // Install Cost charged to client
        }

        const stationCost = (annualFixedCostPerUnit * term) + globalParams.unitCost + station.installCost + globalParams.customerAcquisitionCost;
        const stationNetProfit = stationRevenueLocal - stationCost;

        totalRevenue += stationRevenueLocal;
        totalCost += stationCost;

        return {
            ...station,
            totalRevenue: stationRevenueLocal,
            totalCost: stationCost,
            netProfit: stationNetProfit
        };
    });

    return {
        stationResults: results,
        totalRevenue,
        totalCost,
        totalNetProfit: totalRevenue - totalCost,
        avgProfitPerStation: results.length ? (totalRevenue - totalCost) / results.length : 0,
        roi: totalCost > 0 ? ((totalRevenue - totalCost) / totalCost) * 100 : 0
    };

  }, [stations, globalParams, growthRate, dailyOpsCost]);

  const handleExport = () => {
    const header = ['Station Name', 'Currency', 'Daily Vol', 'Uptime', 'Install Cost', 'Total Revenue', 'Total Cost', 'Net Profit'];
    const rows = analysis.stationResults.map(s => [
        s.name, 
        s.localCurrency || currency,
        s.dailyVolume, 
        s.uptime, 
        s.installCost, 
        s.totalRevenue.toFixed(2), 
        s.totalCost.toFixed(2), 
        s.netProfit.toFixed(2)
    ]);

    let csvContent = "data:text/csv;charset=utf-8," + [header, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Lease_Analysis_Export_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="p-6 lg:p-8 w-full max-w-7xl mx-auto h-full overflow-y-auto pb-24">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-white">Detailed Lease Analysis</h1>
          <p className="text-navy-400 mt-1">Granular station-by-station breakdown with specific unit economics.</p>
        </div>
        <div className="flex space-x-3">
            <button 
                onClick={() => setShowBulkGen(!showBulkGen)}
                className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors"
            >
                <SlidersIcon className="w-4 h-4" />
                <span>Bulk Add</span>
            </button>
            <button 
                onClick={handleExport}
                className="flex items-center space-x-2 bg-navy-800 hover:bg-navy-700 text-white px-4 py-2 rounded-lg border border-white/10 transition-colors"
            >
                <DownloadIcon className="w-4 h-4" />
                <span>Export CSV</span>
            </button>
        </div>
      </div>

      {showBulkGen && (
          <div className="mb-8 bg-glass-200 border border-primary/30 p-4 rounded-xl shadow-lg animate-in fade-in slide-in-from-top-2">
              <div className="flex justify-between items-center mb-4">
                  <h3 className="font-bold text-white">Bulk Station Generator</h3>
                  <button onClick={() => setShowBulkGen(false)} className="text-navy-400 hover:text-white"><XIcon className="w-5 h-5"/></button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                   <div>
                       <label className="text-xs font-bold text-navy-400 uppercase">Number of Stations</label>
                       <input 
                           type="number" 
                           value={bulkCount}
                           onChange={(e) => setBulkCount(Number(e.target.value))}
                           className="w-full bg-navy-950 border border-white/20 rounded p-2 mt-1 text-white"
                           min={1} max={100}
                       />
                   </div>
                   <div>
                       <label className="text-xs font-bold text-navy-400 uppercase">Volume Variance (+/- %)</label>
                       <input 
                           type="number" 
                           value={bulkVariance}
                           onChange={(e) => setBulkVariance(Number(e.target.value))}
                           className="w-full bg-navy-950 border border-white/20 rounded p-2 mt-1 text-white"
                           min={0} max={50}
                       />
                   </div>
                   <div className="flex items-end">
                       <button 
                          onClick={generateBulkStations}
                          className="w-full bg-primary hover:bg-primary-dark text-white font-bold py-2 rounded shadow-lg"
                        >
                           Generate {bulkCount} Stations
                       </button>
                   </div>
              </div>
          </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="lg:col-span-2 space-y-6">
             {/* Aggregated Stats */}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 <MetricDisplay label="Total Net Profit" value={formatCurrency(analysis.totalNetProfit, currency)} highlight={analysis.totalNetProfit >= 0 ? 'net-profit-gain' : 'net-profit-loss'} />
                 <MetricDisplay label="Avg Profit / Unit" value={formatCurrency(analysis.avgProfitPerStation, currency)} />
                 <MetricDisplay label="Total Revenue" value={formatCurrency(analysis.totalRevenue, currency)} />
                 <MetricDisplay label="Portfolio ROI" value={`${analysis.roi.toFixed(1)}%`} highlight="roi" />
             </div>

             <div className="flex justify-end mb-2">
                 <div className="flex bg-navy-900 rounded p-1">
                     <button 
                        onClick={() => setViewMode('table')} 
                        className={`p-2 rounded ${viewMode === 'table' ? 'bg-primary text-white' : 'text-navy-400 hover:text-white'}`}
                        title="Table View"
                     >
                         <TableIcon className="w-4 h-4"/>
                     </button>
                     <button 
                        onClick={() => setViewMode('matrix')} 
                        className={`p-2 rounded ${viewMode === 'matrix' ? 'bg-primary text-white' : 'text-navy-400 hover:text-white'}`}
                        title="Performance Matrix (Chart)"
                     >
                         <ChartBarIcon className="w-4 h-4"/>
                     </button>
                 </div>
             </div>

             <Card title={`Station Portfolio (${stations.length} Units)`} noPadding className="overflow-hidden min-h-[400px]">
                 {viewMode === 'table' ? (
                     <div className="w-full overflow-x-auto custom-scrollbar">
                         <table className="w-full text-sm text-left text-navy-200 min-w-[800px]">
                             <thead className="bg-white/5 border-b border-white/10 sticky top-0 z-10">
                                 <tr>
                                     <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Station Name</th>
                                     <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Currency</th>
                                     <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Daily Vol</th>
                                     <th className="px-6 py-3 font-bold text-white whitespace-nowrap">Recovery</th>
                                     <th className="px-6 py-3 font-bold text-white text-right whitespace-nowrap">Net Profit (Lifetime)</th>
                                     <th className="px-6 py-3 font-bold text-white text-right whitespace-nowrap">Actions</th>
                                 </tr>
                             </thead>
                             <tbody className="divide-y divide-white/5">
                                 {analysis.stationResults.map((s) => {
                                     const isEditing = editingId === s.id;
                                     return (
                                         <tr key={s.id} className="hover:bg-white/5">
                                             <td className="px-6 py-3 font-medium text-white">
                                                 {isEditing ? (
                                                     <input 
                                                         type="text" 
                                                         value={editValues.name || ''}
                                                         onChange={(e) => setEditValues({...editValues, name: e.target.value})}
                                                         className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-full text-white focus:outline-none focus:border-primary"
                                                     />
                                                 ) : s.name}
                                             </td>
                                             <td className="px-6 py-3 text-xs uppercase font-mono text-navy-400">
                                                {isEditing ? (
                                                     <input 
                                                         type="text" 
                                                         value={editValues.localCurrency || currency}
                                                         onChange={(e) => setEditValues({...editValues, localCurrency: e.target.value})}
                                                         className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-16 text-white focus:outline-none focus:border-primary uppercase"
                                                     />
                                                 ) : s.localCurrency || currency}
                                             </td>
                                             <td className="px-6 py-3">
                                                 {isEditing ? (
                                                     <input 
                                                         type="number" 
                                                         value={editValues.dailyVolume}
                                                         onChange={(e) => setEditValues({...editValues, dailyVolume: parseFloat(e.target.value)})}
                                                         className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-24 text-white focus:outline-none focus:border-primary"
                                                     />
                                                 ) : s.dailyVolume.toLocaleString()}
                                             </td>
                                             <td className="px-6 py-3">
                                                 {isEditing ? (
                                                     <div className="flex items-center">
                                                         <input 
                                                             type="number" 
                                                             value={editValues.recoveryRate}
                                                             onChange={(e) => setEditValues({...editValues, recoveryRate: parseFloat(e.target.value)})}
                                                             className="bg-navy-950 border border-white/20 rounded px-2 py-1 w-16 text-white focus:outline-none focus:border-primary"
                                                             step={0.1}
                                                         />
                                                         <span className="ml-1">%</span>
                                                     </div>
                                                 ) : `${(s.recoveryRate).toFixed(2)}%`}
                                             </td>
                                             <td className={`px-6 py-3 text-right font-bold ${s.netProfit >= 0 ? 'text-success' : 'text-danger'}`}>
                                                 {formatCurrency(s.netProfit, currency)}
                                             </td>
                                             <td className="px-6 py-3 text-right">
                                                 {isEditing ? (
                                                     <div className="flex justify-end space-x-2">
                                                         <button onClick={saveEditing} className="text-success hover:text-success-light p-1 bg-white/5 rounded"><CheckIcon className="w-5 h-5" /></button>
                                                         <button onClick={cancelEditing} className="text-danger hover:text-danger-light p-1 bg-white/5 rounded"><XIcon className="w-5 h-5" /></button>
                                                     </div>
                                                 ) : (
                                                     <div className="flex justify-end space-x-2">
                                                         <button onClick={() => startEditing(s)} className="text-navy-400 hover:text-primary-light p-1"><PencilIcon className="w-4 h-4" /></button>
                                                         <button onClick={() => removeStation(s.id)} className="text-navy-400 hover:text-danger p-1"><TrashIcon className="w-4 h-4" /></button>
                                                     </div>
                                                 )}
                                             </td>
                                         </tr>
                                     );
                                 })}
                                 {/* Add Row */}
                                 {!editingId && (
                                     <tr className="bg-navy-900/50">
                                         <td className="px-6 py-2">
                                             <input 
                                                type="text" 
                                                placeholder="New Station Name"
                                                className="bg-transparent border border-white/20 rounded px-2 py-1 w-full text-white placeholder-navy-500 focus:outline-none focus:border-primary"
                                                value={newStation.name}
                                                onChange={e => setNewStation({...newStation, name: e.target.value})}
                                             />
                                         </td>
                                         <td className="px-6 py-2">
                                             <input 
                                                type="text" 
                                                placeholder="USD"
                                                className="bg-transparent border border-white/20 rounded px-2 py-1 w-16 text-white uppercase focus:outline-none focus:border-primary"
                                                value={newStation.localCurrency}
                                                onChange={e => setNewStation({...newStation, localCurrency: e.target.value})}
                                             />
                                         </td>
                                         <td className="px-6 py-2">
                                             <input 
                                                type="number" 
                                                className="bg-transparent border border-white/20 rounded px-2 py-1 w-24 text-white focus:outline-none focus:border-primary"
                                                value={newStation.dailyVolume}
                                                onChange={e => setNewStation({...newStation, dailyVolume: parseFloat(e.target.value)})}
                                             />
                                         </td>
                                         <td className="px-6 py-2 text-sm text-navy-400">
                                              Default ({newStation.recoveryRate}%)
                                         </td>
                                         <td className="px-6 py-2 text-right" colSpan={2}>
                                             <button 
                                                onClick={addStation}
                                                disabled={!newStation.name}
                                                className="bg-primary hover:bg-primary-dark text-white text-xs font-bold px-3 py-1.5 rounded disabled:opacity-50"
                                             >
                                                 Add Station
                                             </button>
                                         </td>
                                     </tr>
                                 )}
                             </tbody>
                         </table>
                     </div>
                 ) : (
                     <div className="h-[400px] w-full p-4">
                         <h4 className="text-center text-white font-bold mb-4">Fleet Performance Matrix</h4>
                         <ResponsiveContainer width="100%" height="100%">
                             <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
                                 <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" />
                                 <XAxis 
                                    type="number" 
                                    dataKey="dailyVolume" 
                                    name="Daily Volume" 
                                    stroke="#94a3b8"
                                    label={{ value: 'Daily Volume', position: 'insideBottom', offset: -10, fill: '#94a3b8' }}
                                 />
                                 <YAxis 
                                    type="number" 
                                    dataKey="netProfit" 
                                    name="Net Profit" 
                                    stroke="#94a3b8"
                                    tickFormatter={(val) => new Intl.NumberFormat('en-US', { notation: "compact", compactDisplay: "short" }).format(val)}
                                    label={{ value: 'Net Profit', angle: -90, position: 'insideLeft', fill: '#94a3b8' }}
                                 />
                                 <Tooltip cursor={{ strokeDasharray: '3 3' }} content={<CustomScatterTooltip currency={currency} />} />
                                 <ReferenceLine y={0} stroke="#ef4444" strokeDasharray="3 3" />
                                 <Scatter name="Stations" data={analysis.stationResults} fill="#8884d8">
                                     {analysis.stationResults.map((entry, index) => (
                                         <Cell key={`cell-${index}`} fill={entry.netProfit > 0 ? '#10b981' : '#ef4444'} />
                                     ))}
                                 </Scatter>
                             </ScatterChart>
                         </ResponsiveContainer>
                     </div>
                 )}
             </Card>
          </div>

          <div className="space-y-6">
              {/* Controls */}
              <Card title="Analysis Parameters">
                  <div className="space-y-4">
                      <SliderInput 
                          label="Volume Growth Rate (Annual)"
                          value={growthRate}
                          min={-5} max={20} step={0.5}
                          unit="%"
                          onChange={setGrowthRate}
                          description="Projected annual increase in gasoline volume across portfolio."
                      />
                       <SliderInput 
                          label="Daily Op Cost / Unit"
                          value={dailyOpsCost}
                          min={0} max={50} step={1}
                          unit={CURRENCY_SYMBOLS[currency]}
                          onChange={setDailyOpsCost}
                          description="Overhead cost per day per unit."
                      />
                  </div>
              </Card>

              {/* Unit Economics Breakdown */}
              <Card title="Unit Economics (Per Unit/Year)">
                  <div className="space-y-3 text-sm">
                       <div className="flex justify-between border-b border-white/10 pb-2">
                           <span className="text-navy-300">Revenue (Year 1 Avg)</span>
                           <span className="text-success font-bold">{formatCurrency((analysis.totalRevenue / globalParams.leaseTerm) / Math.max(1, stations.length), currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Maintenance</span>
                           <span className="text-white">{formatCurrency(globalParams.annualMaintenanceCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Warranty Reserve</span>
                           <span className="text-white">{formatCurrency(globalParams.annualWarrantyCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Consumables</span>
                           <span className="text-white">{formatCurrency(globalParams.annualConsumablesCost, currency)}</span>
                       </div>
                       <div className="flex justify-between">
                           <span className="text-navy-400">Daily Ops ({formatCurrency(dailyOpsCost, currency)}/day)</span>
                           <span className="text-white">{formatCurrency(dailyOpsCost * 365, currency)}</span>
                       </div>
                        <div className="flex justify-between border-t border-white/10 pt-2 font-bold">
                           <span className="text-white">Total Operating Cost</span>
                           <span className="text-danger">{formatCurrency(globalParams.annualMaintenanceCost + globalParams.annualWarrantyCost + globalParams.annualConsumablesCost + (dailyOpsCost * 365), currency)}</span>
                       </div>
                  </div>
              </Card>
          </div>
      </div>
    </div>
  );
};

export default LeaseAnalysis;

import { InputParams, CalculatedResults } from '../types';

function calculateIRR(cashFlows: number[]): number {
    let min = -1.0;
    let max = 10.0;
    let guess = 0.1;
    let npv = 0;

    // Simple Bisection for 20 iterations
    for(let i=0; i<20; i++) {
        guess = (min + max) / 2;
        npv = 0;
        for(let t=0; t<cashFlows.length; t++) {
            npv += cashFlows[t] / Math.pow(1 + guess, t);
        }
        if (npv > 0) {
            min = guess;
        } else {
            max = guess;
        }
    }
    return guess * 100;
}

// Depreciation Schedules
const MACRS_5_YEAR = [0.20, 0.32, 0.192, 0.1152, 0.1152, 0.0576];
const MACRS_7_YEAR = [0.1429, 0.2449, 0.1749, 0.1249, 0.0893, 0.0892, 0.0893, 0.0446];

export const calculateVaporRecovery = (params: InputParams): CalculatedResults => {
  const totalUnitsSold = params.unitsPerClient * params.numberOfClients;
  const LITER_PER_GALLON = 3.78541;
  const isDirectSales = params.businessModel === 'Direct Sales';
  const isLeasing = params.businessModel === 'Leasing';

  // Constants & Conversions
  const co2TonnesPerVolumeUnit = params.unitSystem === 'gallons'
    ? params.co2TonnesPerGallon
    : params.co2TonnesPerGallon / LITER_PER_GALLON;

  const durationYears = Math.max(1, params.leaseTerm); // Ensure at least 1 year

  // --- REVENUE CALCULATIONS ---
  // Apply Margin to Installation Cost to get Price
  const installationPricePerUnit = params.installationCostPerUnit * (1 + (params.installationMargin || 0) / 100);
  const installationRevenue = params.companyHandlesInstallation ? totalUnitsSold * installationPricePerUnit : 0;

  const salesRevenue = isDirectSales ? totalUnitsSold * params.unitSalePrice : 0;

  // --- LOAN SETUP ---
  let loanPrincipal = 0;
  let annualLoanPayment = 0;

  // Cost of the project (Investment basis)
  // Note: If company installs, they pay the cost. The revenue is separate.
  const installationCostTotal = params.companyHandlesInstallation ? totalUnitsSold * params.installationCostPerUnit : 0;

  if (params.enableFinancing) {
      const totalInvestment = (totalUnitsSold * params.unitCost) + installationCostTotal;

      const downPayment = totalInvestment * (params.loanDownPaymentPercent / 100);
      loanPrincipal = totalInvestment - downPayment;

      // PMT Calculation
      if (loanPrincipal > 0 && params.loanInterestRate > 0) {
          const r = params.loanInterestRate / 100;
          const n = params.loanTermYears;
          // Annual payment formula
          annualLoanPayment = (loanPrincipal * r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1);
      } else if (loanPrincipal > 0) {
          annualLoanPayment = loanPrincipal / params.loanTermYears;
      }
  }

  // --- LOOP ---
  let totalLeasingRevenue = 0;
  let totalRecoveredVolume = 0;
  let totalMonthlyFeeRevenue = 0;
  let totalSparePartsRevenue = 0;
  let totalLoanInterestCost = 0;
  let totalTaxableIncome = 0;
  let totalTaxes = 0;

  // Cost Aggregators
  const cogs = totalUnitsSold * params.unitCost;
  // Installation Cost (The expense to the company)
  const installationCost = installationCostTotal;

  // Scale CAC by number of clients (Assuming input is Cost Per Client Acquisition)
  const customerAcquisitionCost = params.customerAcquisitionCost * params.numberOfClients;

  // Base Annual Costs (Year 1)
  const baseAnnualMaintenance = totalUnitsSold * params.annualMaintenanceCost;
  const baseAnnualWarranty = totalUnitsSold * params.annualWarrantyCost;
  const baseAnnualConsumables = totalUnitsSold * params.annualConsumablesCost;
  const baseAnnualOperational = totalUnitsSold * params.dailyOperationalCost * 365;
  const baseAnnualElectricityCostPerUnit = params.unitElectricityConsumptionKwhDay * 365 * params.electricityPrice;
  const baseTotalAnnualElectricity = totalUnitsSold * baseAnnualElectricityCostPerUnit;

  // Cash Flow Setup
  let initialOutflow = 0;
  if (params.enableFinancing) {
      const totalInvestment = cogs + installationCost;
      const downPayment = totalInvestment * (params.loanDownPaymentPercent / 100);
      initialOutflow = downPayment + customerAcquisitionCost;
  } else {
      initialOutflow = cogs + installationCost + customerAcquisitionCost;
  }

  // Year 0 Cashflow (Investment)
  const cashFlow: number[] = [-initialOutflow];

  // Depreciable Basis
  const depreciableBasis = cogs + installationCost;

  // Loop years
  let currentLoanBalance = loanPrincipal;

  // Aggregators for Breakdown
  let totalMaintenance = 0;
  let totalWarranty = 0;
  let totalConsumables = 0;
  let totalOperational = 0;
  let totalElectricity = 0;

  // Payback Period Logic
  let paybackPeriod = 0;
  let cumulativeCashFlow = -initialOutflow;
  let paybackFound = false;

  for (let year = 1; year <= durationYears; year++) {
    const growthFactor = Math.pow(1 + (params.volumeGrowthRate / 100), year - 1);
    const inflationFactor = Math.pow(1 + (params.inflationRate || 0) / 100, year - 1);

    // 1. REVENUE
    let yearRevenue = 0;

    // One-time Sales
    if (year === 1 && isDirectSales) yearRevenue += salesRevenue;
    if (year === 1 && params.companyHandlesInstallation) yearRevenue += installationRevenue;

    // Recurring Leasing
    const dailyVolThisYear = params.avgGasolineSold * growthFactor;
    const recoveredThisYear = dailyVolThisYear * totalUnitsSold * (params.recoveryRate / 100) * 365 * (params.machineUptime / 100);

    if (isLeasing) {
        const leaseRev = recoveredThisYear * params.gasolinePrice * (params.companyRevenueShare / 100);
        yearRevenue += leaseRev;
        totalLeasingRevenue += leaseRev;
    }
    totalRecoveredVolume += recoveredThisYear;

    // Carbon
    if (params.enableCarbonCredits && isLeasing) {
        const carbonRev = (recoveredThisYear * co2TonnesPerVolumeUnit) * params.pricePerCredit;
        yearRevenue += carbonRev;
    }

    // SaaS
    if (params.enableMonthlyFees) {
        const saasRev = totalUnitsSold * params.monthlyFeePerUnit * 12;
        yearRevenue += saasRev;
        totalMonthlyFeeRevenue += saasRev;
    }

    // Spare Parts (Direct Sales only, post warranty)
    if (isDirectSales && year > params.warrantyDurationYears) {
        const partsRev = totalUnitsSold * params.postWarrantyRevenuePerUnit * inflationFactor;
        yearRevenue += partsRev;
        totalSparePartsRevenue += partsRev;
    }

    // 2. OPEX (Apply Inflation)
    let yearOpEx = 0;

    // Inflated Costs
    const thisYearMaintenance = baseAnnualMaintenance * inflationFactor;
    const thisYearConsumables = baseAnnualConsumables * inflationFactor;
    const thisYearOperational = baseAnnualOperational * inflationFactor;
    const thisYearElectricity = baseTotalAnnualElectricity * inflationFactor; // Assuming electricity price inflates
    const thisYearWarranty = baseAnnualWarranty;

    if (isLeasing) {
         yearOpEx = thisYearMaintenance + thisYearWarranty + thisYearConsumables + thisYearOperational + thisYearElectricity;
         totalMaintenance += thisYearMaintenance;
         totalWarranty += thisYearWarranty;
         totalConsumables += thisYearConsumables;
         totalOperational += thisYearOperational;
         totalElectricity += thisYearElectricity;
    } else {
        // Direct Sales Costs
        if (year <= params.warrantyDurationYears) {
            yearOpEx += thisYearWarranty;
            totalWarranty += thisYearWarranty;
        }
    }

    // 3. EBITDA
    const ebitda = yearRevenue - yearOpEx;

    // 4. FINANCING COSTS (Interest)
    let interestPayment = 0;
    let principalPayment = 0;

    if (params.enableFinancing && year <= params.loanTermYears && currentLoanBalance > 0) {
        interestPayment = currentLoanBalance * (params.loanInterestRate / 100);
        principalPayment = annualLoanPayment - interestPayment;
        if (principalPayment > currentLoanBalance) principalPayment = currentLoanBalance; // Cap last payment
        currentLoanBalance -= principalPayment;
    }
    totalLoanInterestCost += interestPayment;

    // 5. DEPRECIATION (Non-cash expense for Tax)
    let depreciation = 0;

    if (params.depreciationMethod === 'Straight Line') {
        depreciation = (year <= params.depreciationPeriod) ? depreciableBasis / params.depreciationPeriod : 0;
    } else if (params.depreciationMethod === 'MACRS 5-Year') {
        const rate = MACRS_5_YEAR[year - 1] || 0;
        depreciation = depreciableBasis * rate;
    } else if (params.depreciationMethod === 'MACRS 7-Year') {
        const rate = MACRS_7_YEAR[year - 1] || 0;
        depreciation = depreciableBasis * rate;
    } else if (params.depreciationMethod === 'Double Declining Balance') {
        // Simplified DDB
         if (year <= params.depreciationPeriod) {
            const rate = 2 / params.depreciationPeriod;
            depreciation = depreciableBasis * rate; 
        }
    }

    // 6. TAX
    const taxableIncome = ebitda - interestPayment - depreciation;
    let tax = 0;
    if (taxableIncome > 0 && params.corporateTaxRate > 0) {
        tax = taxableIncome * (params.corporateTaxRate / 100);
    }
    totalTaxes += tax;
    totalTaxableIncome += taxableIncome;

    // 7. CASH FLOW
    const netCashFlow = yearRevenue - yearOpEx - interestPayment - principalPayment - tax;
    cashFlow.push(netCashFlow);

    // Payback Period Calculation
    if (!paybackFound) {
        const prevCumulative = cumulativeCashFlow;
        cumulativeCashFlow += netCashFlow;
        if (cumulativeCashFlow >= 0) {
            // Fraction of year needed to cover the remainder
            // Guard against division by zero if netCashFlow is 0 (unlikely but possible)
            if (netCashFlow !== 0) {
                const fraction = Math.abs(prevCumulative) / netCashFlow;
                paybackPeriod = (year - 1) + fraction;
            } else {
                paybackPeriod = year;
            }
            paybackFound = true;
        }
    }
  }

  // --- TOTALS ---
  const totalCarbonRevenue = params.enableCarbonCredits && isLeasing
    ? (totalRecoveredVolume * co2TonnesPerVolumeUnit) * params.pricePerCredit
    : 0;

  const totalRevenue = salesRevenue + totalLeasingRevenue + installationRevenue + totalCarbonRevenue + totalMonthlyFeeRevenue + totalSparePartsRevenue;

  const totalOpEx = totalMaintenance + totalWarranty + totalConsumables + totalOperational + totalElectricity;
  const totalCosts = cogs + installationCost + customerAcquisitionCost + totalOpEx + totalLoanInterestCost;

  const netProfit = totalRevenue - totalCosts - totalTaxes; // Post-tax lifetime profit

  // NPV
  let npv = 0;
  cashFlow.forEach((flow, i) => {
      npv += flow / Math.pow(1 + params.discountRate / 100, i);
  });

  // IRR
  const irr = calculateIRR(cashFlow);

  // --- IMPACT & BREAK-EVEN CALCULATIONS ---
  // ESG
  const totalCo2Saved = totalRecoveredVolume * co2TonnesPerVolumeUnit;
  // EPA Factors: 1 Tonne = 0.217 vehicles/year, 1 Tonne = 16.5 tree seedlings (10 years) -> rough approx 40-50 trees planted equivalent for simplified marketing stats
  const carsOffRoadEquiv = totalCo2Saved * 0.22;
  const treesPlantedEquiv = totalCo2Saved * 45; // Approx
  const homesPoweredEquiv = totalCo2Saved * 0.12; // Approx

  // Break Even Volume (Daily)
  // We need to find Volume V such that Revenue(V) = OpEx + (CapEx/Term)
  // Revenue Per Daily Gallon Dispensed = 
  //   (RecoveryRate * Uptime * 365) * [ (GasPrice * RevShare) + (Co2PerGal * CreditPrice) ]

  const recoveryEfficiency = (params.recoveryRate / 100) * (params.machineUptime / 100) * 365;
  const revPerRecoveredUnit = (params.gasolinePrice * (params.companyRevenueShare/100)) + 
                              (params.enableCarbonCredits ? co2TonnesPerVolumeUnit * params.pricePerCredit : 0);

  const annualRevPerDailyDispensedUnit = recoveryEfficiency * revPerRecoveredUnit;

  // Costs
  // OpEx is mostly fixed per unit (maintenance, warranty, etc).
  // Some OpEx is variable (Electricity depends on runtime? usually assumed constant daily profile).
  // Let's assume all OpEx inputs are fixed per machine regardless of volume for this Break Even calc.
  const totalFixedOpExPerYear = totalUnitsSold > 0 
    ? (baseAnnualMaintenance + baseAnnualWarranty + baseAnnualConsumables + baseAnnualOperational + baseTotalAnnualElectricity) / totalUnitsSold
    : 0;

  // CapEx (Hardware + Install + CAC) amortized over lease term
  const totalCapExAmortizedPerYear = (totalUnitsSold > 0 && params.leaseTerm > 0)
    ? ((cogs + installationCost + customerAcquisitionCost) / params.leaseTerm) / totalUnitsSold
    : 0;

  // Break Even for OpEx only (Operating Cash Flow positive)
  let breakEvenDailyVolume = 0;
  let breakEvenTotalVolume = 0;
  let safetyMargin = 0;

  if (isLeasing && annualRevPerDailyDispensedUnit > 0) {
      breakEvenDailyVolume = totalFixedOpExPerYear / annualRevPerDailyDispensedUnit;
      // Break Even for Total ROI > 0
      breakEvenTotalVolume = (totalFixedOpExPerYear + totalCapExAmortizedPerYear) / annualRevPerDailyDispensedUnit;

      if (params.avgGasolineSold > 0) {
          safetyMargin = ((params.avgGasolineSold - breakEvenTotalVolume) / params.avgGasolineSold) * 100;
      }
  }

  return {
    totalUnitsSold,
    revenue: {
      salesRevenue,
      leasingRevenue: totalLeasingRevenue,
      installationRevenue,
      carbonCreditRevenue: totalCarbonRevenue,
      monthlyFeeRevenue: totalMonthlyFeeRevenue,
      sparePartsRevenue: totalSparePartsRevenue,
      totalRevenue,
    },
    costs: {
      cogs,
      installationCost,
      maintenanceCost: totalMaintenance,
      electricityCost: totalElectricity,
      consumablesCost: totalConsumables,
      warrantyCost: totalWarranty,
      operationalCost: totalOperational,
      customerAcquisitionCost,
      loanInterestCost: totalLoanInterestCost,
      totalCosts,
      totalTaxes,
    },
    profitability: {
      grossProfit: totalRevenue - cogs - installationCost, 
      ebitda: totalRevenue - totalOpEx - cogs - installationCost - customerAcquisitionCost,
      netProfit,
      profitMargin: totalRevenue > 0 ? (netProfit / totalRevenue) * 100 : 0,
      roi: (totalCosts + totalTaxes) > 0 ? (netProfit / (totalCosts + totalTaxes)) * 100 : 0,
      npv,
      irr,
      paybackPeriod: paybackFound ? paybackPeriod : 0,
    },
    cashFlow,
    impact: {
        totalCo2Saved,
        treesPlantedEquiv,
        carsOffRoadEquiv,
        homesPoweredEquiv,
        breakEvenDailyVolume,
        breakEvenTotalVolume,
        safetyMargin
    }
  };
};
